fn coordinate_local_delegation_control(
    headers: &HeaderMap,
    state: &AppState,
    delegation_id: &str,
    request: DelegationRunControlRequest,
    expected_operation: RunControlOperation,
) -> std::result::Result<Response, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(headers, state)?;
    require_roles_with_audit(
        headers,
        state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        match expected_operation {
            RunControlOperation::DelegationStop => "execass.delegation.stop",
            RunControlOperation::DelegationResume => "execass.delegation.resume",
            RunControlOperation::GlobalStop | RunControlOperation::GlobalResume => {
                "execass.delegation_control.invalid"
            }
        },
        &format!("execass:delegation:{delegation_id}"),
    )?;
    request.binding.validate().map_err(|_| {
        api_error(
            StatusCode::BAD_REQUEST,
            "invalid ExecAss delegation run-control binding",
        )
    })?;
    if request.binding.operation() != expected_operation
        || request.binding.target()
            != &(RunControlTarget::Delegation {
                delegation_id: delegation_id.to_string(),
            })
    {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "run-control operation or target does not match this endpoint",
        ));
    }
    require_matching_idempotency_header(headers, request.binding.idempotency_key())?;
    let verified = state
        .execass_actor_gate
        .verify_local_run_control(&request.local_proof, &request.binding)
        .map_err(|failure| {
            warn!(failure = ?failure, "rejected unauthenticated ExecAss delegation control request");
            api_error(
                StatusCode::FORBIDDEN,
                "interactive native owner proof is invalid",
            )
        })?;
    let runtime = state.execass_confirmation_runtime.as_ref().ok_or_else(|| {
        api_error(
            StatusCode::SERVICE_UNAVAILABLE,
            "ExecAss confirmation runtime is unavailable",
        )
    })?;
    let outcome = runtime
        .coordinate_verified_delegation_control(&verified, delegation_id)
        .map_err(|failure| {
            let message = failure.to_string();
            if message.contains("requires an exact stopped state") {
                warn!(error = %failure, "rejected conflicting ExecAss delegation run-control snapshot");
                api_error(
                    StatusCode::CONFLICT,
                    "ExecAss delegation run-control snapshot conflicts with durable state",
                )
            } else {
                error!(error = %failure, "failed applying ExecAss delegation run control");
                api_error(
                    StatusCode::INTERNAL_SERVER_ERROR,
                    "ExecAss delegation run-control transition failed closed",
                )
            }
        })?;
    use carsinos_storage::execass::DelegationRunControlMutationOutcome as Outcome;
    match outcome {
        Outcome::StopRequested(status)
        | Outcome::Drained(status)
        | Outcome::Resumed(status)
        | Outcome::Replayed(status)
        | Outcome::AlreadyStopped(status) => {
            Ok(Json(delegation_run_control_response(status)).into_response())
        }
        Outcome::Stale(status) => Ok((
            StatusCode::CONFLICT,
            Json(delegation_run_control_response(status)),
        )
            .into_response()),
        Outcome::NotFound => Err(api_error(
            StatusCode::NOT_FOUND,
            "ExecAss delegation run-control target was not found",
        )),
    }
}

fn require_matching_idempotency_header(
    headers: &HeaderMap,
    expected: &str,
) -> std::result::Result<(), (StatusCode, Json<ApiError>)> {
    let supplied = headers
        .get("idempotency-key")
        .and_then(|value| value.to_str().ok())
        .unwrap_or_default();
    if supplied != expected {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "Idempotency-Key header must match the signed run-control binding",
        ));
    }
    Ok(())
}

fn coordinate_local_global_control(
    headers: &HeaderMap,
    state: &AppState,
    binding: carsinos_protocol::execass::RunControlRequestBinding,
    local_proof: carsinos_protocol::execass::LocalRunControlProof,
    expected_operation: RunControlOperation,
) -> std::result::Result<(StatusCode, StopAllStatusResponse), (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(headers, state)?;
    require_roles_with_audit(
        headers,
        state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        match expected_operation {
            RunControlOperation::GlobalStop => "execass.stop_all.engage",
            RunControlOperation::GlobalResume => "execass.stop_all.resume",
            RunControlOperation::DelegationStop | RunControlOperation::DelegationResume => {
                "execass.global_control.invalid"
            }
        },
        "execass:global-control",
    )?;
    binding.validate().map_err(|_| {
        api_error(
            StatusCode::BAD_REQUEST,
            "invalid ExecAss run-control binding",
        )
    })?;
    if binding.operation() != expected_operation
        || !matches!(binding.target(), RunControlTarget::Global)
    {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "run-control operation does not match this endpoint",
        ));
    }
    require_matching_idempotency_header(headers, binding.idempotency_key())?;
    let verified = state
        .execass_actor_gate
        .verify_local_run_control(&local_proof, &binding)
        .map_err(|failure| {
            warn!(failure = ?failure, "rejected unauthenticated ExecAss native run-control request");
            api_error(
                StatusCode::FORBIDDEN,
                "interactive native owner proof is invalid",
            )
        })?;
    let runtime = state.execass_confirmation_runtime.as_ref().ok_or_else(|| {
        api_error(
            StatusCode::SERVICE_UNAVAILABLE,
            "ExecAss confirmation runtime is unavailable",
        )
    })?;
    let outcome = runtime
        .coordinate_verified_global_control(&verified)
        .map_err(|failure| {
            warn!(error = %failure, "ExecAss global run-control transition rejected");
            api_error(
                StatusCode::CONFLICT,
                "ExecAss global run-control snapshot is stale or unavailable",
            )
        })?;
    match outcome {
        carsinos_storage::execass::GlobalStopMutationOutcome::Engaged(status)
        | carsinos_storage::execass::GlobalStopMutationOutcome::Resumed(status)
        | carsinos_storage::execass::GlobalStopMutationOutcome::Replayed(status)
        | carsinos_storage::execass::GlobalStopMutationOutcome::AlreadyEngaged(status) => {
            Ok((StatusCode::OK, stop_all_status_response(status)))
        }
        carsinos_storage::execass::GlobalStopMutationOutcome::Stale(status) => {
            Ok((StatusCode::CONFLICT, stop_all_status_response(status)))
        }
        carsinos_storage::execass::GlobalStopMutationOutcome::Conflict => Err(api_error(
            StatusCode::CONFLICT,
            "ExecAss global run-control request conflicts with durable state",
        )),
    }
}

fn delegation_run_control_response(
    status: carsinos_storage::execass::DelegationRunControlStatus,
) -> DelegationRunControlResponse {
    use carsinos_storage::execass::{DelegationPhase, DelegationStopDrainState, RunControlState};
    DelegationRunControlResponse {
        delegation_id: status.delegation_id,
        phase: match status.phase {
            DelegationPhase::Accepted => ProtocolDelegationPhase::Accepted,
            DelegationPhase::Planning => ProtocolDelegationPhase::Planning,
            DelegationPhase::InMotion => ProtocolDelegationPhase::InMotion,
            DelegationPhase::WaitingForUser => ProtocolDelegationPhase::WaitingForUser,
            DelegationPhase::WaitingExternal => ProtocolDelegationPhase::WaitingExternal,
            DelegationPhase::Recovering => ProtocolDelegationPhase::Recovering,
            DelegationPhase::Completed => ProtocolDelegationPhase::Completed,
            DelegationPhase::PartiallyCompleted => ProtocolDelegationPhase::PartiallyCompleted,
            DelegationPhase::Failed => ProtocolDelegationPhase::Failed,
        },
        run_control: match status.run_control {
            RunControlState::Running => ProtocolRunControlState::Running,
            RunControlState::StopRequested => ProtocolRunControlState::StopRequested,
            RunControlState::Stopped => ProtocolRunControlState::Stopped,
        },
        state_revision: status.state_revision,
        current_plan_revision: status.current_plan_revision,
        stop_epoch: status.stop_epoch,
        policy_revision: status.policy_revision,
        drain_state: match status.drain_state {
            DelegationStopDrainState::Running => "running",
            DelegationStopDrainState::Draining => "draining",
            DelegationStopDrainState::ReadyToStop => "ready_to_stop",
            DelegationStopDrainState::Stopped => "stopped",
        }
        .to_string(),
        unresolved_effect_disclosure_digest: status.unresolved_external_effects_digest,
        unresolved_external_effect_refs: status
            .unresolved_external_effects
            .into_iter()
            .map(unresolved_external_effect_ref)
            .collect(),
    }
}

fn unresolved_external_effect_ref(
    effect: carsinos_storage::execass::UnresolvedExternalEffectReference,
) -> UnresolvedExternalEffectRef {
    UnresolvedExternalEffectRef {
        logical_effect_id: effect.logical_effect_id,
        delegation_id: effect.delegation_id,
        continuation_id: effect.continuation_id,
        state: match effect.state {
            carsinos_storage::execass::LogicalEffectState::Planned => "planned",
            carsinos_storage::execass::LogicalEffectState::Claimed => "claimed",
            carsinos_storage::execass::LogicalEffectState::Invoking => "invoking",
            carsinos_storage::execass::LogicalEffectState::Succeeded => "succeeded",
            carsinos_storage::execass::LogicalEffectState::Failed => "failed",
            carsinos_storage::execass::LogicalEffectState::OutcomeUnknown => "outcome_unknown",
            carsinos_storage::execass::LogicalEffectState::ReconciledAbsent => "reconciled_absent",
            carsinos_storage::execass::LogicalEffectState::ReconciledPresent => {
                "reconciled_present"
            }
        }
        .to_string(),
        latest_attempt_id: effect.latest_attempt_id,
    }
}

fn stop_all_status_response(
    status: carsinos_storage::execass::GlobalStopStatus,
) -> StopAllStatusResponse {
    StopAllStatusResponse {
        engaged: status.engaged,
        stop_epoch: status.global_stop_epoch,
        current_policy_revision: status.current_policy_revision,
        drain_state: match status.drain_state {
            carsinos_storage::execass::GlobalStopDrainState::Running => "running",
            carsinos_storage::execass::GlobalStopDrainState::Draining => "draining",
            carsinos_storage::execass::GlobalStopDrainState::Drained => "drained",
        }
        .to_string(),
        unresolved_effect_disclosure_digest: status.unresolved_external_effects_digest,
        unresolved_external_effect_refs: status
            .unresolved_external_effects
            .into_iter()
            .map(unresolved_external_effect_ref)
            .collect(),
    }
}

async fn metrics(
    headers: HeaderMap,
    State(state): State<AppState>,
) -> std::result::Result<impl IntoResponse, StatusCode> {
    let auth_ctx = require_bearer_auth(&headers, &state).map_err(|err| err.status)?;
    require_roles_raw(&auth_ctx, &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY])
        .map_err(|err| err.status)?;
    let response = MetricsResponse {
        service: "carsinos-gateway".to_string(),
        version: env!("CARGO_PKG_VERSION").to_string(),
        uptime_ms: state.started_instant.elapsed().as_millis() as u64,
        requests_total: state.metrics.requests_total.load(Ordering::Relaxed),
        auth_failures_total: state.metrics.auth_failures_total.load(Ordering::Relaxed),
        runs_started_total: state.metrics.runs_started_total.load(Ordering::Relaxed),
        runs_succeeded_total: state.metrics.runs_succeeded_total.load(Ordering::Relaxed),
        runs_failed_total: state.metrics.runs_failed_total.load(Ordering::Relaxed),
        notes_created_total: state.metrics.notes_created_total.load(Ordering::Relaxed),
        notes_updated_total: state.metrics.notes_updated_total.load(Ordering::Relaxed),
    };
    Ok(Json(response))
}

async fn list_provider_capabilities(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListProviderCapabilitiesQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    let provider_filter = query
        .provider
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.to_ascii_lowercase());
    let resource = provider_filter
        .as_ref()
        .map(|provider| format!("provider:{provider}"))
        .unwrap_or_else(|| "providers".to_string());
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        "provider.capabilities.list",
        &resource,
    )?;

    let capabilities = if let Some(provider) = provider_filter.as_deref() {
        vec![state.providers.capabilities(provider).ok_or_else(|| {
            api_error(
                StatusCode::BAD_REQUEST,
                "unsupported provider for capabilities query",
            )
        })?]
    } else {
        state.providers.list_capabilities()
    };

    let items = capabilities
        .into_iter()
        .map(|item| ProviderCapabilityResponse {
            provider: item.provider,
            supports_streaming: item.supports_streaming,
            supports_tools: item.supports_tools,
            supports_json_mode: item.supports_json_mode,
            supports_vision: item.supports_vision,
            max_context_tokens: item.max_context_tokens,
            error_classes: item.error_classes,
            retryable_error_classes: item.retryable_error_classes,
        })
        .collect::<Vec<_>>();
    Ok(Json(ListProviderCapabilitiesResponse {
        contract_version: "v2".to_string(),
        items,
    }))
}

async fn list_provider_models(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListProviderModelsQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    let provider = query.provider.trim().to_ascii_lowercase();
    if provider.is_empty() {
        return Err(api_error_with_code(
            StatusCode::BAD_REQUEST,
            "INVALID_INPUT",
            "provider is required",
        ));
    }
    if !provider_models_supported(&provider) {
        return Err(api_error_with_code(
            StatusCode::BAD_REQUEST,
            "INVALID_INPUT",
            "unsupported provider for model catalog",
        ));
    }

    let requested_auth_profile_id = query
        .auth_profile_id
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.to_string());
    let resource = requested_auth_profile_id
        .as_ref()
        .map(|id| format!("provider:{provider}:auth_profile:{id}"))
        .unwrap_or_else(|| format!("provider:{provider}"));
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        "provider.models.list",
        &resource,
    )?;
    require_endpoint_rate_limit_with_error(&state, &auth, "run")?;

    let requested_agent_id = query
        .agent_id
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.to_string());
    let refresh = query.refresh.unwrap_or(false);

    let resolved_auth_record = resolve_provider_models_auth_profile(
        &state,
        &provider,
        requested_agent_id.as_deref(),
        requested_auth_profile_id.as_deref(),
    )
    .await
    .map_err(map_provider_models_auth_resolution_error)?;
    let resolved_auth_profile_id = resolved_auth_record
        .as_ref()
        .map(|profile| profile.auth_profile_id.clone());
    let resolved_auth_profile = match resolved_auth_record.as_ref() {
        Some(profile) => Some(to_provider_auth_profile(&state, profile).map_err(|err| {
            internal_err_with_error("hydrating auth profile for model catalog failed", err)
        })?),
        None => None,
    };
    if provider == AUTH_PROVIDER_ANTHROPIC
        && resolved_auth_profile
            .as_ref()
            .map(|profile| !anthropic_profile_is_direct_api_key(profile))
            .unwrap_or(true)
    {
        return Err(api_error_with_code(
            StatusCode::BAD_REQUEST,
            "AUTH_REQUIRED",
            "Anthropic model catalog requires a direct Anthropic API key profile",
        ));
    }

    let base_url = provider_models_base_url(&provider, resolved_auth_profile.as_ref());
    let cache_key =
        provider_models_cache_key(&provider, &base_url, resolved_auth_profile_id.as_deref());
    let now = current_time_ms();
    if !refresh {
        if let Some(entry) = state
            .provider_models_cache
            .read()
            .await
            .get(&cache_key)
            .cloned()
        {
            if entry.expires_at_ms > now {
                return Ok(Json(ListProviderModelsResponse {
                    contract_version: PROVIDER_MODELS_CONTRACT_VERSION.to_string(),
                    provider,
                    auth_profile_id: entry.auth_profile_id,
                    items: entry.items,
                }));
            }
        }
    }

    let items = fetch_provider_models_from_upstream(
        &state,
        &provider,
        &base_url,
        resolved_auth_profile.as_ref(),
    )
    .await?;
    state.provider_models_cache.write().await.insert(
        cache_key,
        ProviderModelsCacheEntry {
            auth_profile_id: resolved_auth_profile_id.clone(),
            items: items.clone(),
            expires_at_ms: now.saturating_add(PROVIDER_MODELS_CACHE_TTL_MS),
        },
    );

    Ok(Json(ListProviderModelsResponse {
        contract_version: PROVIDER_MODELS_CONTRACT_VERSION.to_string(),
        provider,
        auth_profile_id: resolved_auth_profile_id,
        items,
    }))
}

async fn resolve_provider_models_auth_profile(
    state: &AppState,
    provider: &str,
    requested_agent_id: Option<&str>,
    requested_auth_profile_id: Option<&str>,
) -> AnyResult<Option<AuthProfileRecord>> {
    if provider_requires_auth(provider) {
        let candidates = resolve_run_auth_profiles(
            state,
            provider,
            requested_agent_id.unwrap_or_default(),
            requested_auth_profile_id,
        )
        .await?;
        return Ok(candidates.into_iter().flatten().next());
    }

    let resolved_profile_id = requested_auth_profile_id.map(str::to_string).or_else(|| {
        if !provider_supports_optional_auth(provider) {
            return None;
        }
        let requested_agent_id = requested_agent_id?;
        let ordered = state
            .storage
            .list_agent_provider_profile_order(requested_agent_id, provider)
            .ok()?;
        ordered
            .into_iter()
            .map(|value| value.trim().to_string())
            .find(|value| !value.is_empty())
    });
    let Some(profile_id) = resolved_profile_id.as_deref() else {
        return Ok(None);
    };
    if state.storage.global_kill_switch_active()? {
        anyhow::bail!("AUTH_FORBIDDEN:global kill-switch active");
    }
    if state.storage.provider_kill_switch_active(provider)? {
        anyhow::bail!("AUTH_FORBIDDEN:provider kill-switch active");
    }

    let profile = state
        .storage
        .get_auth_profile(profile_id)?
        .with_context(|| format!("requested auth profile not found: {profile_id}"))?;
    if profile.provider != provider {
        anyhow::bail!(
            "requested auth profile provider mismatch: expected '{}' got '{}'",
            provider,
            profile.provider
        );
    }
    if !profile.enabled {
        anyhow::bail!("requested auth profile is disabled: {profile_id}");
    }
    if !provider_auth_mode_allowed(provider, &profile.auth_mode) {
        anyhow::bail!(
            "requested auth profile mode '{}' not allowed for provider '{}'",
            profile.auth_mode,
            provider
        );
    }
    let policy = auth_mode_policy(&profile.auth_mode)
        .with_context(|| format!("unsupported auth_mode in profile: {}", profile.auth_mode))?;
    if profile.risk_level != policy.risk_level {
        anyhow::bail!(
            "requested auth profile risk_level '{}' mismatches registry '{}'",
            profile.risk_level,
            policy.risk_level
        );
    }
    if policy.requires_kill_switch && profile.kill_switch_scope == KILL_SWITCH_SCOPE_NONE {
        anyhow::bail!("requested high-risk auth profile is missing kill-switch scope");
    }
    let profile = maybe_refresh_expired_auth_profile(state, profile).await?;
    if auth_profile_credentials_expired(&profile)? {
        anyhow::bail!("requested auth profile credentials expired");
    }
    Ok(Some(profile))
}

fn map_provider_models_auth_resolution_error(err: anyhow::Error) -> (StatusCode, Json<ApiError>) {
    let message = err.to_string();
    let normalized = message.to_ascii_lowercase();
    if message.starts_with("AUTH_FORBIDDEN:")
        || normalized.contains("kill-switch")
        || normalized.contains("kill switch")
    {
        return api_error_with_code(
            StatusCode::FORBIDDEN,
            "AUTH_FORBIDDEN",
            &format!("provider auth policy denied model catalog request: {message}"),
        );
    }
    api_error_with_code(
        StatusCode::BAD_GATEWAY,
        "AUTH_REQUIRED",
        &format!("provider auth unavailable for model catalog request: {message}"),
    )
}

fn provider_models_supported(provider: &str) -> bool {
    matches!(
        provider,
        "openai" | "anthropic" | "openrouter" | "ollama" | "vllm" | "lmstudio" | "mock"
    )
}

fn provider_models_default_base_url(provider: &str) -> &'static str {
    match provider {
        "openai" => OPENAI_DEFAULT_API_BASE,
        "anthropic" => ANTHROPIC_DEFAULT_API_BASE,
        "openrouter" => OPENROUTER_DEFAULT_API_BASE,
        "ollama" => OLLAMA_DEFAULT_API_BASE,
        "vllm" => VLLM_DEFAULT_API_BASE,
        "lmstudio" => LMSTUDIO_DEFAULT_API_BASE,
        "mock" => "mock://local",
        _ => "mock://local",
    }
}

fn provider_models_base_url(provider: &str, profile: Option<&ProviderAuthProfile>) -> String {
    profile
        .and_then(|item| item.api_base_url.as_ref())
        .map(|value| value.trim().trim_end_matches('/').to_string())
        .filter(|value| !value.is_empty())
        .or_else(|| provider_models_env_base_url(provider))
        .unwrap_or_else(|| provider_models_default_base_url(provider).to_string())
}

fn provider_models_env_base_url(provider: &str) -> Option<String> {
    let env_var = match provider {
        "ollama" => OLLAMA_API_BASE_URL_ENV,
        "vllm" => VLLM_API_BASE_URL_ENV,
        "lmstudio" => LMSTUDIO_API_BASE_URL_ENV,
        _ => return None,
    };
    std::env::var(env_var)
        .ok()
        .map(|value| value.trim().trim_end_matches('/').to_string())
        .filter(|value| !value.is_empty())
}

fn provider_models_cache_key(
    provider: &str,
    base_url: &str,
    auth_profile_id: Option<&str>,
) -> String {
    format!(
        "{}|{}|{}",
        provider.to_ascii_lowercase(),
        base_url.to_ascii_lowercase(),
        auth_profile_id.unwrap_or("<none>")
    )
}

fn truncate_provider_error_body(raw: &str) -> String {
    let trimmed = raw.trim();
    if trimmed.is_empty() {
        "<empty>".to_string()
    } else if trimmed.len() > 240 {
        trimmed.chars().take(240).collect::<String>()
    } else {
        trimmed.to_string()
    }
}

fn parse_provider_credentials_json(
    profile: &ProviderAuthProfile,
    context_label: &str,
) -> AnyResult<serde_json::Value> {
    serde_json::from_str(&profile.credentials_json).with_context(|| context_label.to_string())
}

fn extract_provider_auth_token(profile: &ProviderAuthProfile) -> AnyResult<Option<String>> {
    let payload = parse_provider_credentials_json(
        profile,
        "failed to parse provider credentials for model catalog",
    )?;
    for key in ["api_key", "token", "access_token", "bearer_token"] {
        if let Some(value) = payload.get(key).and_then(|value| value.as_str()) {
            let trimmed = value.trim();
            if !trimmed.is_empty() {
                return Ok(Some(trimmed.to_string()));
            }
        }
    }
    Ok(None)
}

fn normalize_anthropic_setup_token_value(raw: &str) -> String {
    raw.chars().filter(|char| !char.is_whitespace()).collect()
}

fn is_anthropic_setup_token_value(raw: &str) -> bool {
    let trimmed = normalize_anthropic_setup_token_value(raw);
    trimmed.starts_with(ANTHROPIC_SETUP_TOKEN_PREFIX)
        && trimmed.len() >= ANTHROPIC_SETUP_TOKEN_MIN_LENGTH
}

fn anthropic_profile_is_direct_api_key(profile: &ProviderAuthProfile) -> bool {
    if !profile
        .auth_mode
        .trim()
        .eq_ignore_ascii_case(AUTH_MODE_API_KEY)
    {
        return false;
    }
    let Ok(payload) = parse_provider_credentials_json(
        profile,
        "failed to parse anthropic provider credentials for direct-api-key policy",
    ) else {
        return false;
    };
    if payload
        .get("token_kind")
        .and_then(|value| value.as_str())
        .map(|value| value.trim().eq_ignore_ascii_case("setup_token"))
        .unwrap_or(false)
    {
        return false;
    }
    if ["token", "access_token", "bearer_token", "refresh_token"]
        .iter()
        .any(|key| {
            payload
                .get(*key)
                .and_then(|value| value.as_str())
                .map(|value| !value.trim().is_empty())
                .unwrap_or(false)
        })
    {
        return false;
    }
    payload
        .get("api_key")
        .and_then(|value| value.as_str())
        .map(|value| {
            let trimmed = value.trim();
            !trimmed.is_empty() && !is_anthropic_setup_token_value(trimmed)
        })
        .unwrap_or(false)
}

fn anthropic_profile_uses_curated_catalog(profile: &ProviderAuthProfile) -> bool {
    !anthropic_profile_is_direct_api_key(profile)
}

fn parse_openai_models_payload(payload: &serde_json::Value) -> AnyResult<Vec<String>> {
    let Some(items) = payload.get("data").and_then(|value| value.as_array()) else {
        anyhow::bail!("missing data array in provider models response");
    };
    let mut model_ids = Vec::new();
    for item in items {
        let candidate = item
            .get("id")
            .and_then(|value| value.as_str())
            .or_else(|| item.get("name").and_then(|value| value.as_str()))
            .unwrap_or_default()
            .trim()
            .to_string();
        if !candidate.is_empty() {
            model_ids.push(candidate);
        }
    }
    Ok(model_ids)
}

#[derive(Debug, Clone)]
struct OllamaModelCatalogItem {
    model_id: String,
    family: Option<String>,
}

fn parse_ollama_models_payload(
    payload: &serde_json::Value,
) -> AnyResult<Vec<OllamaModelCatalogItem>> {
    let Some(items) = payload.get("models").and_then(|value| value.as_array()) else {
        anyhow::bail!("missing models array in ollama tags response");
    };
    let mut model_ids = Vec::new();
    for item in items {
        let model_id = item
            .get("name")
            .and_then(|value| value.as_str())
            .or_else(|| item.get("model").and_then(|value| value.as_str()))
            .unwrap_or_default()
            .trim()
            .to_string();
        if model_id.is_empty() {
            continue;
        }
        let family = item
            .get("details")
            .and_then(|details| {
                details
                    .get("family")
                    .and_then(|value| value.as_str())
                    .or_else(|| {
                        details
                            .get("families")
                            .and_then(|value| value.as_array())
                            .and_then(|families| families.first())
                            .and_then(|value| value.as_str())
                    })
            })
            .map(|value| value.trim().to_ascii_lowercase())
            .filter(|value| !value.is_empty());
        model_ids.push(OllamaModelCatalogItem { model_id, family });
    }
    Ok(model_ids)
}

fn ollama_loadability_error_indicates_incompatible(status: StatusCode, body: &str) -> bool {
    if !matches!(
        status,
        StatusCode::INTERNAL_SERVER_ERROR
            | StatusCode::BAD_REQUEST
            | StatusCode::FAILED_DEPENDENCY
            | StatusCode::SERVICE_UNAVAILABLE
    ) {
        return false;
    }
    let normalized = body.to_ascii_lowercase();
    normalized.contains("unknown model architecture")
        || normalized.contains("unable to load model")
        || normalized.contains("failed to load model")
}

async fn probe_ollama_model_loadability(
    state: &AppState,
    base_url: &str,
    auth_token: Option<&str>,
    model_id: &str,
) -> std::result::Result<bool, reqwest::Error> {
    let normalized_base = base_url.trim_end_matches('/');
    let mut request = state
        .provider_models_http_client
        .post(format!("{normalized_base}/api/generate"))
        .timeout(Duration::from_secs(20))
        .json(&serde_json::json!({
            "model": model_id,
            "prompt": "healthcheck",
            "stream": false,
            "keep_alive": "0s",
            "options": {
                "num_predict": 0
            }
        }));
    if let Some(token) = auth_token {
        request = request.bearer_auth(token);
    }
    let response = request.send().await?;
    if response.status().is_success() {
        return Ok(true);
    }
    let status = response.status();
    let body = response.text().await.unwrap_or_default();
    let body = truncate_provider_error_body(&body);
    Ok(!ollama_loadability_error_indicates_incompatible(
        status, &body,
    ))
}

async fn filter_ollama_models_by_runtime_compatibility(
    state: &AppState,
    base_url: &str,
    auth_token: Option<&str>,
    models: Vec<OllamaModelCatalogItem>,
) -> Vec<String> {
    let mut output = Vec::new();
    let mut family_cache = HashMap::<String, bool>::new();
    for item in models {
        if let Some(family) = item.family.as_ref() {
            if let Some(is_supported) = family_cache.get(family) {
                if *is_supported {
                    output.push(item.model_id);
                }
                continue;
            }
        }
        match probe_ollama_model_loadability(state, base_url, auth_token, &item.model_id).await {
            Ok(is_supported) => {
                if let Some(family) = item.family.as_ref() {
                    family_cache.insert(family.clone(), is_supported);
                }
                if is_supported {
                    output.push(item.model_id);
                } else {
                    warn!(
                        model_id = %item.model_id,
                        family = %item.family.clone().unwrap_or_else(|| "unknown".to_string()),
                        "filtered incompatible ollama model from catalog"
                    );
                }
            }
            Err(err) => {
                // Fail-open for transient probe failures so we do not hide valid models.
                warn!(
                    model_id = %item.model_id,
                    error = %err,
                    "ollama compatibility probe failed; keeping model in catalog"
                );
                if let Some(family) = item.family.as_ref() {
                    family_cache.insert(family.clone(), true);
                }
                output.push(item.model_id);
            }
        }
    }
    output
}

fn normalize_provider_models(raw: Vec<String>) -> Vec<ProviderModelResponse> {
    let mut seen = HashSet::new();
    let mut items = Vec::new();
    for model_id in raw {
        let trimmed = model_id.trim();
        if trimmed.is_empty() {
            continue;
        }
        if !seen.insert(trimmed.to_string()) {
            continue;
        }
        items.push(ProviderModelResponse {
            model_id: trimmed.to_string(),
            label: trimmed.to_string(),
        });
    }
    items
}

fn curated_anthropic_provider_models() -> Vec<ProviderModelResponse> {
    normalize_provider_models(vec![
        "claude-sonnet-4-5".to_string(),
        "claude-opus-4-5".to_string(),
        "claude-sonnet-4-6".to_string(),
        "claude-opus-4-6".to_string(),
        "claude-haiku-3-5".to_string(),
    ])
}

async fn fetch_provider_models_from_upstream(
    state: &AppState,
    provider: &str,
    base_url: &str,
    auth_profile: Option<&ProviderAuthProfile>,
) -> std::result::Result<Vec<ProviderModelResponse>, (StatusCode, Json<ApiError>)> {
    if provider == "mock" {
        return Ok(vec![ProviderModelResponse {
            model_id: "mock-echo-v1".to_string(),
            label: "mock-echo-v1".to_string(),
        }]);
    }
    if provider == "anthropic"
        && auth_profile
            .map(anthropic_profile_uses_curated_catalog)
            .unwrap_or(false)
    {
        // Non-direct Anthropic auth profiles are no longer valid for live catalog
        // discovery. Keep the fallback deterministic for legacy rows while the
        // creation and execution paths reject those profiles.
        return Ok(curated_anthropic_provider_models());
    }

    let token = match auth_profile {
        Some(profile) => extract_provider_auth_token(profile).map_err(|err| {
            internal_err_with_error(
                "extracting provider auth token for model catalog failed",
                err,
            )
        })?,
        None => None,
    };
    let provider_requires_token = matches!(provider, "openai" | "anthropic" | "openrouter");
    if provider_requires_token && token.is_none() {
        return Err(api_error_with_code(
            StatusCode::BAD_GATEWAY,
            "AUTH_REQUIRED",
            "provider auth profile is missing API token",
        ));
    }

    let normalized_base = base_url.trim_end_matches('/');
    let mut request = match provider {
        "openai" | "openrouter" | "vllm" | "lmstudio" => state
            .provider_models_http_client
            .get(format!("{normalized_base}/v1/models")),
        "anthropic" => state
            .provider_models_http_client
            .get(format!("{normalized_base}/v1/models"))
            .header("anthropic-version", "2023-06-01"),
        "ollama" => state
            .provider_models_http_client
            .get(format!("{normalized_base}/api/tags")),
        _ => {
            return Err(api_error_with_code(
                StatusCode::BAD_REQUEST,
                "INVALID_INPUT",
                "unsupported provider for model catalog",
            ));
        }
    };
    if let Some(token) = token.as_ref() {
        if provider == "anthropic" {
            request = request.header("x-api-key", token);
        } else {
            request = request.bearer_auth(token);
        }
    }

    let response = request.send().await.map_err(|err| {
        if err.is_timeout() {
            api_error_with_code(
                StatusCode::GATEWAY_TIMEOUT,
                "TIMEOUT",
                "provider model catalog request timed out",
            )
        } else {
            api_error_with_code(
                StatusCode::SERVICE_UNAVAILABLE,
                "DEPENDENCY_UNAVAILABLE",
                "provider model catalog request failed",
            )
        }
    })?;
    let status = response.status();
    if !status.is_success() {
        let body = response.text().await.unwrap_or_default();
        let body = truncate_provider_error_body(&body);
        if matches!(status, StatusCode::UNAUTHORIZED | StatusCode::FORBIDDEN) {
            return Err(api_error_with_code(
                StatusCode::BAD_GATEWAY,
                "AUTH_REQUIRED",
                &format!(
                    "provider auth rejected model catalog request (status={} body={body})",
                    status.as_u16()
                ),
            ));
        }
        if status == StatusCode::TOO_MANY_REQUESTS {
            return Err(api_error_with_code(
                StatusCode::TOO_MANY_REQUESTS,
                "RATE_LIMITED",
                &format!(
                    "provider model catalog request was rate limited (status={} body={body})",
                    status.as_u16()
                ),
            ));
        }
        if matches!(
            status,
            StatusCode::REQUEST_TIMEOUT | StatusCode::GATEWAY_TIMEOUT
        ) {
            return Err(api_error_with_code(
                StatusCode::GATEWAY_TIMEOUT,
                "TIMEOUT",
                &format!(
                    "provider model catalog request timed out (status={} body={body})",
                    status.as_u16()
                ),
            ));
        }
        return Err(api_error_with_code(
            StatusCode::SERVICE_UNAVAILABLE,
            "DEPENDENCY_UNAVAILABLE",
            &format!(
                "provider model catalog request failed (status={} body={body})",
                status.as_u16()
            ),
        ));
    }

    let payload: serde_json::Value = response.json().await.map_err(|err| {
        api_error_with_code(
            StatusCode::SERVICE_UNAVAILABLE,
            "DEPENDENCY_UNAVAILABLE",
            &format!("failed to parse provider model catalog response: {err}"),
        )
    })?;
    let raw_models = match provider {
        "openai" | "openrouter" | "anthropic" | "vllm" | "lmstudio" => {
            parse_openai_models_payload(&payload).map_err(|err| {
                api_error_with_code(
                    StatusCode::SERVICE_UNAVAILABLE,
                    "DEPENDENCY_UNAVAILABLE",
                    &format!("invalid provider model catalog payload: {err}"),
                )
            })?
        }
        "ollama" => {
            let catalog_items = parse_ollama_models_payload(&payload).map_err(|err| {
                api_error_with_code(
                    StatusCode::SERVICE_UNAVAILABLE,
                    "DEPENDENCY_UNAVAILABLE",
                    &format!("invalid provider model catalog payload: {err}"),
                )
            })?;
            filter_ollama_models_by_runtime_compatibility(
                state,
                normalized_base,
                token.as_deref(),
                catalog_items,
            )
            .await
        }
        _ => unreachable!(),
    };
    Ok(normalize_provider_models(raw_models))
}

