fn agent_mail_attachment_max_bytes() -> usize {
    std::env::var("CARSINOS_AGENT_MAIL_ATTACHMENT_MAX_BYTES")
        .ok()
        .and_then(|value| value.trim().parse::<usize>().ok())
        .filter(|value| *value > 0)
        .unwrap_or(AGENT_MAIL_DEFAULT_ATTACHMENT_MAX_BYTES)
}

fn agent_mail_mcp_default_lease_ttl_ms() -> i64 {
    std::env::var("CARSINOS_AGENT_MAIL_MCP_DEFAULT_LEASE_TTL_MS")
        .ok()
        .and_then(|value| value.trim().parse::<i64>().ok())
        .filter(|value| *value > 0)
        .unwrap_or(300_000)
}

fn agent_mail_allowed_mimes() -> &'static HashSet<String> {
    static ALLOWED_MIMES: std::sync::OnceLock<HashSet<String>> = std::sync::OnceLock::new();
    ALLOWED_MIMES.get_or_init(|| {
        let configured = std::env::var("CARSINOS_AGENT_MAIL_ALLOWED_MIME").unwrap_or_else(|_| {
            "text/plain,text/markdown,application/pdf,image/png,image/jpeg,image/webp,image/gif"
                .to_string()
        });
        configured
            .split(',')
            .map(|item| item.trim().to_ascii_lowercase())
            .filter(|item| !item.is_empty())
            .collect::<HashSet<_>>()
    })
}

fn agent_mail_mime_allowed(mime: &str) -> bool {
    let normalized = mime.trim().to_ascii_lowercase();
    agent_mail_allowed_mimes().contains(normalized.as_str())
}

fn board_asset_mime_allowed(mime: &str) -> bool {
    matches!(
        mime.trim().to_ascii_lowercase().as_str(),
        "image/png"
            | "image/jpeg"
            | "image/jpg"
            | "image/webp"
            | "image/gif"
            | "application/pdf"
            | "text/markdown"
            | "text/plain"
    )
}

fn sanitize_filename(raw: &str) -> String {
    let mut out = raw
        .trim()
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || matches!(ch, '.' | '_' | '-') {
                ch
            } else {
                '_'
            }
        })
        .collect::<String>();
    if out.is_empty() {
        out = "asset.bin".to_string();
    }
    if out.len() > 120 {
        out.truncate(120);
    }
    out
}

fn tags_from_json(raw: Option<&String>) -> Vec<String> {
    raw.and_then(|value| serde_json::from_str::<Vec<String>>(value).ok())
        .unwrap_or_default()
}

fn tags_to_json(tags: Option<Vec<String>>) -> Option<String> {
    tags.map(|items| {
        serde_json::json!(items
            .into_iter()
            .map(|item| item.trim().to_string())
            .filter(|item| !item.is_empty())
            .collect::<Vec<_>>())
        .to_string()
    })
}

fn to_agent_memory_binding_response(
    record: AgentMemoryBindingRecord,
) -> AgentMemoryBindingResponse {
    AgentMemoryBindingResponse {
        binding_id: record.binding_id,
        provider_kind: record.provider_kind,
        base_url: record.base_url,
        auth_mode: record.auth_mode,
        auth_secret_ref: record.auth_secret_ref,
        principal_id: record.principal_id,
        principal_display_name: record.principal_display_name,
        enabled: record.enabled,
        trusted_local_operator_actions: record.trusted_local_operator_actions,
    }
}

const AGENT_MEMORY_PROVIDER_KIND_MNO: &str = "modelnumquamoblita";

fn normalize_agent_memory_provider_kind_for_gateway(
    value: &str,
) -> std::result::Result<String, (StatusCode, Json<ApiError>)> {
    let normalized = value.trim().to_ascii_lowercase();
    match normalized.as_str() {
        "mno" | AGENT_MEMORY_PROVIDER_KIND_MNO => Ok(AGENT_MEMORY_PROVIDER_KIND_MNO.to_string()),
        _ => Err(api_error(
            StatusCode::BAD_REQUEST,
            "memory_binding.provider_kind must be 'modelnumquamoblita'",
        )),
    }
}

fn normalize_agent_memory_base_url_for_gateway(
    value: &str,
) -> std::result::Result<String, (StatusCode, Json<ApiError>)> {
    let normalized = value.trim().trim_end_matches('/').to_string();
    let parsed = Url::parse(&normalized).map_err(|_| {
        api_error(
            StatusCode::BAD_REQUEST,
            "memory_binding.base_url must be a valid URL",
        )
    })?;
    match parsed.scheme() {
        "http" | "https" => {}
        _ => {
            return Err(api_error(
                StatusCode::BAD_REQUEST,
                "memory_binding.base_url must use http:// or https://",
            ))
        }
    }
    if !parsed.username().is_empty() || parsed.password().is_some() {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "memory_binding.base_url must not include embedded credentials",
        ));
    }
    Ok(normalized)
}

fn is_trusted_local_memory_base_url(base_url: &str) -> bool {
    Url::parse(base_url)
        .ok()
        .and_then(|url| url.host_str().map(|host| host.to_ascii_lowercase()))
        .map(|host| matches!(host.as_str(), "localhost" | "127.0.0.1" | "::1"))
        .unwrap_or(false)
}

fn normalize_agent_memory_auth_mode_for_gateway(
    value: &str,
) -> std::result::Result<String, (StatusCode, Json<ApiError>)> {
    let normalized = value.trim().to_ascii_lowercase();
    match normalized.as_str() {
        "none" | "secret_ref" => Ok(normalized),
        _ => Err(api_error(
            StatusCode::BAD_REQUEST,
            "memory_binding.auth_mode must be one of: none, secret_ref",
        )),
    }
}

