async fn get_runtime_trust_contract_lock(
    headers: HeaderMap,
    State(state): State<AppState>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_error(&auth, &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY])?;
    let lock = state.trust_contract_lock.read().await.clone();
    Ok(Json(GetRuntimeTrustContractLockResponse {
        lock: runtime_trust_lock_response(&lock, state.trust_contract_lock_path.as_str()),
    }))
}

async fn refresh_runtime_trust_contract_lock(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<RefreshRuntimeTrustContractLockRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN],
        "runtime.trust_lock.refresh",
        "config.runtime.trust_lock",
    )?;

    let runtime_config = load_runtime_config(&state)
        .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
    let lock_record = build_runtime_trust_contract_lock_record(
        &runtime_config.global,
        &auth.principal_id,
        Utc::now().timestamp_millis(),
    )
    .map_err(|err| internal_err_with_error("building runtime trust lock failed", err))?;
    let lock_path = state.trust_contract_lock_path.as_str().to_string();
    persist_runtime_trust_contract_lock(FsPath::new(&lock_path), &lock_record)
        .map_err(|err| internal_err_with_error("persisting runtime trust lock failed", err))?;
    {
        let mut write = state.trust_contract_lock.write().await;
        *write = lock_record.clone();
    }

    let reason = request
        .reason
        .as_ref()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    record_security_audit(
        &headers,
        &state,
        &auth,
        "runtime.trust_lock.refresh",
        "config.runtime.trust_lock",
        "allow",
        reason.clone(),
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "lock_path": lock_path,
            "trust_hash": lock_record.trust_hash,
            "locked_at": lock_record.locked_at,
            "reason": reason
        })),
    );

    Ok(Json(RefreshRuntimeTrustContractLockResponse {
        lock: runtime_trust_lock_response(&lock_record, state.trust_contract_lock_path.as_str()),
    }))
}

async fn update_runtime_config(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<UpdateRuntimeConfigRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN],
        "runtime.config.update",
        "config.runtime",
    )?;

    let update_global = request.global.is_some();
    let update_providers = request.providers.is_some();
    let update_channels = request.channels.is_some();
    let update_routing = request.routing.is_some();
    let update_memory = request.memory.is_some();
    let update_extensions = request.extensions.is_some();
    let update_security = request.security.is_some();
    let update_autonomy_guardrails = request.autonomy_guardrails.is_some();

    let existing = load_runtime_config(&state)
        .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
    let existing_trust_lock = state.trust_contract_lock.read().await.clone();
    enforce_runtime_global_against_trust_lock(&existing.global, &existing_trust_lock)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    let existing_json = serde_json::to_string(&existing).map_err(|err| {
        internal_err_with_error("serializing existing runtime config failed", err.into())
    })?;
    let existing_hash = sha256_hex(&existing_json);

    let mut config = existing;
    if let Some(global) = request.global {
        config.global = global;
    }
    if let Some(providers) = request.providers {
        config.providers = providers;
    }
    if let Some(channels) = request.channels {
        config.channels = channels;
    }
    if let Some(routing) = request.routing {
        config.routing = routing;
    }
    if let Some(memory) = request.memory {
        config.memory = memory;
    }
    if let Some(extensions) = request.extensions {
        config.extensions = extensions;
    }
    if let Some(security) = request.security {
        config.security = security;
    }
    if let Some(autonomy_guardrails) = request.autonomy_guardrails {
        config.autonomy_guardrails = autonomy_guardrails;
    }
    config.schema_version = RUNTIME_CONFIG_SCHEMA_VERSION.to_string();
    config = normalize_runtime_config(config);

    validate_runtime_config(&config)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    validate_runtime_routing_agent_refs(&state, &config.routing)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    let lock_path = state.trust_contract_lock_path.as_str().to_string();
    let mut trust_lock_hash = existing_trust_lock.trust_hash.clone();
    let trust_lock_refreshed = if update_global {
        let refreshed_lock = build_runtime_trust_contract_lock_record(
            &config.global,
            &auth.principal_id,
            Utc::now().timestamp_millis(),
        )
        .map_err(|err| internal_err_with_error("building runtime trust lock failed", err))?;
        persist_runtime_trust_contract_lock(FsPath::new(&lock_path), &refreshed_lock)
            .map_err(|err| internal_err_with_error("persisting runtime trust lock failed", err))?;
        trust_lock_hash = refreshed_lock.trust_hash.clone();
        {
            let mut write = state.trust_contract_lock.write().await;
            *write = refreshed_lock;
        }
        true
    } else {
        enforce_runtime_global_against_trust_lock(&config.global, &existing_trust_lock)
            .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
        false
    };

    let config_json = serde_json::to_string(&config)
        .map_err(|err| internal_err_with_error("serializing runtime config failed", err.into()))?;
    let config_hash = sha256_hex(&config_json);
    let previous_snapshot_updated_at = state
        .storage
        .set_app_kv_json(APP_KV_RUNTIME_CONFIG_LAST_GOOD, existing_json)
        .map_err(|err| {
            internal_err_with_error("saving runtime config rollback snapshot failed", err)
        })?;
    let updated_at = state
        .storage
        .set_app_kv_json(APP_KV_RUNTIME_CONFIG, config_json)
        .map_err(|err| internal_err_with_error("saving runtime config failed", err))?;
    config.updated_at = updated_at;

    let mut changed_scopes = Vec::new();
    if update_global {
        changed_scopes.push("global");
    }
    if update_providers {
        changed_scopes.push("providers");
    }
    if update_channels {
        changed_scopes.push("channels");
    }
    if update_routing {
        changed_scopes.push("routing");
    }
    if update_memory {
        changed_scopes.push("memory");
    }
    if update_extensions {
        changed_scopes.push("extensions");
    }
    if update_security {
        changed_scopes.push("security");
    }
    if update_autonomy_guardrails {
        changed_scopes.push("autonomy_guardrails");
    }
    record_security_audit(
        &headers,
        &state,
        &auth,
        "runtime.config.update",
        "config.runtime",
        "allow",
        None,
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "schema_version": RUNTIME_CONFIG_SCHEMA_VERSION,
            "updated_at": updated_at,
            "rollback_snapshot_updated_at": previous_snapshot_updated_at,
            "changed_scopes": changed_scopes,
            "previous_hash": existing_hash,
            "new_hash": config_hash,
            "trust_lock_refreshed": trust_lock_refreshed,
            "trust_lock_hash": trust_lock_hash,
            "trust_lock_path": lock_path
        })),
    );
    state.channel_runtime.reconcile();

    Ok(Json(UpdateRuntimeConfigResponse { config }))
}

async fn persist_runtime_config_internal(
    state: &AppState,
    config: &RuntimeConfigResponse,
) -> AnyResult<RuntimeConfigResponse> {
    let existing = load_runtime_config(state)?;
    let existing_trust_lock = state.trust_contract_lock.read().await.clone();
    enforce_runtime_global_against_trust_lock(&config.global, &existing_trust_lock)?;
    let existing_json =
        serde_json::to_string(&existing).with_context(|| "serializing runtime config failed")?;
    let config_json =
        serde_json::to_string(config).with_context(|| "serializing runtime config failed")?;
    state
        .storage
        .set_app_kv_json(APP_KV_RUNTIME_CONFIG_LAST_GOOD, existing_json)
        .with_context(|| "saving runtime rollback snapshot failed")?;
    let updated_at = state
        .storage
        .set_app_kv_json(APP_KV_RUNTIME_CONFIG, config_json)
        .with_context(|| "saving runtime config failed")?;
    state.channel_runtime.reconcile();
    let mut updated = config.clone();
    updated.updated_at = updated_at;
    Ok(updated)
}

async fn upsert_runtime_platform_identity_link(
    state: &AppState,
    provider: &str,
    platform_user_id: &str,
    human_identity_id: &str,
) -> AnyResult<RuntimeConfigResponse> {
    let provider = provider.trim().to_ascii_lowercase();
    let platform_user_id = platform_user_id.trim().to_string();
    let human_identity_id = human_identity_id.trim().to_string();
    if provider.is_empty() || platform_user_id.is_empty() || human_identity_id.is_empty() {
        anyhow::bail!("pairing link target is incomplete");
    }

    let mut config = load_runtime_config(state)?;
    if !config
        .routing
        .human_identities
        .iter()
        .any(|item| item.human_identity_id == human_identity_id)
    {
        anyhow::bail!("requested human_identity_id is not defined in runtime routing");
    }
    config.routing.enabled = true;

    if let Some(existing) = config
        .routing
        .platform_identity_links
        .iter_mut()
        .find(|item| {
            item.provider.eq_ignore_ascii_case(&provider)
                && item.platform_user_id == platform_user_id
        })
    {
        existing.human_identity_id = human_identity_id;
        existing.enabled = true;
    } else {
        config
            .routing
            .platform_identity_links
            .push(RuntimePlatformIdentityLinkConfig {
                provider,
                platform_user_id,
                human_identity_id,
                display_name: None,
                enabled: true,
            });
    }

    config = normalize_runtime_config(config);
    validate_runtime_config(&config)?;
    validate_runtime_routing_agent_refs(state, &config.routing)?;
    persist_runtime_config_internal(state, &config).await
}

async fn rollback_runtime_config(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<RollbackRuntimeConfigRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN],
        "runtime.config.rollback",
        "config.runtime",
    )?;

    let current = load_runtime_config(&state)
        .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
    let existing_trust_lock = state.trust_contract_lock.read().await.clone();
    enforce_runtime_global_against_trust_lock(&current.global, &existing_trust_lock)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    let current_json = serde_json::to_string(&current).map_err(|err| {
        internal_err_with_error("serializing current runtime config failed", err.into())
    })?;
    let current_hash = sha256_hex(&current_json);

    let (rollback_json, rollback_source_updated_at) = state
        .storage
        .get_app_kv_json(APP_KV_RUNTIME_CONFIG_LAST_GOOD)
        .map_err(|err| internal_err_with_error("loading runtime rollback snapshot failed", err))?
        .ok_or_else(|| {
            api_error(
                StatusCode::BAD_REQUEST,
                "runtime rollback snapshot is missing; update config at least once before rollback",
            )
        })?;

    let mut rollback_config: RuntimeConfigResponse =
        serde_json::from_str(&rollback_json).map_err(|err| {
            internal_err_with_error("deserializing runtime rollback snapshot failed", err.into())
        })?;
    rollback_config = normalize_runtime_config(rollback_config);
    rollback_config.schema_version = RUNTIME_CONFIG_SCHEMA_VERSION.to_string();
    validate_runtime_config(&rollback_config)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    validate_runtime_routing_agent_refs(&state, &rollback_config.routing)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    let rollback_hash = sha256_hex(&rollback_json);
    let persisted_rollback_json = serde_json::to_string(&rollback_config).map_err(|err| {
        internal_err_with_error("serializing rollback runtime config failed", err.into())
    })?;

    let rollback_snapshot_updated_at = state
        .storage
        .set_app_kv_json(APP_KV_RUNTIME_CONFIG_LAST_GOOD, current_json)
        .map_err(|err| {
            internal_err_with_error(
                "saving current runtime config as rollback snapshot failed",
                err,
            )
        })?;
    let updated_at = state
        .storage
        .set_app_kv_json(APP_KV_RUNTIME_CONFIG, persisted_rollback_json)
        .map_err(|err| internal_err_with_error("writing runtime rollback config failed", err))?;
    rollback_config.updated_at = updated_at;
    let lock_path = state.trust_contract_lock_path.as_str().to_string();
    let refreshed_lock = build_runtime_trust_contract_lock_record(
        &rollback_config.global,
        &auth.principal_id,
        Utc::now().timestamp_millis(),
    )
    .map_err(|err| internal_err_with_error("building runtime trust lock failed", err))?;
    persist_runtime_trust_contract_lock(FsPath::new(&lock_path), &refreshed_lock)
        .map_err(|err| internal_err_with_error("persisting runtime trust lock failed", err))?;
    {
        let mut write = state.trust_contract_lock.write().await;
        *write = refreshed_lock.clone();
    }

    let reason = request
        .reason
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    let audit_reason = reason.clone();
    record_security_audit(
        &headers,
        &state,
        &auth,
        "runtime.config.rollback",
        "config.runtime",
        "allow",
        audit_reason,
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "schema_version": RUNTIME_CONFIG_SCHEMA_VERSION,
            "restored_from_updated_at": rollback_source_updated_at,
            "updated_at": updated_at,
            "rollback_snapshot_updated_at": rollback_snapshot_updated_at,
            "restored_hash": rollback_hash,
            "replaced_hash": current_hash,
            "reason": reason,
            "trust_lock_hash": refreshed_lock.trust_hash,
            "trust_lock_path": lock_path
        })),
    );
    state.channel_runtime.reconcile();

    Ok(Json(RollbackRuntimeConfigResponse {
        config: rollback_config,
        restored_from_updated_at: rollback_source_updated_at,
    }))
}

async fn upsert_runtime_secret(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<UpsertRuntimeSecretRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN],
        "runtime.config.secret.upsert",
        &format!("config.runtime.secret:{}", request.scope.trim()),
    )?;

    let secret_key = runtime_secret_key_from_scope(&request.scope)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    let secret_value = request.secret_value.trim().to_string();
    if secret_value.is_empty() {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "secret_value must not be empty",
        ));
    }

    state
        .secret_store
        .set_raw(&secret_key, &secret_value)
        .map_err(|err| internal_err_with_error("storing runtime secret failed", err))?;
    let secret_ref = runtime_secret_ref_from_key(&secret_key);

    let mut previous_secret_deleted = false;
    if let Some(previous_ref) = request
        .previous_secret_ref
        .as_ref()
        .map(|value| value.trim())
        .filter(|value| !value.is_empty())
    {
        let previous_key = runtime_secret_key_from_ref(previous_ref)
            .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
        if previous_key != secret_key {
            state.secret_store.delete(&previous_key).map_err(|err| {
                internal_err_with_error("deleting previous runtime secret failed", err)
            })?;
            previous_secret_deleted = true;
        }
    }

    record_security_audit(
        &headers,
        &state,
        &auth,
        "runtime.config.secret.upsert",
        "config.runtime.secret",
        "allow",
        None,
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "scope": request.scope.trim(),
            "secret_ref": &secret_ref,
            "secret_store_mode": state.secret_store.mode_name(),
            "previous_secret_ref_provided": request.previous_secret_ref.is_some(),
            "previous_secret_deleted": previous_secret_deleted
        })),
    );
    state.channel_runtime.reconcile();

    Ok(Json(UpsertRuntimeSecretResponse { secret_ref }))
}

async fn delete_runtime_secret(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<DeleteRuntimeSecretRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN],
        "runtime.config.secret.delete",
        "config.runtime.secret",
    )?;

    let secret_key = runtime_secret_key_from_ref(&request.secret_ref)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    state
        .secret_store
        .delete(&secret_key)
        .map_err(|err| internal_err_with_error("deleting runtime secret failed", err))?;

    record_security_audit(
        &headers,
        &state,
        &auth,
        "runtime.config.secret.delete",
        "config.runtime.secret",
        "allow",
        None,
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "secret_ref": request.secret_ref.trim(),
            "secret_store_mode": state.secret_store.mode_name()
        })),
    );
    state.channel_runtime.reconcile();

    Ok(Json(DeleteRuntimeSecretResponse { deleted: true }))
}

fn get_or_create_channel_session(
    state: &AppState,
    session_key: &str,
    title: String,
    desired_agent_id: Option<&str>,
) -> AnyResult<SessionRecord> {
    if let Some(existing) = state.storage.get_session_by_key(session_key)? {
        if let Some(agent_id) = desired_agent_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
        {
            if existing.agent_id != agent_id && existing.agent_id == "default" {
                if let Some(updated) = state
                    .storage
                    .update_session_agent(&existing.session_id, agent_id)?
                {
                    return Ok(updated);
                }
            }
        }
        return Ok(existing);
    }

    let agent_id = desired_agent_id
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("default");

    match state.storage.create_session(NewSession {
        session_key: Some(session_key.to_string()),
        agent_id: agent_id.to_string(),
        title: Some(title),
    }) {
        Ok(created) => Ok(created),
        Err(err) => {
            if is_unique_constraint_violation(&err, Some("sessions.session_key")) {
                if let Some(existing) = state.storage.get_session_by_key(session_key)? {
                    return Ok(existing);
                }
            }
            Err(err)
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct AgentMailAutoExecutionStatus {
    status: String,
    message_id: String,
    thread_id: String,
    recipient_agent_id: String,
    run_id: Option<String>,
    session_id: Option<String>,
    reply_message_id: Option<String>,
    error: Option<String>,
    updated_at: i64,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct AgentMailAutoExecutionOutcome {
    status: String,
    message_id: String,
    thread_id: String,
    recipient_agent_id: String,
    run_id: Option<String>,
    session_id: Option<String>,
    reply_message_id: Option<String>,
}

fn agent_mail_auto_execution_key(message_id: &str, recipient_agent_id: &str) -> String {
    format!(
        "{}:{}:{}",
        APP_KV_AGENT_MAIL_AUTO_PREFIX,
        message_id.trim(),
        recipient_agent_id.trim()
    )
}

fn persist_agent_mail_auto_status(
    state: &AppState,
    status: &AgentMailAutoExecutionStatus,
) -> AnyResult<()> {
    let key = agent_mail_auto_execution_key(&status.message_id, &status.recipient_agent_id);
    state
        .storage
        .set_app_kv_json(&key, serde_json::to_string(status)?)
        .map(|_| ())
}

fn load_agent_mail_auto_status(
    state: &AppState,
    message_id: &str,
    recipient_agent_id: &str,
) -> AnyResult<Option<AgentMailAutoExecutionStatus>> {
    let key = agent_mail_auto_execution_key(message_id, recipient_agent_id);
    let Some((json, _updated_at)) = state.storage.get_app_kv_json(&key)? else {
        return Ok(None);
    };
    Ok(serde_json::from_str(&json).ok())
}

fn agent_mail_message_is_auto_execution(message: &AgentMailMessageRecord) -> bool {
    message
        .metadata_json
        .as_deref()
        .and_then(|json| serde_json::from_str::<serde_json::Value>(json).ok())
        .and_then(|value| value.get("auto_execution").and_then(|item| item.as_bool()))
        .unwrap_or(false)
}

fn bounded_agent_mail_context(messages: &[AgentMailMessageRecord]) -> String {
    let mut lines = Vec::new();
    let mut remaining = AGENT_MAIL_AUTO_MAX_CONTEXT_CHARS;
    for message in messages
        .iter()
        .rev()
        .take(AGENT_MAIL_AUTO_MAX_THREAD_MESSAGES)
        .collect::<Vec<_>>()
        .into_iter()
        .rev()
    {
        if remaining == 0 {
            break;
        }
        let mut body = message.body_text.trim().to_string();
        if body.len() > remaining {
            body.truncate(remaining);
        }
        remaining = remaining.saturating_sub(body.len());
        lines.push(format!(
            "[{} / {}]\n{}",
            message.sender_principal, message.sender_kind, body
        ));
    }
    lines.join("\n\n")
}

fn build_agent_mail_auto_prompt(
    thread: &AgentMailThreadRecord,
    triggering_message: &AgentMailMessageRecord,
    recipient_agent_id: &str,
    messages: &[AgentMailMessageRecord],
) -> String {
    format!(
        "You were directly addressed through CarsinOS Agent Mail.\n\nThread: {}\nTriggering message id: {}\nSender: {} ({})\nRecipient: {}\n\nRecent thread context:\n{}\n\nReply as the addressed teammate. Keep the reply focused on the sender's request.",
        thread.subject,
        triggering_message.message_id,
        triggering_message.sender_principal,
        triggering_message.sender_kind,
        recipient_agent_id,
        bounded_agent_mail_context(messages)
    )
}

fn agent_mail_reply_recipients(
    state: &AppState,
    triggering_message: &AgentMailMessageRecord,
    recipient_agent_id: &str,
) -> AnyResult<Vec<String>> {
    let mut recipients = Vec::new();
    let sender = triggering_message.sender_principal.trim();
    if !sender.is_empty() && sender != recipient_agent_id {
        recipients.push(sender.to_string());
    }
    if recipient_agent_id != "execass"
        && sender != "execass"
        && state.storage.get_agent("execass")?.is_some()
    {
        recipients.push("execass".to_string());
    }
    recipients.sort();
    recipients.dedup();
    Ok(recipients)
}

fn schedule_agent_mail_auto_execution_for_message(state: &AppState, message_id: &str) {
    let Ok(Some(message)) = state.storage.get_agent_mail_message(message_id) else {
        return;
    };
    if agent_mail_message_is_auto_execution(&message) {
        return;
    }
    let Ok(recipients) = state.storage.list_agent_mail_message_recipients(message_id) else {
        return;
    };
    for recipient in recipients
        .into_iter()
        .map(|item| item.recipient_principal)
        .filter(|principal| principal != &message.sender_principal)
        .take(AGENT_MAIL_AUTO_MAX_RECIPIENTS)
    {
        let state_clone = state.clone();
        let message_id = message_id.to_string();
        tokio::spawn(async move {
            if let Err(err) =
                execute_agent_mail_auto_execution(&state_clone, &message_id, &recipient).await
            {
                warn!(
                    message_id = %message_id,
                    recipient_agent_id = %recipient,
                    error = %err,
                    "agent mail auto-execution failed"
                );
            }
        });
    }
}

async fn execute_agent_mail_auto_execution(
    state: &AppState,
    message_id: &str,
    recipient_agent_id: &str,
) -> AnyResult<AgentMailAutoExecutionOutcome> {
    let recipient_agent_id = recipient_agent_id.trim().to_ascii_lowercase();
    let message = state
        .storage
        .get_agent_mail_message(message_id)?
        .with_context(|| format!("agent-mail message not found: {message_id}"))?;
    if message.sender_principal == recipient_agent_id {
        return Ok(AgentMailAutoExecutionOutcome {
            status: "skipped_self".to_string(),
            message_id: message.message_id,
            thread_id: message.thread_id,
            recipient_agent_id,
            run_id: None,
            session_id: None,
            reply_message_id: None,
        });
    }
    if agent_mail_message_is_auto_execution(&message) {
        return Ok(AgentMailAutoExecutionOutcome {
            status: "skipped_generated_reply".to_string(),
            message_id: message.message_id,
            thread_id: message.thread_id,
            recipient_agent_id,
            run_id: None,
            session_id: None,
            reply_message_id: None,
        });
    }
    if let Some(existing) =
        load_agent_mail_auto_status(state, &message.message_id, &recipient_agent_id)?
    {
        return Ok(AgentMailAutoExecutionOutcome {
            status: format!("skipped_existing_{}", existing.status),
            message_id: existing.message_id,
            thread_id: existing.thread_id,
            recipient_agent_id: existing.recipient_agent_id,
            run_id: existing.run_id,
            session_id: existing.session_id,
            reply_message_id: existing.reply_message_id,
        });
    }

    let Some(agent) = state.storage.get_agent(&recipient_agent_id)? else {
        return Ok(AgentMailAutoExecutionOutcome {
            status: "non_agent_recipient".to_string(),
            message_id: message.message_id,
            thread_id: message.thread_id,
            recipient_agent_id,
            run_id: None,
            session_id: None,
            reply_message_id: None,
        });
    };
    if !provider_supported(&agent.model_provider) {
        let status = AgentMailAutoExecutionStatus {
            status: "recipient_not_runnable".to_string(),
            message_id: message.message_id.clone(),
            thread_id: message.thread_id.clone(),
            recipient_agent_id: recipient_agent_id.clone(),
            run_id: None,
            session_id: None,
            reply_message_id: None,
            error: Some("unsupported model_provider".to_string()),
            updated_at: Utc::now().timestamp_millis(),
        };
        persist_agent_mail_auto_status(state, &status)?;
        emit_event(
            state,
            "agent_mail.auto_execution",
            serde_json::json!({
                "message_id": status.message_id,
                "thread_id": status.thread_id,
                "recipient_agent_id": status.recipient_agent_id,
                "status": status.status,
                "error": status.error
            }),
        );
        return Ok(AgentMailAutoExecutionOutcome {
            status: status.status,
            message_id: status.message_id,
            thread_id: status.thread_id,
            recipient_agent_id: status.recipient_agent_id,
            run_id: None,
            session_id: None,
            reply_message_id: None,
        });
    }

    let mut status = AgentMailAutoExecutionStatus {
        status: "started".to_string(),
        message_id: message.message_id.clone(),
        thread_id: message.thread_id.clone(),
        recipient_agent_id: recipient_agent_id.clone(),
        run_id: None,
        session_id: None,
        reply_message_id: None,
        error: None,
        updated_at: Utc::now().timestamp_millis(),
    };
    persist_agent_mail_auto_status(state, &status)?;

    let thread = state
        .storage
        .get_agent_mail_thread(&message.thread_id)?
        .with_context(|| format!("agent-mail thread not found: {}", message.thread_id))?;
    let thread_messages = state.storage.list_agent_mail_messages(
        &message.thread_id,
        AGENT_MAIL_AUTO_MAX_THREAD_MESSAGES as u32,
    )?;
    let session_key = format!(
        "agent-mail:thread:{}:recipient:{}",
        message.thread_id, recipient_agent_id
    );
    let session = get_or_create_channel_session(
        state,
        &session_key,
        format!("Agent Mail: {}", thread.subject),
        Some(&recipient_agent_id),
    )?;
    let prompt =
        build_agent_mail_auto_prompt(&thread, &message, &recipient_agent_id, &thread_messages);
    let _ = state
        .storage
        .create_message(NewMessage {
            session_id: session.session_id.clone(),
            source_channel: "agent_mail".to_string(),
            source_peer_id: Some(message.sender_principal.clone()),
            source_message_id: Some(message.message_id.clone()),
            role: "user".to_string(),
            content_text: prompt,
            content_format: "markdown".to_string(),
        })?
        .with_context(|| {
            format!(
                "mail auto-execution session missing: {}",
                session.session_id
            )
        })?;

    let run = execute_channel_run(
        state,
        &session,
        agent.model_provider.clone(),
        agent.model_id.clone(),
        None,
    )
    .await?;
    status.run_id = Some(run.run_id.clone());
    status.session_id = Some(session.session_id.clone());

    if run.status != "succeeded" {
        status.status = "run_failed".to_string();
        status.error = run.error_text.clone();
        status.updated_at = Utc::now().timestamp_millis();
        persist_agent_mail_auto_status(state, &status)?;
        emit_event(
            state,
            "agent_mail.auto_execution",
            serde_json::json!({
                "message_id": status.message_id,
                "thread_id": status.thread_id,
                "recipient_agent_id": status.recipient_agent_id,
                "run_id": status.run_id,
                "session_id": status.session_id,
                "status": status.status,
                "error": status.error
            }),
        );
        return Ok(AgentMailAutoExecutionOutcome {
            status: status.status,
            message_id: status.message_id,
            thread_id: status.thread_id,
            recipient_agent_id: status.recipient_agent_id,
            run_id: status.run_id,
            session_id: status.session_id,
            reply_message_id: None,
        });
    }

    let Some(reply_text) = latest_assistant_reply_text(state, &session.session_id)? else {
        status.status = "no_assistant_reply".to_string();
        status.updated_at = Utc::now().timestamp_millis();
        persist_agent_mail_auto_status(state, &status)?;
        return Ok(AgentMailAutoExecutionOutcome {
            status: status.status,
            message_id: status.message_id,
            thread_id: status.thread_id,
            recipient_agent_id: status.recipient_agent_id,
            run_id: status.run_id,
            session_id: status.session_id,
            reply_message_id: None,
        });
    };
    let reply_recipients = agent_mail_reply_recipients(state, &message, &recipient_agent_id)?;
    let reply_metadata = serde_json::json!({
        "auto_execution": true,
        "triggering_message_id": message.message_id,
        "run_id": run.run_id,
        "session_id": session.session_id,
        "recipient_agent_id": recipient_agent_id
    });
    let reply = state
        .storage
        .create_agent_mail_message(NewAgentMailMessage {
            thread_id: message.thread_id.clone(),
            sender_principal: recipient_agent_id.clone(),
            sender_kind: "agent".to_string(),
            body_text: reply_text,
            metadata_json: Some(reply_metadata.to_string()),
            recipients: reply_recipients,
        })?
        .with_context(|| format!("reply thread not found: {}", message.thread_id))?;
    let _ = state
        .storage
        .acknowledge_agent_mail_message(&message.message_id, &recipient_agent_id);
    status.status = "succeeded".to_string();
    status.reply_message_id = Some(reply.message_id.clone());
    status.updated_at = Utc::now().timestamp_millis();
    persist_agent_mail_auto_status(state, &status)?;
    emit_event(
        state,
        "agent_mail.auto_execution",
        serde_json::json!({
            "message_id": status.message_id,
            "thread_id": status.thread_id,
            "recipient_agent_id": status.recipient_agent_id,
            "run_id": status.run_id,
            "session_id": status.session_id,
            "reply_message_id": status.reply_message_id,
            "status": status.status
        }),
    );
    Ok(AgentMailAutoExecutionOutcome {
        status: status.status,
        message_id: status.message_id,
        thread_id: status.thread_id,
        recipient_agent_id: status.recipient_agent_id,
        run_id: status.run_id,
        session_id: status.session_id,
        reply_message_id: status.reply_message_id,
    })
}

fn infer_unique_agent_id_for_model(
    state: &AppState,
    model_provider: &str,
    model_id: &str,
) -> AnyResult<Option<String>> {
    let normalized_provider = model_provider.trim();
    let normalized_model_id = model_id.trim();
    if normalized_provider.is_empty() || normalized_model_id.is_empty() {
        return Ok(None);
    }

    let matches = state
        .storage
        .list_agents()?
        .into_iter()
        .filter(|agent| {
            agent.model_provider.trim() == normalized_provider
                && agent.model_id.trim() == normalized_model_id
        })
        .map(|agent| agent.agent_id)
        .collect::<Vec<_>>();

    if matches.len() == 1 {
        Ok(matches.into_iter().next())
    } else {
        Ok(None)
    }
}

fn persist_inferred_channel_default_agent(
    state: &AppState,
    provider: &str,
    inferred_agent_id: &str,
) -> AnyResult<()> {
    let mut config = load_channel_config(state)?;
    let key = match provider {
        "discord" => {
            if config.discord.default_agent_id.is_some() {
                return Ok(());
            }
            config.discord.default_agent_id = Some(inferred_agent_id.to_string());
            APP_KV_CHANNELS_DISCORD
        }
        "telegram" => {
            if config.telegram.default_agent_id.is_some() {
                return Ok(());
            }
            config.telegram.default_agent_id = Some(inferred_agent_id.to_string());
            APP_KV_CHANNELS_TELEGRAM
        }
        _ => anyhow::bail!("unsupported channel provider for inferred agent persistence"),
    };

    let payload = match provider {
        "discord" => serde_json::to_string(&config.discord)
            .with_context(|| "serializing discord channel config failed")?,
        "telegram" => serde_json::to_string(&config.telegram)
            .with_context(|| "serializing telegram channel config failed")?,
        _ => unreachable!(),
    };
    state.storage.set_app_kv_json(key, payload)?;
    Ok(())
}

fn resolve_channel_default_agent_id(
    state: &AppState,
    provider: &str,
    explicit_agent_id: Option<&str>,
    default_model_provider: &str,
    default_model_id: &str,
) -> AnyResult<Option<String>> {
    if let Some(agent_id) = explicit_agent_id
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        return Ok(Some(agent_id.to_string()));
    }

    let inferred =
        infer_unique_agent_id_for_model(state, default_model_provider, default_model_id)?;
    if let Some(agent_id) = inferred.as_deref() {
        persist_inferred_channel_default_agent(state, provider, agent_id)?;
        info!(
            provider,
            agent_id,
            model_provider = default_model_provider,
            model_id = default_model_id,
            "backfilled missing channel default agent from unique model match"
        );
    }
    Ok(inferred)
}

#[derive(Debug, Clone)]
struct ResolvedChannelLaneRoute {
    assistant_agent_id: String,
    human_identity_id: String,
    session_key: String,
    session_title: String,
}

#[derive(Debug, Clone)]
struct ExplicitChannelAgentRoute {
    agent: AgentRecord,
    session_key: String,
    session_title: String,
    message_text: String,
    source: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct StickyChannelAgentRouteRecord {
    agent_id: String,
    expires_at_ms: i64,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum UnmappedChannelRoutingPolicy {
    ChannelDefault,
    ApprovalRequired,
    Block,
}

fn canonical_lane_session_key(lane_id: &str) -> String {
    format!("lane:{lane_id}:main")
}

fn session_key_looks_lane_managed(session_key: &str) -> bool {
    let trimmed = session_key.trim();
    !trimmed.is_empty() && trimmed.starts_with("lane:")
}

fn canonical_lane_id(
    human_identity_id: &str,
    assistant_agent_id: &str,
    memory_policy: Option<&RuntimeLaneMemoryPolicyConfig>,
) -> String {
    memory_policy
        .and_then(|policy| policy.lane_id.clone())
        .unwrap_or_else(|| format!("human:{human_identity_id}:assistant:{assistant_agent_id}"))
}

fn resolve_channel_lane_route(
    state: &AppState,
    routing: &RuntimeRoutingConfig,
    provider: &str,
    platform_user_id: &str,
) -> AnyResult<Option<ResolvedChannelLaneRoute>> {
    if !routing.enabled {
        return Ok(None);
    }

    let normalized_provider = provider.trim().to_ascii_lowercase();
    let normalized_platform_user_id = platform_user_id.trim();
    if normalized_provider.is_empty() || normalized_platform_user_id.is_empty() {
        return Ok(None);
    }

    let Some(link) = routing.platform_identity_links.iter().find(|item| {
        item.enabled
            && item.provider == normalized_provider
            && item.platform_user_id == normalized_platform_user_id
    }) else {
        return Ok(None);
    };

    let Some(human) = routing
        .human_identities
        .iter()
        .find(|item| item.enabled && item.human_identity_id == link.human_identity_id)
    else {
        warn!(
            provider = normalized_provider,
            platform_user_id = normalized_platform_user_id,
            human_identity_id = %link.human_identity_id,
            "routing link references disabled or missing human identity; falling back to channel default"
        );
        return Ok(None);
    };

    let enabled_assignments = routing
        .assistant_assignments
        .iter()
        .filter(|item| item.enabled && item.human_identity_id == human.human_identity_id)
        .collect::<Vec<_>>();
    if enabled_assignments.len() != 1 {
        if !enabled_assignments.is_empty() {
            warn!(
                provider = normalized_provider,
                platform_user_id = normalized_platform_user_id,
                human_identity_id = %human.human_identity_id,
                assignment_count = enabled_assignments.len(),
                "routing has ambiguous enabled assignments for human identity; falling back to channel default"
            );
        }
        return Ok(None);
    }
    let assignment = enabled_assignments[0];
    if state
        .storage
        .get_agent(&assignment.assistant_agent_id)?
        .is_none()
    {
        warn!(
            provider = normalized_provider,
            platform_user_id = normalized_platform_user_id,
            human_identity_id = %human.human_identity_id,
            assistant_agent_id = %assignment.assistant_agent_id,
            "routing references missing assistant agent; falling back to channel default"
        );
        return Ok(None);
    }

    let memory_policy = routing.lane_memory_policies.iter().find(|item| {
        item.human_identity_id == human.human_identity_id
            && item.assistant_agent_id == assignment.assistant_agent_id
    });
    let lane_id = canonical_lane_id(
        &human.human_identity_id,
        &assignment.assistant_agent_id,
        memory_policy,
    );
    let session_key = canonical_lane_session_key(&lane_id);

    Ok(Some(ResolvedChannelLaneRoute {
        assistant_agent_id: assignment.assistant_agent_id.clone(),
        human_identity_id: human.human_identity_id.clone(),
        session_key,
        session_title: format!("{} / {}", human.display_name, assignment.assistant_agent_id),
    }))
}

fn parse_explicit_agent_route_token(text: &str) -> Option<(String, String)> {
    let trimmed = text.trim_start();
    let first = trimmed.split_whitespace().next()?;
    let raw = first.strip_prefix('@')?;
    let candidate = raw
        .trim_end_matches([':', ',', '.', ';'])
        .to_ascii_lowercase();
    if candidate.is_empty()
        || candidate.len() > 64
        || !candidate
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '_' | '-'))
    {
        return None;
    }
    let stripped = trimmed[first.len()..].trim_start().to_string();
    Some((candidate, stripped))
}

fn linked_channel_human_identity_id(
    routing: &RuntimeRoutingConfig,
    provider: &str,
    platform_user_id: &str,
) -> Option<String> {
    if !routing.enabled {
        return None;
    }
    let normalized_provider = provider.trim().to_ascii_lowercase();
    let normalized_platform_user_id = platform_user_id.trim();
    routing
        .platform_identity_links
        .iter()
        .find(|item| {
            item.enabled
                && item.provider == normalized_provider
                && item.platform_user_id == normalized_platform_user_id
        })
        .and_then(|link| {
            routing
                .human_identities
                .iter()
                .find(|human| human.enabled && human.human_identity_id == link.human_identity_id)
                .map(|human| human.human_identity_id.clone())
        })
}

fn channel_route_identity_segment(
    routing: &RuntimeRoutingConfig,
    provider: &str,
    platform_user_id: &str,
) -> String {
    linked_channel_human_identity_id(routing, provider, platform_user_id)
        .map(|human| format!("human:{human}"))
        .unwrap_or_else(|| format!("user:{platform_user_id}"))
}

fn channel_explicit_route_session_key(
    routing: &RuntimeRoutingConfig,
    provider: &str,
    platform_user_id: &str,
    conversation_id: &str,
    agent_id: &str,
) -> String {
    format!(
        "channel-route:{provider}:{}:conversation:{conversation_id}:agent:{agent_id}:main",
        channel_route_identity_segment(routing, provider, platform_user_id)
    )
}

fn channel_sticky_route_key(
    routing: &RuntimeRoutingConfig,
    provider: &str,
    platform_user_id: &str,
    conversation_id: &str,
) -> String {
    format!(
        "{}:{provider}:{}:conversation:{conversation_id}",
        APP_KV_CHANNEL_STICKY_ROUTE_PREFIX,
        channel_route_identity_segment(routing, provider, platform_user_id)
    )
}

fn persist_sticky_channel_agent_route(
    state: &AppState,
    routing: &RuntimeRoutingConfig,
    provider: &str,
    platform_user_id: &str,
    conversation_id: &str,
    agent_id: &str,
) -> AnyResult<()> {
    let key = channel_sticky_route_key(routing, provider, platform_user_id, conversation_id);
    let record = StickyChannelAgentRouteRecord {
        agent_id: agent_id.to_string(),
        expires_at_ms: Utc::now().timestamp_millis() + CHANNEL_STICKY_ROUTE_TTL_MS,
    };
    state
        .storage
        .set_app_kv_json(&key, serde_json::to_string(&record)?)?;
    Ok(())
}

fn load_sticky_channel_agent_route(
    state: &AppState,
    routing: &RuntimeRoutingConfig,
    provider: &str,
    platform_user_id: &str,
    conversation_id: &str,
) -> AnyResult<Option<AgentRecord>> {
    let key = channel_sticky_route_key(routing, provider, platform_user_id, conversation_id);
    let Some((json, _updated_at)) = state.storage.get_app_kv_json(&key)? else {
        return Ok(None);
    };
    let Ok(record) = serde_json::from_str::<StickyChannelAgentRouteRecord>(&json) else {
        return Ok(None);
    };
    if record.expires_at_ms <= Utc::now().timestamp_millis() {
        return Ok(None);
    }
    state.storage.get_agent(&record.agent_id)
}

fn resolve_explicit_or_sticky_channel_agent_route(
    state: &AppState,
    routing: &RuntimeRoutingConfig,
    provider: &str,
    platform_user_id: &str,
    conversation_id: &str,
    text: &str,
) -> AnyResult<(Option<ExplicitChannelAgentRoute>, String, Option<String>)> {
    let normalized_provider = provider.trim().to_ascii_lowercase();
    if let Some((candidate, stripped_text)) = parse_explicit_agent_route_token(text) {
        if let Some(agent) = state.storage.get_agent(&candidate)? {
            persist_sticky_channel_agent_route(
                state,
                routing,
                &normalized_provider,
                platform_user_id,
                conversation_id,
                &agent.agent_id,
            )?;
            let session_key = channel_explicit_route_session_key(
                routing,
                &normalized_provider,
                platform_user_id,
                conversation_id,
                &agent.agent_id,
            );
            return Ok((
                Some(ExplicitChannelAgentRoute {
                    session_title: format!("{normalized_provider} / {}", agent.agent_id),
                    session_key,
                    message_text: if stripped_text.is_empty() {
                        text.trim().to_string()
                    } else {
                        stripped_text
                    },
                    source: "explicit".to_string(),
                    agent,
                }),
                candidate,
                None,
            ));
        }
        return Ok((None, text.to_string(), Some(candidate)));
    }

    if let Some(agent) = load_sticky_channel_agent_route(
        state,
        routing,
        &normalized_provider,
        platform_user_id,
        conversation_id,
    )? {
        let session_key = channel_explicit_route_session_key(
            routing,
            &normalized_provider,
            platform_user_id,
            conversation_id,
            &agent.agent_id,
        );
        return Ok((
            Some(ExplicitChannelAgentRoute {
                session_title: format!("{normalized_provider} / {}", agent.agent_id),
                session_key,
                message_text: text.to_string(),
                source: "sticky".to_string(),
                agent,
            }),
            text.to_string(),
            None,
        ));
    }

    Ok((None, text.to_string(), None))
}

fn resolve_channel_run_model(
    state: &AppState,
    desired_agent_id: Option<&str>,
    requested_model_provider: Option<String>,
    requested_model_id: Option<String>,
    default_model_provider: &str,
    default_model_id: &str,
) -> AnyResult<(String, String)> {
    let requested_model_provider = requested_model_provider
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    let requested_model_id = requested_model_id
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    if let (Some(provider), Some(model_id)) = (requested_model_provider, requested_model_id) {
        return Ok((provider, model_id));
    }
    if let Some(agent_id) = desired_agent_id
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        if let Some(agent) = state.storage.get_agent(agent_id)? {
            return Ok((agent.model_provider, agent.model_id));
        }
    }
    Ok((
        default_model_provider.trim().to_string(),
        default_model_id.trim().to_string(),
    ))
}

fn unmapped_channel_routing_policy(
    routing: &RuntimeRoutingConfig,
    is_dm: bool,
) -> UnmappedChannelRoutingPolicy {
    if !routing.enabled {
        return UnmappedChannelRoutingPolicy::ChannelDefault;
    }

    let raw = if is_dm {
        routing.dm_unmapped_policy.as_str()
    } else {
        routing.shared_unmapped_policy.as_str()
    };
    match raw {
        "approval_required" => UnmappedChannelRoutingPolicy::ApprovalRequired,
        "block" => UnmappedChannelRoutingPolicy::Block,
        _ => UnmappedChannelRoutingPolicy::ChannelDefault,
    }
}

fn resolve_lane_route_for_human_identity(
    state: &AppState,
    routing: &RuntimeRoutingConfig,
    human_identity_id: &str,
    requested_assistant_agent_id: Option<&str>,
) -> AnyResult<Option<ResolvedChannelLaneRoute>> {
    let normalized_human_identity_id = human_identity_id.trim();
    if normalized_human_identity_id.is_empty() {
        return Ok(None);
    }

    let Some(human) = routing
        .human_identities
        .iter()
        .find(|item| item.enabled && item.human_identity_id == normalized_human_identity_id)
    else {
        return Ok(None);
    };

    let requested_assistant_agent_id = requested_assistant_agent_id
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let enabled_assignments = routing
        .assistant_assignments
        .iter()
        .filter(|item| {
            item.enabled
                && item.human_identity_id == human.human_identity_id
                && requested_assistant_agent_id
                    .map(|requested| item.assistant_agent_id == requested)
                    .unwrap_or(true)
        })
        .collect::<Vec<_>>();
    if enabled_assignments.len() != 1 {
        return Ok(None);
    }
    let assignment = enabled_assignments[0];
    if state
        .storage
        .get_agent(&assignment.assistant_agent_id)?
        .is_none()
    {
        return Ok(None);
    }
    let memory_policy = routing.lane_memory_policies.iter().find(|item| {
        item.human_identity_id == human.human_identity_id
            && item.assistant_agent_id == assignment.assistant_agent_id
    });
    let lane_id = canonical_lane_id(
        &human.human_identity_id,
        &assignment.assistant_agent_id,
        memory_policy,
    );
    Ok(Some(ResolvedChannelLaneRoute {
        assistant_agent_id: assignment.assistant_agent_id.clone(),
        human_identity_id: human.human_identity_id.clone(),
        session_key: canonical_lane_session_key(&lane_id),
        session_title: format!("{} / {}", human.display_name, assignment.assistant_agent_id),
    }))
}

fn resolve_lane_route_for_session(
    state: &AppState,
    routing: &RuntimeRoutingConfig,
    session: &SessionRecord,
) -> AnyResult<Option<ResolvedChannelLaneRoute>> {
    let session_key = session.session_key.trim();
    if session_key.is_empty() {
        return Ok(None);
    }

    for assignment in routing
        .assistant_assignments
        .iter()
        .filter(|item| item.enabled && item.assistant_agent_id == session.agent_id)
    {
        let Some(human) = routing
            .human_identities
            .iter()
            .find(|item| item.enabled && item.human_identity_id == assignment.human_identity_id)
        else {
            continue;
        };

        if state
            .storage
            .get_agent(&assignment.assistant_agent_id)?
            .is_none()
        {
            continue;
        }

        let memory_policy = routing.lane_memory_policies.iter().find(|item| {
            item.human_identity_id == human.human_identity_id
                && item.assistant_agent_id == assignment.assistant_agent_id
        });
        let lane_id = canonical_lane_id(
            &human.human_identity_id,
            &assignment.assistant_agent_id,
            memory_policy,
        );
        let canonical_session_key = canonical_lane_session_key(&lane_id);
        if session_key != canonical_session_key {
            continue;
        }

        return Ok(Some(ResolvedChannelLaneRoute {
            assistant_agent_id: assignment.assistant_agent_id.clone(),
            human_identity_id: human.human_identity_id.clone(),
            session_key: canonical_session_key,
            session_title: format!("{} / {}", human.display_name, assignment.assistant_agent_id),
        }));
    }

    Ok(None)
}

#[derive(Debug, Clone)]
struct ResolvedSessionLaneMemoryPolicy {
    policy_scope: String,
    configured_mode: String,
    effective_mode: String,
    human_identity_id: Option<String>,
    lane_id: Option<String>,
}

fn resolve_session_lane_memory_policy(
    state: &AppState,
    runtime_config: &RuntimeConfigResponse,
    session_id: &str,
    assistant_agent_id: &str,
) -> AnyResult<ResolvedSessionLaneMemoryPolicy> {
    let default_mode = runtime_config.memory.blend_mode.clone();
    let default_policy = ResolvedSessionLaneMemoryPolicy {
        policy_scope: "runtime_default".to_string(),
        configured_mode: "inherit_runtime".to_string(),
        effective_mode: default_mode.clone(),
        human_identity_id: None,
        lane_id: None,
    };

    if !runtime_config.routing.enabled {
        return Ok(default_policy);
    }

    let Some(session) = state.storage.get_session(session_id)? else {
        return Ok(default_policy);
    };
    let session_key = session.session_key.trim();
    if session_key.is_empty() {
        return Ok(default_policy);
    }

    for assignment in runtime_config
        .routing
        .assistant_assignments
        .iter()
        .filter(|item| item.enabled && item.assistant_agent_id == assistant_agent_id)
    {
        let Some(human) =
            runtime_config.routing.human_identities.iter().find(|item| {
                item.enabled && item.human_identity_id == assignment.human_identity_id
            })
        else {
            continue;
        };
        let memory_policy = runtime_config
            .routing
            .lane_memory_policies
            .iter()
            .find(|item| {
                item.human_identity_id == human.human_identity_id
                    && item.assistant_agent_id == assignment.assistant_agent_id
            });
        let lane_id = canonical_lane_id(
            &human.human_identity_id,
            &assignment.assistant_agent_id,
            memory_policy,
        );
        if session_key != canonical_lane_session_key(&lane_id) {
            continue;
        }
        let configured_mode = memory_policy
            .map(|policy| policy.memory_mode.clone())
            .unwrap_or_else(|| "inherit_runtime".to_string());
        let effective_mode = if configured_mode == "inherit_runtime" {
            default_mode.clone()
        } else {
            configured_mode.clone()
        };
        return Ok(ResolvedSessionLaneMemoryPolicy {
            policy_scope: "lane".to_string(),
            configured_mode,
            effective_mode,
            human_identity_id: Some(human.human_identity_id.clone()),
            lane_id: Some(lane_id),
        });
    }

    Ok(default_policy)
}

fn resolve_memory_sync_sources(
    state: &AppState,
    runtime_config: &RuntimeConfigResponse,
    requested_sources: &[String],
    requested_human_identity_id: Option<&str>,
    requested_assistant_agent_id: Option<&str>,
) -> AnyResult<Vec<String>> {
    let explicit_sources = normalize_memory_sync_sources(requested_sources);
    if !explicit_sources.is_empty() {
        return Ok(explicit_sources);
    }

    let Some(route) = resolve_requested_job_lane_route(
        state,
        runtime_config,
        requested_human_identity_id,
        requested_assistant_agent_id,
        "memory.sync",
    )?
    else {
        return Ok(runtime_config.memory.memory_md_sources.clone());
    };

    let lane_sources = runtime_config
        .routing
        .lane_memory_policies
        .iter()
        .find(|item| {
            item.human_identity_id == route.human_identity_id
                && item.assistant_agent_id == route.assistant_agent_id
        })
        .map(|item| normalize_memory_sync_sources(&item.local_memory_sources))
        .unwrap_or_default();
    if !lane_sources.is_empty() {
        return Ok(lane_sources);
    }

    Ok(runtime_config.memory.memory_md_sources.clone())
}

fn resolve_requested_job_lane_route(
    state: &AppState,
    runtime_config: &RuntimeConfigResponse,
    requested_human_identity_id: Option<&str>,
    requested_assistant_agent_id: Option<&str>,
    target_label: &str,
) -> AnyResult<Option<ResolvedChannelLaneRoute>> {
    let requested_human_identity_id = requested_human_identity_id
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let requested_assistant_agent_id = requested_assistant_agent_id
        .map(str::trim)
        .filter(|value| !value.is_empty());

    if requested_human_identity_id.is_none() {
        if requested_assistant_agent_id.is_some() {
            anyhow::bail!("INVALID_INPUT: assistant_agent_id requires human_identity_id");
        }
        return Ok(None);
    }

    let human_identity_id = requested_human_identity_id.expect("checked above");
    let Some(route) = resolve_lane_route_for_human_identity(
        state,
        &runtime_config.routing,
        human_identity_id,
        requested_assistant_agent_id,
    )?
    else {
        anyhow::bail!(
            "INVALID_INPUT: unable to resolve a unique enabled lane for requested {} target",
            target_label
        );
    };

    Ok(Some(route))
}

fn memory_mode_uses_numquam(mode: &str) -> bool {
    matches!(
        mode,
        "mno_primary" | "local_augment" | "mno_only" | "mno_with_local_sources"
    )
}

fn memory_mode_includes_local_context(
    mode: &str,
    numquam_enabled: bool,
    numquam_degrade_mode: bool,
    numquam_error_present: bool,
    has_numquam_context: bool,
) -> bool {
    match mode {
        "disabled" | "mno_only" => false,
        "local_only" | "local_fallback_only" | "local_augment" | "mno_with_local_sources" => true,
        _ => {
            numquam_degrade_mode
                || numquam_error_present
                || !numquam_enabled
                || !has_numquam_context
        }
    }
}

fn memory_mode_queries_local_memory(mode: &str) -> bool {
    !matches!(mode, "disabled" | "mno_only")
}

fn normalized_prompt_text(value: &str) -> Option<String> {
    let normalized = value.replace("\r\n", "\n").replace('\r', "\n");
    let trimmed = normalized.trim();
    if trimmed.is_empty() {
        None
    } else {
        Some(trimmed.to_string())
    }
}

fn collect_unique_system_messages(
    messages: &[MessageRecord],
    include_core_seed: bool,
) -> Vec<String> {
    let mut collected = Vec::new();
    for message in messages {
        if message.role != "system" {
            continue;
        }
        if !include_core_seed && message.source_channel == SYSTEM_SOURCE_CHANNEL_CORE {
            continue;
        }
        let Some(text) = normalized_prompt_text(&message.content_text) else {
            continue;
        };
        if !collected.iter().any(|existing| existing == &text) {
            collected.push(text);
        }
    }
    collected
}

fn configured_assistant_core_system_prompt(state: &AppState) -> String {
    match load_runtime_config(state) {
        Ok(config) => config
            .global
            .assistant_system_prompt
            .as_deref()
            .and_then(normalized_prompt_text)
            .unwrap_or_else(|| DEFAULT_ASSISTANT_CORE_SYSTEM_PROMPT.to_string()),
        Err(err) => {
            warn!(
                error = %err,
                "failed loading runtime config for assistant system prompt; using built-in default"
            );
            DEFAULT_ASSISTANT_CORE_SYSTEM_PROMPT.to_string()
        }
    }
}

fn resolve_run_system_messages(
    state: &AppState,
    session_id: &str,
    recent_messages: &[MessageRecord],
) -> AnyResult<Vec<String>> {
    let mut system_messages = collect_unique_system_messages(recent_messages, false);
    if system_messages.is_empty() {
        let expanded_messages = state.storage.list_messages(session_id, 256)?;
        system_messages = collect_unique_system_messages(&expanded_messages, false);
    }
    if system_messages.is_empty() {
        system_messages.push(configured_assistant_core_system_prompt(state));
    }
    Ok(system_messages)
}

fn compose_provider_input(provider_base_input: &str, context_sections: &[String]) -> String {
    if context_sections.is_empty() {
        provider_base_input.to_string()
    } else {
        format!(
            "{}\n\nUser request:\n{}",
            context_sections.join("\n\n"),
            provider_base_input
        )
    }
}

fn compose_provider_system_prompt(system_messages: &[String]) -> Option<String> {
    if system_messages.is_empty() {
        None
    } else {
        Some(system_messages.join("\n\n"))
    }
}

fn text_contains_any(haystack: &str, needles: &[&str]) -> bool {
    needles.iter().any(|needle| haystack.contains(needle))
}

fn contains_digit_near(text: &str, marker: &str, max_chars: usize) -> bool {
    let Some(start) = text.find(marker) else {
        return false;
    };
    text[start..]
        .chars()
        .take(max_chars)
        .any(|value| value.is_ascii_digit())
}

fn contains_20xx_year(text: &str) -> bool {
    text.as_bytes().windows(4).any(|window| {
        window[0] == b'2'
            && window[1] == b'0'
            && window[2].is_ascii_digit()
            && window[3].is_ascii_digit()
    })
}

fn contains_concrete_money_amount(text: &str) -> bool {
    contains_digit_near(text, "$", 24)
        || (text.contains("usd") && text.chars().any(|value| value.is_ascii_digit()))
}

fn contains_concrete_date_value(text: &str) -> bool {
    const MONTHS: &[&str] = &[
        "january",
        "february",
        "march",
        "april",
        "may",
        "june",
        "july",
        "august",
        "september",
        "october",
        "november",
        "december",
    ];
    text_contains_any(text, &["next business day", "t+"])
        || contains_20xx_year(text)
        || (MONTHS.iter().any(|month| text.contains(month))
            && text.chars().any(|value| value.is_ascii_digit()))
}

fn contains_concrete_rollout_scope(text: &str) -> bool {
    text_contains_any(
        text,
        &[
            "internal beta",
            "external pilot",
            "public launch",
            "full public release",
            "early adopter",
            "pilot users",
            "rollout to",
        ],
    ) || (text.contains("users") && text.chars().any(|value| value.is_ascii_digit()))
}

fn user_requested_project_decision_commitment(session_messages: &[MessageRecord]) -> bool {
    let Some(latest_user) = session_messages
        .iter()
        .rev()
        .find(|message| message.role == "user")
    else {
        return false;
    };
    let text = latest_user.content_text.to_ascii_lowercase();
    let mentions_project_decision = text_contains_any(
        &text,
        &[
            "launch date",
            "budget",
            "public scope",
            "scope",
            "rollout",
            "owner",
            "project direction",
            "project-defining",
        ],
    );
    let requests_commitment = text_contains_any(
        &text,
        &[
            "pick",
            "choose",
            "commit",
            "decide",
            "select",
            "set ",
            "handle it yourself",
            "move on",
            "make the call",
            "just pick",
        ],
    );
    mentions_project_decision && requests_commitment
}

fn assistant_output_commits_project_decision(output_text: &str) -> bool {
    let text = output_text.to_ascii_lowercase();
    let mentions_project_decision = text_contains_any(
        &text,
        &[
            "launch date",
            "budget",
            "public scope",
            "scope",
            "rollout",
            "project-defining",
        ],
    );
    if !mentions_project_decision {
        return false;
    }
    let has_concrete_commitment = contains_concrete_money_amount(&text)
        || contains_concrete_date_value(&text)
        || contains_concrete_rollout_scope(&text);
    let speaks_as_commitment = text_contains_any(
        &text,
        &[
            "proposed commitment",
            "proposed commitments",
            "proposed decisions",
            "here are my proposed",
            "i will commit",
            "i'll commit",
            "if these assumptions are acceptable",
            "do you approve these commitments",
        ],
    );
    has_concrete_commitment && (speaks_as_commitment || contains_concrete_money_amount(&text))
}

fn guard_project_decision_commitment(
    session_messages: &[MessageRecord],
    output_text: &str,
) -> Option<String> {
    if user_requested_project_decision_commitment(session_messages)
        && assistant_output_commits_project_decision(output_text)
    {
        if user_requested_monitoring_summary(session_messages) {
            Some(PROJECT_DECISION_MONITORING_GUARDRAIL_MESSAGE.to_string())
        } else {
            Some(PROJECT_DECISION_GUARDRAIL_MESSAGE.to_string())
        }
    } else {
        None
    }
}

fn user_requested_monitoring_summary(session_messages: &[MessageRecord]) -> bool {
    let Some(latest_user) = session_messages
        .iter()
        .rev()
        .find(|message| message.role == "user")
    else {
        return false;
    };
    let text = latest_user.content_text.to_ascii_lowercase();
    text_contains_any(&text, &["monitor", "summarize", "status"])
        && text_contains_any(&text, &["board", "task"])
        && text_contains_any(&text, &["team", "room"])
        && text_contains_any(
            &text,
            &[
                "agent windows",
                "window",
                "session",
                "codexcli",
                "codex cli",
                "claude code",
            ],
        )
}

fn count_project_decision_terms(text: &str) -> usize {
    [
        ["launch date", "launch timing", "launch"].as_slice(),
        ["budget", "budget ceiling", "dollar amount"].as_slice(),
        [
            "public rollout",
            "rollout scope",
            "public scope",
            "public/private rollout",
            "scope",
        ]
        .as_slice(),
        ["owner", "approver", "ownership"].as_slice(),
    ]
    .iter()
    .filter(|terms| text_contains_any(text, terms))
    .count()
}

fn user_requested_pending_project_decision_register(session_messages: &[MessageRecord]) -> bool {
    let Some(latest_user) = session_messages
        .iter()
        .rev()
        .find(|message| message.role == "user")
    else {
        return false;
    };
    let text = latest_user.content_text.to_ascii_lowercase();
    text_contains_any(
        &text,
        &[
            "pending",
            "do not pick",
            "don't pick",
            "do not choose",
            "don't choose",
            "do not decide",
            "don't decide",
            "ask confirmation",
            "ask for confirmation",
        ],
    ) && count_project_decision_terms(&text) >= 2
}

fn assistant_output_mentions_pending_project_decision_register(output_text: &str) -> bool {
    let text = output_text.to_ascii_lowercase();
    text_contains_any(
        &text,
        &["pending", "operator confirmation", "explicit confirmation"],
    ) && count_project_decision_terms(&text) >= 3
}

fn guard_pending_project_decision_register(
    session_messages: &[MessageRecord],
    output_text: &str,
) -> Option<String> {
    if !user_requested_pending_project_decision_register(session_messages)
        || assistant_output_mentions_pending_project_decision_register(output_text)
    {
        return None;
    }
    let trimmed = output_text.trim_end();
    if trimmed.is_empty() {
        Some(PENDING_PROJECT_DECISION_REGISTER_MESSAGE.to_string())
    } else {
        Some(format!(
            "{trimmed}\n\n{PENDING_PROJECT_DECISION_REGISTER_MESSAGE}"
        ))
    }
}

fn user_text_pivots_to_current(text: &str) -> bool {
    text.contains("current")
        && ((text_contains_any(
            text,
            &[
                "current is first",
                "current first",
                "put current first",
                "prioritize current",
                "current is the priority",
            ],
        ) && text_contains_any(text, &["no wait", "actually", "change", "first"]))
            || text_contains_any(
                text,
                &[
                    "for current",
                    "current:",
                    "current work",
                    "current task",
                    "beacon visible but secondary",
                    "beacon should stay visible but secondary",
                    "beacon remains visible but secondary",
                    "keep beacon visible but secondary",
                    "visible but secondary",
                    "beacon secondary",
                ],
            ))
}

fn user_text_pivots_to_beacon(text: &str) -> bool {
    text.contains("beacon")
        && text_contains_any(
            text,
            &[
                "beacon is first",
                "beacon first",
                "put beacon first",
                "prioritize beacon",
                "beacon is the priority",
            ],
        )
}

fn latest_priority_pivot_is_current(session_messages: &[MessageRecord]) -> bool {
    for message in session_messages.iter().rev() {
        if message.role != "user" {
            continue;
        }
        let text = message.content_text.to_ascii_lowercase();
        if user_text_pivots_to_current(&text) {
            return true;
        }
        if user_text_pivots_to_beacon(&text) {
            return false;
        }
    }
    false
}

fn assistant_output_uses_stale_beacon_priority(output_text: &str) -> bool {
    let text = output_text.to_ascii_lowercase();
    let beacon_primary_sentence = text.split(['.', '\n']).any(|part| {
        part.contains("beacon")
            && (part.contains("primary focus")
                || part.contains("current priority focus")
                || part.contains("current priority"))
            && !part.contains("not primary")
            && !part.contains("not as primary")
            && !part.contains("not the primary")
            && !part.contains("visible/tracked only")
            && !part.contains("visible/tracked/secondary only")
            && !part.contains("beacon (visible/tracked")
            && !part.contains("beacon** (visible/tracked")
            && !part.contains("beacon: visible/tracked")
            && !part.contains("beacon set to visible/tracked")
            && !part.contains("beacon** set to visible/tracked")
            && !part.contains("beacon remains visible/tracked")
            && !part.contains("beacon** remains visible/tracked")
            && !part.contains("beacon remaining visible/tracked")
            && !part.contains("beacon** remaining visible/tracked")
            && !part.contains("beacon status: visible/tracked")
            && !part.contains("visible and tracked only")
            && !part.contains("visible but secondary")
            && !part.contains("beacon status")
    });
    text_contains_any(
        &text,
        &[
            "priority focus:** **beacon",
            "priority focus: **beacon",
            "priority focus: beacon",
            "priority project:** beacon",
            "priority project:** **beacon",
            "priority project: beacon",
            "primary priority:** beacon",
            "primary priority:** **beacon",
            "primary priority: beacon",
            "current priority is **beacon",
            "current priority is beacon",
            "current priority for this monitoring window is **beacon",
            "current priority for this monitoring window is beacon",
            "current priority (beacon)",
            "current priority: **beacon",
            "current priority: beacon",
            "current priority focus:** beacon",
            "current priority focus: beacon",
            "current priority focus:** **beacon",
            "beacon is the primary focus",
            "beacon is primary",
            "beacon remains the primary focus",
            "beacon remains primary",
            "beacon remains the priority",
            "beacon remains priority",
        ],
    ) || beacon_primary_sentence
}

fn assistant_output_honors_current_priority(output_text: &str) -> bool {
    let text = output_text.to_ascii_lowercase();
    text_contains_any(
        &text,
        &[
            "current is first",
            "current first",
            "current remains first",
            "current is the priority",
            "current is the primary focus",
            "current is confirmed as the primary focus",
            "current (primary focus)",
            "current focus",
            "current blocker",
            "current priority focus: current",
            "current priority focus:** current",
            "priority has pivoted to current",
            "priority has shifted to current",
        ],
    )
}

fn assistant_output_is_orchestration_status(output_text: &str) -> bool {
    let text = output_text.to_ascii_lowercase();
    text_contains_any(
        &text,
        &[
            "codexcli",
            "codex cli",
            "claude code",
            "board",
            "task",
            "team",
            "window",
            "session",
            "monitor",
        ],
    )
}

fn assistant_output_defers_project_decision(output_text: &str) -> bool {
    let text = output_text.to_ascii_lowercase();
    text_contains_any(
        &text,
        &[
            "can't commit",
            "cannot commit",
            "without explicit operator confirmation",
            "explicit confirmation",
            "pending confirmation",
            "provide or confirm",
        ],
    ) && count_project_decision_terms(&text) >= 3
}

fn latest_priority_pivot_context_section(session_messages: &[MessageRecord]) -> Option<String> {
    if !latest_priority_pivot_is_current(session_messages) {
        return None;
    }
    Some(
        [
            "Latest operator priority override:",
            "- Current is first for the active monitoring window.",
            "- Current is a literal project/lane name in this context, not a generic adjective. Never replace Current with Beacon.",
            "- Beacon remains visible/tracked only. Do not describe Beacon as primary, first, or current priority unless the operator explicitly pivots back.",
            "- Atlas remains risk-watch only unless the operator explicitly changes that scope.",
            "- Keep launch date, budget, public rollout/scope, and owner pending until explicit operator confirmation.",
            "- This priority override persists across follow-up planning/drafting messages until a newer operator priority pivot appears.",
            "- Every planning, status, monitoring, or helper-window summary while this override is active must include: Current Priority Focus: Current; Beacon Status: visible/tracked/secondary only.",
            "- For board, task split, memory note, and team-room drafts, lead with Current-first monitoring and keep Beacon visible/tracked only.",
            "- In artifact drafts, write Current Priority Focus: Current; never write Current Priority Focus: Beacon while this override is active.",
            "- In anti-duplication monitoring answers, include board status, task status, runbook entries, worker/team assignment ownership, and agent-window/session status.",
        ]
        .join("\n"),
    )
}

fn guard_latest_priority_pivot(
    session_messages: &[MessageRecord],
    output_text: &str,
) -> Option<String> {
    if !latest_priority_pivot_is_current(session_messages) {
        return None;
    }
    if assistant_output_uses_stale_beacon_priority(output_text) {
        return Some(LATEST_PRIORITY_PIVOT_GUARDRAIL_MESSAGE.to_string());
    }
    if assistant_output_is_orchestration_status(output_text)
        && !assistant_output_honors_current_priority(output_text)
        && !assistant_output_defers_project_decision(output_text)
    {
        return Some(LATEST_PRIORITY_PIVOT_GUARDRAIL_MESSAGE.to_string());
    }
    None
}

fn guardrail_raw_output_excerpt(output_text: &str) -> String {
    const MAX_EXCERPT_CHARS: usize = 1_200;
    let mut excerpt = String::new();
    for ch in output_text.chars() {
        if excerpt.len() >= MAX_EXCERPT_CHARS {
            break;
        }
        match ch {
            '\r' | '\n' | '\t' => excerpt.push(' '),
            _ if ch.is_control() => excerpt.push(' '),
            _ => excerpt.push(ch),
        }
    }
    if output_text.chars().count() > excerpt.chars().count() {
        excerpt.push_str("...");
    }
    excerpt
}

fn core_tool_command_syntax(command: &str) -> String {
    match command {
        "exec" => "tool.exec <command>".to_string(),
        "web_search" => "tool.web_search <query>".to_string(),
        "web_fetch" => "tool.web_fetch <url>".to_string(),
        "fs_read" => "tool.fs_read <path>".to_string(),
        "fs_write" => "tool.fs_write <path>|<content>".to_string(),
        "process" => "tool.process <status|terminate> [session_id]".to_string(),
        "channel_send" => "tool.channel_send <provider>:<target>|<text>".to_string(),
        "channel_reply" => "tool.channel_reply <provider>:<target>|<text>".to_string(),
        "channel_pin" => "tool.channel_pin <provider>:<target>".to_string(),
        "channel_reaction" => "tool.channel_reaction <provider>:<target>|<reaction>".to_string(),
        other => format!("tool.{other} <args>"),
    }
}

fn approval_label(requires_approval: bool) -> &'static str {
    if requires_approval {
        "approval required"
    } else {
        "no approval required"
    }
}

fn push_tool_inventory_line(
    lines: &mut Vec<String>,
    name_or_syntax: &str,
    risk_level: &str,
    requires_approval: bool,
    detail: Option<&str>,
) {
    match detail {
        Some(detail) if !detail.trim().is_empty() => lines.push(format!(
            "- `{}` ({}, {}; {}).",
            name_or_syntax,
            risk_level,
            approval_label(requires_approval),
            detail.trim()
        )),
        _ => lines.push(format!(
            "- `{}` ({}, {}).",
            name_or_syntax,
            risk_level,
            approval_label(requires_approval)
        )),
    }
}

fn compose_available_tools_system_context(
    state: &AppState,
    runtime_config: &RuntimeConfigResponse,
    plugin_registry: &PluginRegistry,
    connector_tool_bindings: &[ConnectorRuntimeToolBinding],
    session_agent_id: &str,
) -> String {
    let mut lines = vec![
        "Available CarsinOS tools for this run:".to_string(),
        "This inventory is authoritative for the current run. If the operator asks what tools you can use, answer from this list.".to_string(),
        "Do not name tools that are not listed here. Approval-gated tools must wait for CarsinOS approval before execution.".to_string(),
        "Core run tools (CarsinOS tool-line syntax):".to_string(),
    ];

    let mut core_tools = state
        .tool_registry
        .definitions
        .iter()
        .map(|(command, definition)| (*command, definition))
        .collect::<Vec<_>>();
    core_tools.sort_by(
        |(left_command, left_definition), (right_command, right_definition)| {
            left_definition
                .tool_name
                .cmp(right_definition.tool_name)
                .then_with(|| left_command.cmp(right_command))
        },
    );
    for (command, definition) in core_tools {
        let requires_approval = matches!(definition.approval_policy, ToolApprovalPolicy::Always);
        push_tool_inventory_line(
            &mut lines,
            &core_tool_command_syntax(command),
            definition.base_risk_level,
            requires_approval,
            Some(definition.tool_name),
        );
    }

    lines.push("Assistant orchestration tools (Assistant Tools HTTP/MCP bridge):".to_string());
    lines.push(
        "Use these with CarsinOS tool-line syntax: `tool.<tool_name> <json_args>`.".to_string(),
    );
    lines.push(
        "Board/task examples: `tool.assistant.board.snapshot {\"include_cards\":true,\"query\":\"launch readiness\"}` and `tool.assistant.task.update {\"task_id\":\"...\",\"status\":\"in_progress\",\"detail_append\":\"...\"}`."
            .to_string(),
    );
    let mut assistant_tools = assistant_tool_capabilities_payload(runtime_config).tools;
    assistant_tools.sort_by(|left, right| left.tool_name.cmp(&right.tool_name));
    for tool in assistant_tools {
        push_tool_inventory_line(
            &mut lines,
            &format!("tool.{} <json_args>", tool.tool_name),
            &tool.risk_level,
            tool.requires_approval,
            None,
        );
    }

    let mut plugin_tools = Vec::new();
    for manifest in plugin_registry.list_manifests() {
        if !manifest.enabled {
            continue;
        }
        for tool in manifest.capabilities.tools {
            plugin_tools.push((manifest.plugin_id.clone(), tool.name));
        }
    }
    plugin_tools.sort_by(|left, right| left.1.cmp(&right.1).then_with(|| left.0.cmp(&right.0)));
    lines.push("Enabled plugin tools:".to_string());
    if plugin_tools.is_empty() {
        lines.push("- None currently enabled.".to_string());
    } else {
        for (plugin_id, tool_name) in plugin_tools {
            push_tool_inventory_line(
                &mut lines,
                &format!("tool.{tool_name} <args>"),
                "high",
                true,
                Some(&format!("plugin:{plugin_id}")),
            );
        }
    }

    let mut connector_tools = connector_tool_bindings.to_vec();
    connector_tools.sort_by(|left, right| {
        left.published_tool
            .tool_name
            .cmp(&right.published_tool.tool_name)
    });
    lines.push(format!(
        "Connector tools routed to assistant `{}`:",
        session_agent_id
    ));
    if connector_tools.is_empty() {
        lines.push("- None currently routed to this assistant.".to_string());
    } else {
        for binding in connector_tools {
            let (risk_level, requires_approval) =
                connector_risk_and_approval(&binding.published_tool.write_classification);
            push_tool_inventory_line(
                &mut lines,
                &format!("tool.{} <json_args>", binding.published_tool.tool_name),
                risk_level,
                requires_approval,
                Some(&format!(
                    "{} / {}",
                    binding.connector.display_name, binding.published_tool.display_name
                )),
            );
        }
    }

    lines.join("\n")
}

fn ensure_session_core_system_message(state: &AppState, session: &SessionRecord) -> AnyResult<()> {
    let existing_messages = state.storage.list_messages(&session.session_id, 256)?;
    if !collect_unique_system_messages(&existing_messages, true).is_empty() {
        return Ok(());
    }

    let _ = state.storage.create_message(NewMessage {
        session_id: session.session_id.clone(),
        source_channel: SYSTEM_SOURCE_CHANNEL_CORE.to_string(),
        source_peer_id: None,
        source_message_id: None,
        role: "system".to_string(),
        content_text: configured_assistant_core_system_prompt(state),
        content_format: "markdown".to_string(),
    })?;
    Ok(())
}

async fn execute_channel_run(
    state: &AppState,
    session: &SessionRecord,
    model_provider: String,
    model_id: String,
    requested_auth_profile_id: Option<&str>,
) -> AnyResult<RunRecord> {
    ensure_session_core_system_message(state, session).with_context(|| {
        format!(
            "ensuring system prompt for session {} failed",
            session.session_id
        )
    })?;
    let created_run = state
        .storage
        .create_run(NewRun {
            session_id: session.session_id.clone(),
            model_provider,
            model_id,
        })?
        .with_context(|| format!("creating run for session {} failed", session.session_id))?;
    match execute_run_with_lane_control(
        state,
        &created_run,
        &session.agent_id,
        requested_auth_profile_id,
        RunLaneConflictPolicy::Wait,
    )
    .await
    {
        Ok(run) => Ok(run),
        Err(RunLaneExecutionError::Busy) => {
            anyhow::bail!("unexpected channel lane lock busy state")
        }
        Err(RunLaneExecutionError::Execute(err)) => Err(err),
    }
}

async fn ingest_telegram_channel_message(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<IngestTelegramMessageRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    ingest_telegram_channel_message_inner(headers, state, request, None).await
}

async fn ingest_telegram_channel_message_inner(
    headers: HeaderMap,
    state: AppState,
    request: IngestTelegramMessageRequest,
    verified_owner_actor: Option<execass_actor_gate::BaseActorAssurance>,
) -> std::result::Result<Json<IngestChannelMessageResponse>, (StatusCode, Json<ApiError>)> {
    let pipeline_started = Instant::now();
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    let execass_transport_actor = state.execass_actor_gate.classify_untrusted_transport(
        &execass_actor_gate::UntrustedTransportAuthentication {
            auth_method: auth.auth_method.to_string(),
            principal_id: auth.principal_id.clone(),
            claimed_operator_id: headers
                .get("x-operator-id")
                .and_then(|value| value.to_str().ok())
                .map(ToOwned::to_owned),
            claimed_peer_id: Some(request.user_id.to_string()),
            claimed_actor_type: None,
            confirmation_text: Some(request.text.clone()),
            request_correlation_id: request_id_from_headers(&headers),
        },
    );
    debug!(
        actor_type = ?execass_transport_actor.actor_type(),
        may_submit_owner_intent = execass_transport_actor.may_submit_or_amend_owner_intent(),
        "generic Telegram HTTP ingress remains non-authoritative for ExecAss"
    );
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_CHANNEL_ADAPTER, ROLE_OPERATOR_ADMIN],
        "channel.telegram.ingest",
        &format!("telegram:chat:{}", request.chat_id),
    )?;
    require_endpoint_rate_limit_with_error(&state, &auth, "run")?;

    let config = load_channel_config(&state)
        .map_err(|err| internal_err_with_error("loading channel config failed", err))?;
    let runtime_config = load_runtime_config(&state)
        .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
    let route_config = telegram_channel::TelegramAdapterConfig {
        require_mention_in_groups: config.telegram.require_mention_in_groups,
        allowlisted_user_ids: config.telegram.allowlisted_user_ids.clone(),
        dm_policy: config.telegram.dm_policy.clone(),
        group_policy: config.telegram.group_policy.clone(),
        group_allowlisted_user_ids: config.telegram.group_allowlisted_user_ids.clone(),
        allowlisted_chat_ids: config.telegram.allowlisted_chat_ids.clone(),
    };
    let inbound = telegram_channel::TelegramInboundMessage {
        chat_id: request.chat_id,
        user_id: request.user_id,
        text: request.text.clone(),
        is_group_chat: request.is_group_chat,
        mentions_bot: request.mentions_bot,
        reply_to_bot: request.reply_to_bot,
    };
    info!(
        provider = "telegram",
        chat_id = request.chat_id,
        user_id = request.user_id,
        inbound_chars = request.text.len(),
        is_group_chat = request.is_group_chat,
        mentions_bot = request.mentions_bot,
        reply_to_bot = request.reply_to_bot,
        run_immediately = request
            .run_immediately
            .unwrap_or(config.telegram.auto_run_enabled),
        "channel ingest received"
    );

    match telegram_channel::route_message(&route_config, &inbound) {
        telegram_channel::RouteDecision::Reject(reason) => {
            let reason_text = if reason == "sender_not_paired" && !inbound.is_group_chat {
                issue_telegram_pairing_challenge(&state, &config.telegram, &inbound).map_err(
                    |err| internal_err_with_error("issuing telegram pairing challenge failed", err),
                )?
            } else {
                reason.to_string()
            };
            let mut extra_payload = serde_json::json!({
                "decision": "rejected"
            });
            if inbound.is_group_chat
                && config.telegram.auto_leave_unauthorized_groups
                && matches!(reason, "group_disabled" | "group_chat_not_allowlisted")
            {
                let left_group = maybe_leave_telegram_group(&state, inbound.chat_id, reason)
                    .map_err(|err| {
                        internal_err_with_error("leaving unauthorized telegram group failed", err)
                    })?;
                extra_payload["left_group"] = serde_json::Value::Bool(left_group);
            }
            record_security_audit(
                &headers,
                &state,
                &auth,
                "channel.telegram.ingest",
                &format!("telegram:chat:{}", request.chat_id),
                "deny",
                Some(reason_text.clone()),
                StatusCode::OK,
                Some("CHANNEL_ROUTE_REJECTED"),
                None,
                None,
                Some(extra_payload),
            );
            Ok(Json(IngestChannelMessageResponse {
                decision: "rejected".to_string(),
                reason: Some(reason_text),
                session_id: None,
                message_id: None,
                run_id: None,
            }))
        }
        telegram_channel::RouteDecision::Ignore(reason) => {
            let reason_text = reason.to_string();
            record_security_audit(
                &headers,
                &state,
                &auth,
                "channel.telegram.ingest",
                &format!("telegram:chat:{}", request.chat_id),
                "allow",
                Some(reason_text.clone()),
                StatusCode::OK,
                None,
                None,
                None,
                Some(serde_json::json!({
                    "decision": "ignored"
                })),
            );
            Ok(Json(IngestChannelMessageResponse {
                decision: "ignored".to_string(),
                reason: Some(reason_text),
                session_id: None,
                message_id: None,
                run_id: None,
            }))
        }
        telegram_channel::RouteDecision::Accept => {
            if let Some(actor) = verified_owner_actor.as_ref() {
                let (delegation_id, replayed) =
                    admit_listener_verified_owner_intake(&state, actor, &request.text)
                        .await
                        .map_err(|err| {
                            internal_err_with_error(
                                "admitting authenticated Telegram owner intake failed",
                                err,
                            )
                        })?;
                record_security_audit(
                    &headers,
                    &state,
                    &auth,
                    "execass.intake.telegram",
                    &format!("execass:delegation:{delegation_id}"),
                    "allow",
                    Some("authenticated owner intake durably admitted".to_string()),
                    StatusCode::OK,
                    None,
                    None,
                    None,
                    Some(serde_json::json!({
                        "delegation_id": delegation_id,
                        "replayed": replayed,
                        "legacy_run_started": false
                    })),
                );
                return Ok(Json(IngestChannelMessageResponse {
                    decision: "accepted".to_string(),
                    reason: Some(format!("execass_delegation:{delegation_id}")),
                    session_id: None,
                    message_id: None,
                    run_id: None,
                }));
            }
            let session_started = Instant::now();
            let conversation_id = request.chat_id.to_string();
            let platform_user_id = request.user_id.to_string();
            let (explicit_route, fallback_text, unresolved_route_token) =
                resolve_explicit_or_sticky_channel_agent_route(
                    &state,
                    &runtime_config.routing,
                    "telegram",
                    &platform_user_id,
                    &conversation_id,
                    &request.text,
                )
                .map_err(|err| {
                    internal_err_with_error("resolving telegram explicit route failed", err)
                })?;
            let mut route_source = "default".to_string();
            let mut channel_message_text = fallback_text;
            let lane_route = if explicit_route.is_some() {
                None
            } else {
                resolve_channel_lane_route(
                    &state,
                    &runtime_config.routing,
                    "telegram",
                    &platform_user_id,
                )
                .map_err(|err| {
                    internal_err_with_error("resolving telegram lane route failed", err)
                })?
            };
            let (session_key, session_title, desired_agent_id) = if let Some(route) = explicit_route
            {
                route_source = route.source.clone();
                channel_message_text = route.message_text.clone();
                info!(
                    provider = "telegram",
                    assistant_agent_id = %route.agent.agent_id,
                    session_key = %route.session_key,
                    route_source = %route.source,
                    "channel ingest resolved explicit agent route"
                );
                (
                    route.session_key,
                    route.session_title,
                    Some(route.agent.agent_id),
                )
            } else if let Some(route) = lane_route {
                route_source = "lane".to_string();
                info!(
                    provider = "telegram",
                    human_identity_id = %route.human_identity_id,
                    assistant_agent_id = %route.assistant_agent_id,
                    session_key = %route.session_key,
                    "channel ingest resolved canonical lane route"
                );
                (
                    route.session_key,
                    route.session_title,
                    Some(route.assistant_agent_id),
                )
            } else {
                match unmapped_channel_routing_policy(
                    &runtime_config.routing,
                    !request.is_group_chat,
                ) {
                    UnmappedChannelRoutingPolicy::ChannelDefault => {
                        let desired_agent_id = resolve_channel_default_agent_id(
                            &state,
                            "telegram",
                            config.telegram.default_agent_id.as_deref(),
                            &config.telegram.default_model_provider,
                            &config.telegram.default_model_id,
                        )
                        .map_err(|err| {
                            internal_err_with_error("resolving telegram channel agent failed", err)
                        })?;
                        (
                            telegram_channel::session_key(&inbound),
                            format!("telegram {}", request.chat_id),
                            desired_agent_id,
                        )
                    }
                    UnmappedChannelRoutingPolicy::ApprovalRequired => {
                        let reason_text =
                            issue_telegram_pairing_challenge(&state, &config.telegram, &inbound)
                                .map_err(|err| {
                                    internal_err_with_error(
                                        "issuing telegram lane approval challenge failed",
                                        err,
                                    )
                                })?;
                        record_security_audit(
                            &headers,
                            &state,
                            &auth,
                            "channel.telegram.ingest",
                            &format!("telegram:chat:{}", request.chat_id),
                            "deny",
                            Some(reason_text.clone()),
                            StatusCode::OK,
                            Some("CHANNEL_ROUTE_REJECTED"),
                            None,
                            None,
                            Some(serde_json::json!({
                                "decision": "rejected",
                                "policy": "approval_required",
                                "reason_code": "lane_unmapped"
                            })),
                        );
                        return Ok(Json(IngestChannelMessageResponse {
                            decision: "rejected".to_string(),
                            reason: Some(reason_text),
                            session_id: None,
                            message_id: None,
                            run_id: None,
                        }));
                    }
                    UnmappedChannelRoutingPolicy::Block => {
                        let reason_text = if request.is_group_chat {
                            "This Telegram group is not assigned to an assistant yet.".to_string()
                        } else {
                            "This Telegram chat is not assigned to an assistant yet.".to_string()
                        };
                        record_security_audit(
                            &headers,
                            &state,
                            &auth,
                            "channel.telegram.ingest",
                            &format!("telegram:chat:{}", request.chat_id),
                            "deny",
                            Some(reason_text.clone()),
                            StatusCode::OK,
                            Some("CHANNEL_ROUTE_REJECTED"),
                            None,
                            None,
                            Some(serde_json::json!({
                                "decision": "rejected",
                                "policy": "block",
                                "reason_code": "lane_unmapped"
                            })),
                        );
                        return Ok(Json(IngestChannelMessageResponse {
                            decision: "rejected".to_string(),
                            reason: Some(reason_text),
                            session_id: None,
                            message_id: None,
                            run_id: None,
                        }));
                    }
                }
            };
            let session = get_or_create_channel_session(
                &state,
                &session_key,
                session_title,
                desired_agent_id.as_deref(),
            )
            .map_err(|err| internal_err_with_error("creating channel session failed", err))?;
            info!(
                provider = "telegram",
                session_id = %session.session_id,
                agent_id = %session.agent_id,
                session_key = %session_key,
                elapsed_ms = session_started.elapsed().as_millis() as u64,
                "channel ingest session ready"
            );
            let message_started = Instant::now();
            let safe_text = prepare_external_channel_message(
                "telegram",
                &format!("telegram-user:{}", request.user_id),
                &channel_message_text,
            );
            let created_message = state
                .storage
                .create_message(NewMessage {
                    session_id: session.session_id.clone(),
                    source_channel: "telegram".to_string(),
                    source_peer_id: Some(request.user_id.to_string()),
                    source_message_id: request.source_message_id.clone(),
                    role: "user".to_string(),
                    content_text: safe_text,
                    content_format: "markdown".to_string(),
                })
                .map_err(|err| internal_err_with_error("creating channel message failed", err))?
                .ok_or_else(|| {
                    api_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "channel session missing while writing inbound message",
                    )
                })?;
            info!(
                provider = "telegram",
                session_id = %session.session_id,
                message_id = %created_message.message_id,
                source_message_id = ?created_message.source_message_id,
                inbound_chars = created_message.content_text.len(),
                elapsed_ms = message_started.elapsed().as_millis() as u64,
                "channel ingest inbound message stored"
            );

            let run_immediately = request
                .run_immediately
                .unwrap_or(config.telegram.auto_run_enabled);
            let mut run_id = None;
            let mut outbound_reply_status = "not_attempted".to_string();
            let mut outbound_reply_error: Option<String> = None;
            let mut outbound_delivery_mode: Option<String> = None;
            let mut outbound_chunk_count: Option<usize> = None;
            if run_immediately {
                let run_started = Instant::now();
                let (model_provider, model_id) = resolve_channel_run_model(
                    &state,
                    desired_agent_id.as_deref(),
                    request.model_provider,
                    request.model_id,
                    &config.telegram.default_model_provider,
                    &config.telegram.default_model_id,
                )
                .map_err(|err| {
                    internal_err_with_error("resolving telegram run model failed", err)
                })?;
                if model_provider.is_empty() || model_id.is_empty() {
                    return Err(api_error(
                        StatusCode::BAD_REQUEST,
                        "model_provider and model_id must be non-empty when run_immediately=true",
                    ));
                }
                if !provider_supported(&model_provider) {
                    return Err(api_error(
                        StatusCode::BAD_REQUEST,
                        "unsupported model_provider",
                    ));
                }
                let requested_auth_profile_id = request
                    .auth_profile_id
                    .as_ref()
                    .map(|value| value.trim().to_string())
                    .filter(|value| !value.is_empty());
                let run = execute_channel_run(
                    &state,
                    &session,
                    model_provider,
                    model_id,
                    requested_auth_profile_id.as_deref(),
                )
                .await
                .map_err(|err| {
                    internal_err_with_error("executing inbound channel run failed", err)
                })?;
                run_id = Some(run.run_id);
                info!(
                    provider = "telegram",
                    session_id = %session.session_id,
                    run_id = run_id.as_deref(),
                    run_status = %run.status,
                    elapsed_ms = run_started.elapsed().as_millis() as u64,
                    "channel ingest run completed"
                );

                if run.status == "succeeded" {
                    let reply_started = Instant::now();
                    if let Some(reply_text) =
                        latest_assistant_reply_text(&state, &session.session_id).map_err(|err| {
                            internal_err_with_error(
                                "loading assistant reply for telegram dispatch failed",
                                err,
                            )
                        })?
                    {
                        info!(
                            provider = "telegram",
                            session_id = %session.session_id,
                            run_id = run_id.as_deref(),
                            reply_chars = reply_text.len(),
                            elapsed_ms = reply_started.elapsed().as_millis() as u64,
                            "channel ingest assistant reply loaded"
                        );
                        let outbound_target = format!("chat:{}", request.chat_id);
                        let dispatch_started = Instant::now();
                        match dispatch_channel_ingest_reply(
                            &state,
                            "telegram",
                            "send",
                            &outbound_target,
                            &reply_text,
                        ) {
                            Ok((chunk_count, delivery_mode, transport_message_ids)) => {
                                outbound_reply_status = "sent".to_string();
                                outbound_delivery_mode = Some(delivery_mode.to_string());
                                outbound_chunk_count = Some(chunk_count);
                                info!(
                                    provider = "telegram",
                                    session_id = %session.session_id,
                                    run_id = run_id.as_deref(),
                                    delivery_mode,
                                    chunk_count,
                                    transport_message_ids = ?transport_message_ids,
                                    elapsed_ms = dispatch_started.elapsed().as_millis() as u64,
                                    total_pipeline_ms = pipeline_started.elapsed().as_millis() as u64,
                                    "channel ingest outbound dispatch succeeded"
                                );
                                emit_event(
                                    &state,
                                    "channel.ingest.reply_dispatch",
                                    serde_json::json!({
                                        "provider": "telegram",
                                        "target": outbound_target,
                                        "action": "send",
                                        "session_id": &session.session_id,
                                        "run_id": run_id.as_deref(),
                                        "status": "sent",
                                        "delivery_mode": delivery_mode,
                                        "chunk_count": chunk_count,
                                        "transport_message_ids": transport_message_ids
                                    }),
                                );
                            }
                            Err(err) => {
                                outbound_reply_status = "dispatch_failed".to_string();
                                outbound_reply_error = Some(err.to_string());
                                warn!(
                                    provider = "telegram",
                                    session_id = %session.session_id,
                                    run_id = run_id.as_deref(),
                                    elapsed_ms = dispatch_started.elapsed().as_millis() as u64,
                                    total_pipeline_ms = pipeline_started.elapsed().as_millis() as u64,
                                    error = %err,
                                    "channel ingest outbound dispatch failed"
                                );
                                warn!(
                                    "telegram ingest outbound dispatch failed for session {} run {}: {}",
                                    session.session_id,
                                    run_id.as_deref().unwrap_or(""),
                                    err
                                );
                                emit_event(
                                    &state,
                                    "channel.ingest.reply_dispatch",
                                    serde_json::json!({
                                        "provider": "telegram",
                                        "target": outbound_target,
                                        "action": "send",
                                        "session_id": &session.session_id,
                                        "run_id": run_id.as_deref(),
                                        "status": "failed",
                                        "error": err.to_string()
                                    }),
                                );
                            }
                        }
                    } else {
                        outbound_reply_status = "no_assistant_reply".to_string();
                        warn!(
                            provider = "telegram",
                            session_id = %session.session_id,
                            run_id = run_id.as_deref(),
                            total_pipeline_ms = pipeline_started.elapsed().as_millis() as u64,
                            "channel ingest run succeeded but no assistant reply was available"
                        );
                    }
                } else {
                    outbound_reply_status = "run_not_succeeded".to_string();
                    warn!(
                        provider = "telegram",
                        session_id = %session.session_id,
                        run_id = run_id.as_deref(),
                        run_status = %run.status,
                        total_pipeline_ms = pipeline_started.elapsed().as_millis() as u64,
                        "channel ingest run did not succeed"
                    );
                }
            }
            info!(
                provider = "telegram",
                session_id = %session.session_id,
                run_id = run_id.as_deref(),
                run_immediately,
                outbound_reply_status = %outbound_reply_status,
                outbound_delivery_mode = ?outbound_delivery_mode,
                outbound_chunk_count = outbound_chunk_count.unwrap_or(0),
                total_pipeline_ms = pipeline_started.elapsed().as_millis() as u64,
                "channel ingest pipeline complete"
            );

            record_security_audit(
                &headers,
                &state,
                &auth,
                "channel.telegram.ingest",
                &format!("telegram:chat:{}", request.chat_id),
                "allow",
                Some("inbound message ingested".to_string()),
                StatusCode::OK,
                None,
                Some(&session.session_id),
                run_id.as_deref(),
                Some(serde_json::json!({
                    "decision": "accepted",
                    "run_immediately": run_immediately,
                    "outbound_reply_status": outbound_reply_status,
                    "outbound_delivery_mode": outbound_delivery_mode,
                    "outbound_chunk_count": outbound_chunk_count,
                    "outbound_reply_error": outbound_reply_error,
                    "route_source": route_source,
                    "unresolved_route_token": unresolved_route_token
                })),
            );

            Ok(Json(IngestChannelMessageResponse {
                decision: "accepted".to_string(),
                reason: None,
                session_id: Some(session.session_id),
                message_id: Some(created_message.message_id),
                run_id,
            }))
        }
    }
}

async fn ingest_discord_channel_message(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<IngestDiscordMessageRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    ingest_discord_channel_message_inner(headers, state, request, None).await
}

async fn ingest_discord_channel_message_inner(
    headers: HeaderMap,
    state: AppState,
    request: IngestDiscordMessageRequest,
    verified_owner_actor: Option<execass_actor_gate::BaseActorAssurance>,
) -> std::result::Result<Json<IngestChannelMessageResponse>, (StatusCode, Json<ApiError>)> {
    let pipeline_started = Instant::now();
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    let execass_transport_actor = state.execass_actor_gate.classify_untrusted_transport(
        &execass_actor_gate::UntrustedTransportAuthentication {
            auth_method: auth.auth_method.to_string(),
            principal_id: auth.principal_id.clone(),
            claimed_operator_id: headers
                .get("x-operator-id")
                .and_then(|value| value.to_str().ok())
                .map(ToOwned::to_owned),
            claimed_peer_id: Some(request.author_id.clone()),
            claimed_actor_type: None,
            confirmation_text: Some(request.text.clone()),
            request_correlation_id: request_id_from_headers(&headers),
        },
    );
    debug!(
        actor_type = ?execass_transport_actor.actor_type(),
        may_submit_owner_intent = execass_transport_actor.may_submit_or_amend_owner_intent(),
        "generic Discord HTTP ingress remains non-authoritative for ExecAss"
    );
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_CHANNEL_ADAPTER, ROLE_OPERATOR_ADMIN],
        "channel.discord.ingest",
        &format!("discord:channel:{}", request.channel_id),
    )?;
    require_endpoint_rate_limit_with_error(&state, &auth, "run")?;

    let config = load_channel_config(&state)
        .map_err(|err| internal_err_with_error("loading channel config failed", err))?;
    let runtime_config = load_runtime_config(&state)
        .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
    let route_config = discord_channel::DiscordAdapterConfig {
        require_mention_in_guild_channels: config.discord.require_mention_in_guild_channels,
        allowlisted_user_ids: config.discord.allowlisted_user_ids.clone(),
    };
    let inbound = discord_channel::DiscordInboundMessage {
        guild_id: request.guild_id.clone(),
        channel_id: request.channel_id.clone(),
        thread_id: request.thread_id.clone(),
        author_id: request.author_id.clone(),
        text: request.text.clone(),
        mentions_bot: request.mentions_bot,
        is_dm: request.is_dm,
    };
    info!(
        provider = "discord",
        guild_id = ?request.guild_id,
        channel_id = %request.channel_id,
        thread_id = ?request.thread_id,
        author_id = %request.author_id,
        inbound_chars = request.text.len(),
        mentions_bot = request.mentions_bot,
        is_dm = request.is_dm,
        run_immediately = request.run_immediately.unwrap_or(config.discord.auto_run_enabled),
        "channel ingest received"
    );

    match discord_channel::route_message(&route_config, &inbound) {
        discord_channel::RouteDecision::Reject(reason) => {
            let reason_text = reason.to_string();
            record_security_audit(
                &headers,
                &state,
                &auth,
                "channel.discord.ingest",
                &format!("discord:channel:{}", request.channel_id),
                "deny",
                Some(reason_text.clone()),
                StatusCode::OK,
                Some("CHANNEL_ROUTE_REJECTED"),
                None,
                None,
                None,
            );
            Ok(Json(IngestChannelMessageResponse {
                decision: "rejected".to_string(),
                reason: Some(reason_text),
                session_id: None,
                message_id: None,
                run_id: None,
            }))
        }
        discord_channel::RouteDecision::Ignore(reason) => {
            let reason_text = reason.to_string();
            record_security_audit(
                &headers,
                &state,
                &auth,
                "channel.discord.ingest",
                &format!("discord:channel:{}", request.channel_id),
                "allow",
                Some(reason_text.clone()),
                StatusCode::OK,
                None,
                None,
                None,
                Some(serde_json::json!({
                    "decision": "ignored"
                })),
            );
            Ok(Json(IngestChannelMessageResponse {
                decision: "ignored".to_string(),
                reason: Some(reason_text),
                session_id: None,
                message_id: None,
                run_id: None,
            }))
        }
        discord_channel::RouteDecision::Accept => {
            if let Some(actor) = verified_owner_actor.as_ref() {
                let (delegation_id, replayed) =
                    admit_listener_verified_owner_intake(&state, actor, &request.text)
                        .await
                        .map_err(|err| {
                            internal_err_with_error(
                                "admitting authenticated Discord owner intake failed",
                                err,
                            )
                        })?;
                record_security_audit(
                    &headers,
                    &state,
                    &auth,
                    "execass.intake.discord",
                    &format!("execass:delegation:{delegation_id}"),
                    "allow",
                    Some("authenticated owner intake durably admitted".to_string()),
                    StatusCode::OK,
                    None,
                    None,
                    None,
                    Some(serde_json::json!({
                        "delegation_id": delegation_id,
                        "replayed": replayed,
                        "legacy_run_started": false
                    })),
                );
                return Ok(Json(IngestChannelMessageResponse {
                    decision: "accepted".to_string(),
                    reason: Some(format!("execass_delegation:{delegation_id}")),
                    session_id: None,
                    message_id: None,
                    run_id: None,
                }));
            }
            let session_started = Instant::now();
            let conversation_id = request
                .thread_id
                .as_deref()
                .unwrap_or(request.channel_id.as_str())
                .to_string();
            let (explicit_route, fallback_text, unresolved_route_token) =
                resolve_explicit_or_sticky_channel_agent_route(
                    &state,
                    &runtime_config.routing,
                    "discord",
                    &request.author_id,
                    &conversation_id,
                    &request.text,
                )
                .map_err(|err| {
                    internal_err_with_error("resolving discord explicit route failed", err)
                })?;
            let mut route_source = "default".to_string();
            let mut channel_message_text = fallback_text;
            let lane_route = if explicit_route.is_some() {
                None
            } else {
                resolve_channel_lane_route(
                    &state,
                    &runtime_config.routing,
                    "discord",
                    &request.author_id,
                )
                .map_err(|err| {
                    internal_err_with_error("resolving discord lane route failed", err)
                })?
            };
            let (session_key, session_title, desired_agent_id) = if let Some(route) = explicit_route
            {
                route_source = route.source.clone();
                channel_message_text = route.message_text.clone();
                info!(
                    provider = "discord",
                    assistant_agent_id = %route.agent.agent_id,
                    session_key = %route.session_key,
                    route_source = %route.source,
                    "channel ingest resolved explicit agent route"
                );
                (
                    route.session_key,
                    route.session_title,
                    Some(route.agent.agent_id),
                )
            } else if let Some(route) = lane_route {
                route_source = "lane".to_string();
                info!(
                    provider = "discord",
                    human_identity_id = %route.human_identity_id,
                    assistant_agent_id = %route.assistant_agent_id,
                    session_key = %route.session_key,
                    "channel ingest resolved canonical lane route"
                );
                (
                    route.session_key,
                    route.session_title,
                    Some(route.assistant_agent_id),
                )
            } else {
                match unmapped_channel_routing_policy(&runtime_config.routing, request.is_dm) {
                    UnmappedChannelRoutingPolicy::ChannelDefault => {
                        let desired_agent_id = resolve_channel_default_agent_id(
                            &state,
                            "discord",
                            config.discord.default_agent_id.as_deref(),
                            &config.discord.default_model_provider,
                            &config.discord.default_model_id,
                        )
                        .map_err(|err| {
                            internal_err_with_error("resolving discord channel agent failed", err)
                        })?;
                        (
                            discord_channel::session_key(&inbound),
                            format!("discord {}", request.channel_id),
                            desired_agent_id,
                        )
                    }
                    UnmappedChannelRoutingPolicy::ApprovalRequired
                    | UnmappedChannelRoutingPolicy::Block => {
                        let (reason_text, outbound_notice, policy_label) = if request.is_dm {
                            match unmapped_channel_routing_policy(
                                &runtime_config.routing,
                                request.is_dm,
                            ) {
                                UnmappedChannelRoutingPolicy::ApprovalRequired => {
                                    let (reason_code, reply_text) =
                                        issue_discord_pairing_challenge(&state, &inbound).map_err(
                                            |err| {
                                                internal_err_with_error(
                                                    "issuing discord pairing challenge failed",
                                                    err,
                                                )
                                            },
                                        )?;
                                    (reason_code, Some(reply_text), "approval_required")
                                }
                                _ => (
                                    "This Discord chat is locked until it is assigned to an assistant."
                                        .to_string(),
                                    Some(
                                        "This Discord chat is locked until it is assigned to an assistant."
                                            .to_string(),
                                    ),
                                    "block",
                                ),
                            }
                        } else {
                            (
                                "This Discord channel is not assigned to an assistant yet."
                                    .to_string(),
                                None,
                                "block",
                            )
                        };
                        if request.is_dm {
                            let outbound_target = format!("channel:{}", request.channel_id);
                            if let Some(reply_text) = outbound_notice.as_deref() {
                                if let Err(error) = dispatch_channel_ingest_reply(
                                    &state,
                                    "discord",
                                    "send",
                                    &outbound_target,
                                    reply_text,
                                ) {
                                    warn!(
                                        provider = "discord",
                                        channel_id = %request.channel_id,
                                        error = %error,
                                        "failed sending unmapped-lane discord notice"
                                    );
                                }
                            }
                        }
                        record_security_audit(
                            &headers,
                            &state,
                            &auth,
                            "channel.discord.ingest",
                            &format!("discord:channel:{}", request.channel_id),
                            "deny",
                            Some(reason_text.clone()),
                            StatusCode::OK,
                            Some("CHANNEL_ROUTE_REJECTED"),
                            None,
                            None,
                            Some(serde_json::json!({
                                "decision": "rejected",
                                "policy": policy_label,
                                "reason_code": "lane_unmapped"
                            })),
                        );
                        return Ok(Json(IngestChannelMessageResponse {
                            decision: "rejected".to_string(),
                            reason: Some(reason_text),
                            session_id: None,
                            message_id: None,
                            run_id: None,
                        }));
                    }
                }
            };
            let session = get_or_create_channel_session(
                &state,
                &session_key,
                session_title,
                desired_agent_id.as_deref(),
            )
            .map_err(|err| internal_err_with_error("creating channel session failed", err))?;
            info!(
                provider = "discord",
                session_id = %session.session_id,
                agent_id = %session.agent_id,
                session_key = %session_key,
                elapsed_ms = session_started.elapsed().as_millis() as u64,
                "channel ingest session ready"
            );
            let message_started = Instant::now();
            let safe_text = prepare_external_channel_message(
                "discord",
                &format!("discord-user:{}", request.author_id),
                &channel_message_text,
            );
            let created_message = state
                .storage
                .create_message(NewMessage {
                    session_id: session.session_id.clone(),
                    source_channel: "discord".to_string(),
                    source_peer_id: Some(request.author_id.clone()),
                    source_message_id: request.source_message_id.clone(),
                    role: "user".to_string(),
                    content_text: safe_text,
                    content_format: "markdown".to_string(),
                })
                .map_err(|err| internal_err_with_error("creating channel message failed", err))?
                .ok_or_else(|| {
                    api_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "channel session missing while writing inbound message",
                    )
                })?;
            info!(
                provider = "discord",
                session_id = %session.session_id,
                message_id = %created_message.message_id,
                source_message_id = ?created_message.source_message_id,
                inbound_chars = created_message.content_text.len(),
                elapsed_ms = message_started.elapsed().as_millis() as u64,
                "channel ingest inbound message stored"
            );

            let run_immediately = request
                .run_immediately
                .unwrap_or(config.discord.auto_run_enabled);
            let mut run_id = None;
            let mut outbound_reply_status = "not_attempted".to_string();
            let mut outbound_reply_error: Option<String> = None;
            let mut outbound_delivery_mode: Option<String> = None;
            let mut outbound_chunk_count: Option<usize> = None;
            if run_immediately {
                let run_started = Instant::now();
                let (model_provider, model_id) = resolve_channel_run_model(
                    &state,
                    desired_agent_id.as_deref(),
                    request.model_provider,
                    request.model_id,
                    &config.discord.default_model_provider,
                    &config.discord.default_model_id,
                )
                .map_err(|err| {
                    internal_err_with_error("resolving discord run model failed", err)
                })?;
                if model_provider.is_empty() || model_id.is_empty() {
                    return Err(api_error(
                        StatusCode::BAD_REQUEST,
                        "model_provider and model_id must be non-empty when run_immediately=true",
                    ));
                }
                if !provider_supported(&model_provider) {
                    return Err(api_error(
                        StatusCode::BAD_REQUEST,
                        "unsupported model_provider",
                    ));
                }
                let requested_auth_profile_id = request
                    .auth_profile_id
                    .as_ref()
                    .map(|value| value.trim().to_string())
                    .filter(|value| !value.is_empty());
                let run = execute_channel_run(
                    &state,
                    &session,
                    model_provider,
                    model_id,
                    requested_auth_profile_id.as_deref(),
                )
                .await
                .map_err(|err| {
                    internal_err_with_error("executing inbound channel run failed", err)
                })?;
                run_id = Some(run.run_id);
                info!(
                    provider = "discord",
                    session_id = %session.session_id,
                    run_id = run_id.as_deref(),
                    run_status = %run.status,
                    elapsed_ms = run_started.elapsed().as_millis() as u64,
                    "channel ingest run completed"
                );

                if run.status == "succeeded" {
                    let reply_started = Instant::now();
                    if let Some(reply_text) =
                        latest_assistant_reply_text(&state, &session.session_id).map_err(|err| {
                            internal_err_with_error(
                                "loading assistant reply for discord dispatch failed",
                                err,
                            )
                        })?
                    {
                        info!(
                            provider = "discord",
                            session_id = %session.session_id,
                            run_id = run_id.as_deref(),
                            reply_chars = reply_text.len(),
                            elapsed_ms = reply_started.elapsed().as_millis() as u64,
                            "channel ingest assistant reply loaded"
                        );
                        let outbound_channel_id = request
                            .thread_id
                            .as_ref()
                            .map(|value| value.trim().to_string())
                            .filter(|value| !value.is_empty())
                            .unwrap_or_else(|| request.channel_id.clone());
                        let outbound_action = if request
                            .source_message_id
                            .as_ref()
                            .map(|value| !value.trim().is_empty())
                            .unwrap_or(false)
                        {
                            "reply"
                        } else {
                            "send"
                        };
                        let outbound_target = if outbound_action == "reply" {
                            format!(
                                "channel:{}/{}",
                                outbound_channel_id,
                                request
                                    .source_message_id
                                    .as_ref()
                                    .map(|value| value.trim())
                                    .unwrap_or_default()
                            )
                        } else {
                            format!("channel:{}", outbound_channel_id)
                        };
                        let dispatch_started = Instant::now();
                        match dispatch_channel_ingest_reply(
                            &state,
                            "discord",
                            outbound_action,
                            &outbound_target,
                            &reply_text,
                        ) {
                            Ok((chunk_count, delivery_mode, transport_message_ids)) => {
                                outbound_reply_status = "sent".to_string();
                                outbound_delivery_mode = Some(delivery_mode.to_string());
                                outbound_chunk_count = Some(chunk_count);
                                info!(
                                    provider = "discord",
                                    session_id = %session.session_id,
                                    run_id = run_id.as_deref(),
                                    delivery_mode,
                                    chunk_count,
                                    transport_message_ids = ?transport_message_ids,
                                    elapsed_ms = dispatch_started.elapsed().as_millis() as u64,
                                    total_pipeline_ms = pipeline_started.elapsed().as_millis() as u64,
                                    "channel ingest outbound dispatch succeeded"
                                );
                                emit_event(
                                    &state,
                                    "channel.ingest.reply_dispatch",
                                    serde_json::json!({
                                        "provider": "discord",
                                        "target": outbound_target,
                                        "action": outbound_action,
                                        "session_id": &session.session_id,
                                        "run_id": run_id.as_deref(),
                                        "status": "sent",
                                        "delivery_mode": delivery_mode,
                                        "chunk_count": chunk_count,
                                        "transport_message_ids": transport_message_ids
                                    }),
                                );
                            }
                            Err(err) => {
                                outbound_reply_status = "dispatch_failed".to_string();
                                outbound_reply_error = Some(err.to_string());
                                warn!(
                                    provider = "discord",
                                    session_id = %session.session_id,
                                    run_id = run_id.as_deref(),
                                    elapsed_ms = dispatch_started.elapsed().as_millis() as u64,
                                    total_pipeline_ms = pipeline_started.elapsed().as_millis() as u64,
                                    error = %err,
                                    "channel ingest outbound dispatch failed"
                                );
                                warn!(
                                    "discord ingest outbound dispatch failed for session {} run {}: {}",
                                    session.session_id,
                                    run_id.as_deref().unwrap_or(""),
                                    err
                                );
                                emit_event(
                                    &state,
                                    "channel.ingest.reply_dispatch",
                                    serde_json::json!({
                                        "provider": "discord",
                                        "target": outbound_target,
                                        "action": outbound_action,
                                        "session_id": &session.session_id,
                                        "run_id": run_id.as_deref(),
                                        "status": "failed",
                                        "error": err.to_string()
                                    }),
                                );
                            }
                        }
                    } else {
                        outbound_reply_status = "no_assistant_reply".to_string();
                        warn!(
                            provider = "discord",
                            session_id = %session.session_id,
                            run_id = run_id.as_deref(),
                            total_pipeline_ms = pipeline_started.elapsed().as_millis() as u64,
                            "channel ingest run succeeded but no assistant reply was available"
                        );
                    }
                } else {
                    outbound_reply_status = "run_not_succeeded".to_string();
                    warn!(
                        provider = "discord",
                        session_id = %session.session_id,
                        run_id = run_id.as_deref(),
                        run_status = %run.status,
                        total_pipeline_ms = pipeline_started.elapsed().as_millis() as u64,
                        "channel ingest run did not succeed"
                    );
                }
            }
            info!(
                provider = "discord",
                session_id = %session.session_id,
                run_id = run_id.as_deref(),
                run_immediately,
                outbound_reply_status = %outbound_reply_status,
                outbound_delivery_mode = ?outbound_delivery_mode,
                outbound_chunk_count = outbound_chunk_count.unwrap_or(0),
                total_pipeline_ms = pipeline_started.elapsed().as_millis() as u64,
                "channel ingest pipeline complete"
            );

            record_security_audit(
                &headers,
                &state,
                &auth,
                "channel.discord.ingest",
                &format!("discord:channel:{}", request.channel_id),
                "allow",
                Some("inbound message ingested".to_string()),
                StatusCode::OK,
                None,
                Some(&session.session_id),
                run_id.as_deref(),
                Some(serde_json::json!({
                    "decision": "accepted",
                    "run_immediately": run_immediately,
                    "outbound_reply_status": outbound_reply_status,
                    "outbound_delivery_mode": outbound_delivery_mode,
                    "outbound_chunk_count": outbound_chunk_count,
                    "outbound_reply_error": outbound_reply_error,
                    "route_source": route_source,
                    "unresolved_route_token": unresolved_route_token
                })),
            );

            Ok(Json(IngestChannelMessageResponse {
                decision: "accepted".to_string(),
                reason: None,
                session_id: Some(session.session_id),
                message_id: Some(created_message.message_id),
                run_id,
            }))
        }
    }
}

async fn resolve_channel_approval_action(
    headers: HeaderMap,
    state: State<AppState>,
    Json(request): Json<ResolveChannelApprovalActionRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let provider = request.provider.trim().to_ascii_lowercase();
    if provider.is_empty() {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "provider cannot be empty",
        ));
    }

    let action_payload = request.action_payload.trim();
    if action_payload.is_empty() {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "action_payload cannot be empty",
        ));
    }

    let actor_peer_id = request.actor_peer_id.trim();
    if actor_peer_id.is_empty() {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "actor_peer_id cannot be empty",
        ));
    }

    let parsed = match provider.as_str() {
        "telegram" => telegram_channel::parse_approval_callback_payload(action_payload),
        "discord" => discord_channel::parse_approval_custom_id(action_payload),
        _ => {
            return Err(api_error(
                StatusCode::BAD_REQUEST,
                "provider must be one of: telegram, discord",
            ))
        }
    };
    let (approval_id, decision) = parsed.ok_or_else(|| {
        api_error(
            StatusCode::BAD_REQUEST,
            "invalid action_payload for provider approval action format",
        )
    })?;

    let mut forwarded_headers = headers.clone();
    let actor_header = HeaderValue::from_str(actor_peer_id).map_err(|_| {
        api_error(
            StatusCode::BAD_REQUEST,
            "actor_peer_id contains invalid header characters",
        )
    })?;
    forwarded_headers.insert("x-operator-id", actor_header);

    resolve_approval(
        forwarded_headers,
        state,
        Path(approval_id),
        Json(ResolveApprovalRequest {
            decision,
            decided_via: Some(provider),
            decided_by_peer_id: Some(actor_peer_id.to_string()),
        }),
    )
    .await
}

async fn list_jobs(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListJobsQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[
            ROLE_OPERATOR_ADMIN,
            ROLE_OPERATOR_READONLY,
            ROLE_AUTOMATION_RUNNER,
        ],
        "job.list",
        "jobs",
    )?;
    let limit = query.limit.unwrap_or(50).clamp(1, 500);
    let include_disabled = query.include_disabled.unwrap_or(false);
    let items = state
        .storage
        .list_jobs(limit, include_disabled)
        .map_err(|err| internal_err_with_error("listing jobs failed", err))?
        .into_iter()
        .map(to_job_response)
        .collect();
    Ok(Json(ListJobsResponse { items }))
}

async fn job_status(
    headers: HeaderMap,
    State(state): State<AppState>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[
            ROLE_OPERATOR_ADMIN,
            ROLE_OPERATOR_READONLY,
            ROLE_AUTOMATION_RUNNER,
        ],
        "job.status",
        "jobs",
    )?;
    let now_ms = current_time_ms();
    let jobs_total = state
        .storage
        .jobs_total_count()
        .map_err(|err| internal_err_with_error("loading jobs total failed", err))?;
    let jobs_enabled = state
        .storage
        .jobs_enabled_count()
        .map_err(|err| internal_err_with_error("loading enabled jobs count failed", err))?;
    let jobs_due = state
        .storage
        .jobs_due_count(now_ms)
        .map_err(|err| internal_err_with_error("loading due jobs count failed", err))?;
    let runtime_config = load_runtime_config(&state)
        .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
    let numquam = current_numquam_status(&state, Some(&runtime_config)).await;
    let (circuit_breakers, open_circuit_breakers) = collect_breaker_summary(&state, 64, None)
        .map_err(|err| internal_err_with_error("loading circuit breaker summary failed", err))?;
    let top_stop_reasons = collect_top_stop_reasons_from_jobs(&state, 10)
        .map_err(|err| internal_err_with_error("loading top stop reasons failed", err))?;
    Ok(Json(JobStatusResponse {
        scheduler_running: state.scheduler_instance.enabled,
        scheduler_lock: scheduler_lock_state_response(&state),
        jobs_total,
        jobs_enabled,
        jobs_due,
        numquam,
        open_circuit_breakers,
        circuit_breakers,
        top_stop_reasons,
        now_utc: Utc::now(),
    }))
}

async fn add_job(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<CreateJobRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_AUTOMATION_RUNNER],
        "job.create",
        "jobs",
    )?;
    let now_ms = current_time_ms();
    let name = request.name.trim().to_string();
    if name.is_empty() {
        return Err(api_error(StatusCode::BAD_REQUEST, "name cannot be empty"));
    }
    let schedule_kind = normalize_job_schedule_kind(&request.schedule_kind)?;
    let interval_seconds = request.interval_seconds.map(|value| value as i64);
    let run_at_ms = request.run_at_ms;
    let cron_expr = request
        .cron_expr
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.to_string());
    let next_run_at = compute_initial_next_run_at(
        schedule_kind.as_str(),
        interval_seconds,
        run_at_ms,
        cron_expr.as_deref(),
        now_ms,
    )?;
    let payload_value = request
        .payload_json
        .unwrap_or_else(|| serde_json::json!({ "mode": "noop" }));
    let payload_json = materialize_job_payload_with_schedule_metadata(
        payload_value,
        schedule_kind.as_str(),
        cron_expr.as_deref(),
    )?;
    let max_retries = request.max_retries.unwrap_or(1).clamp(0, 10) as i64;
    let retry_backoff_ms = request.retry_backoff_ms.unwrap_or(1_000).clamp(10, 300_000) as i64;
    let timeout_ms = request.timeout_ms.unwrap_or(60_000).clamp(50, 600_000) as i64;
    let enabled = request.enabled.unwrap_or(true);
    let agent_id = request
        .agent_id
        .unwrap_or_else(|| "default".to_string())
        .trim()
        .to_string();
    if agent_id.is_empty() {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "agent_id cannot be empty",
        ));
    }

    let job = state
        .storage
        .create_job(NewJob {
            agent_id,
            name,
            enabled,
            schedule_kind,
            interval_seconds,
            run_at_ms,
            next_run_at,
            payload_json,
            max_retries,
            retry_backoff_ms,
            timeout_ms,
        })
        .map_err(|err| {
            if err.to_string().contains("agent does not exist") {
                api_error(StatusCode::BAD_REQUEST, &err.to_string())
            } else {
                internal_err_with_error("creating job failed", err)
            }
        })?;

    emit_event(
        &state,
        "job.created",
        serde_json::json!({
            "job_id": &job.job_id,
            "agent_id": &job.agent_id,
            "enabled": job.enabled,
            "next_run_at": job.next_run_at
        }),
    );

    Ok((
        StatusCode::CREATED,
        Json(CreateJobResponse {
            job: to_job_response(job),
        }),
    ))
}

async fn update_job(
    headers: HeaderMap,
    State(state): State<AppState>,
    Path(job_id): Path<String>,
    Json(request): Json<UpdateJobRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_AUTOMATION_RUNNER],
        "job.update",
        &format!("job:{job_id}"),
    )?;
    let current = state
        .storage
        .get_job(&job_id)
        .map_err(|err| internal_err_with_error("loading job failed", err))?
        .ok_or_else(|| api_error(StatusCode::NOT_FOUND, "job not found"))?;

    let name = request
        .name
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    let schedule_kind = match request.schedule_kind.as_ref() {
        Some(value) => normalize_job_schedule_kind(value)?,
        None => current.schedule_kind.clone(),
    };
    let interval_seconds = request.interval_seconds.map(|value| value as i64);
    let run_at_ms = request.run_at_ms;
    let current_cron_expr = job_cron_expr_from_payload_json(&current.payload_json);
    let cron_expr = request
        .cron_expr
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.to_string())
        .or(current_cron_expr);
    let next_run_at = compute_updated_next_run_at(
        &current,
        schedule_kind.as_str(),
        interval_seconds,
        run_at_ms,
        cron_expr.as_deref(),
        current_time_ms(),
    )?;
    let payload_base = request.payload_json.unwrap_or_else(|| {
        serde_json::from_str(&current.payload_json)
            .unwrap_or_else(|_| serde_json::json!({ "mode": "noop" }))
    });
    let payload_json = materialize_job_payload_with_schedule_metadata(
        payload_base,
        schedule_kind.as_str(),
        cron_expr.as_deref(),
    )?;

    let updated = state
        .storage
        .update_job(
            &job_id,
            JobUpdatePatch {
                name,
                enabled: request.enabled,
                schedule_kind: Some(schedule_kind),
                interval_seconds,
                run_at_ms,
                next_run_at,
                payload_json: Some(payload_json),
                max_retries: request.max_retries.map(|value| value as i64),
                retry_backoff_ms: request.retry_backoff_ms.map(|value| value as i64),
                timeout_ms: request.timeout_ms.map(|value| value as i64),
            },
        )
        .map_err(|err| internal_err_with_error("updating job failed", err))?
        .ok_or_else(|| api_error(StatusCode::NOT_FOUND, "job not found"))?;

    emit_event(
        &state,
        "job.updated",
        serde_json::json!({
            "job_id": &updated.job_id,
            "enabled": updated.enabled,
            "next_run_at": updated.next_run_at
        }),
    );
    Ok(Json(UpdateJobResponse {
        job: to_job_response(updated),
    }))
}

async fn remove_job(
    headers: HeaderMap,
    State(state): State<AppState>,
    Path(job_id): Path<String>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_AUTOMATION_RUNNER],
        "job.remove",
        &format!("job:{job_id}"),
    )?;
    let removed = state
        .storage
        .remove_job(&job_id)
        .map_err(|err| internal_err_with_error("removing job failed", err))?;
    if !removed {
        return Err(api_error(StatusCode::NOT_FOUND, "job not found"));
    }
    emit_event(
        &state,
        "job.removed",
        serde_json::json!({
            "job_id": &job_id
        }),
    );
    Ok(Json(RemoveJobResponse { job_id, removed }))
}

async fn run_job_now(
    headers: HeaderMap,
    State(state): State<AppState>,
    Path(job_id): Path<String>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_AUTOMATION_RUNNER],
        "job.run_now",
        &format!("job:{job_id}"),
    )?;
    let job = state
        .storage
        .get_job(&job_id)
        .map_err(|err| internal_err_with_error("loading job for run-now failed", err))?
        .ok_or_else(|| api_error(StatusCode::NOT_FOUND, "job not found"))?;
    if carsinos_storage::execass::is_execass_continuation_job_payload(&job.payload_json)
        || carsinos_storage::execass::is_execass_routine_driver_payload(&job.payload_json)
        || carsinos_storage::execass::is_execass_routine_trigger_payload(&job.payload_json)
    {
        return Err(api_error(
            StatusCode::CONFLICT,
            "reserved ExecAss jobs can only run through their fenced scheduler path",
        ));
    }

    let run = execute_job_once(&state, &job, "manual")
        .await
        .map_err(|err| internal_err_with_error("run-now execution failed", err))?;
    Ok(Json(RunJobNowResponse {
        job_run: to_job_run_response(run),
    }))
}

async fn job_history(
    headers: HeaderMap,
    State(state): State<AppState>,
    Path(job_id): Path<String>,
    Query(query): Query<ListJobHistoryQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[
            ROLE_OPERATOR_ADMIN,
            ROLE_OPERATOR_READONLY,
            ROLE_AUTOMATION_RUNNER,
        ],
        "job.history",
        &format!("job:{job_id}"),
    )?;
    let limit = query.limit.unwrap_or(50).clamp(1, 500);
    let items = state
        .storage
        .list_job_runs(&job_id, limit)
        .map_err(|err| internal_err_with_error("listing job history failed", err))?
        .into_iter()
        .map(to_job_run_response)
        .collect();
    Ok(Json(ListJobHistoryResponse { items }))
}

fn mission_control_week_start_ms(
    now_ms: i64,
    requested_week_start_ms: Option<i64>,
    tz_offset_minutes: Option<i32>,
) -> i64 {
    if let Some(explicit) = requested_week_start_ms {
        return explicit;
    }
    let tz_offset_seconds = i64::from(tz_offset_minutes.unwrap_or(0)).saturating_mul(60);
    let local_seconds = now_ms
        .saturating_div(1000)
        .saturating_add(tz_offset_seconds);
    let local_dt = DateTime::<Utc>::from_timestamp(local_seconds, 0).unwrap_or_else(Utc::now);
    let local_date = local_dt.date_naive();
    let weekday_offset = i64::from(local_date.weekday().num_days_from_monday());
    let week_start_local_date = local_date - chrono::Duration::days(weekday_offset);
    let week_start_local_ms = week_start_local_date
        .and_hms_opt(0, 0, 0)
        .map(|value| value.and_utc().timestamp_millis())
        .unwrap_or(now_ms);
    week_start_local_ms.saturating_sub(tz_offset_seconds.saturating_mul(1000))
}

fn mission_control_calendar_job_from_record(
    job: &JobRecord,
) -> MissionControlCalendarWeekJobResponse {
    let lane = if job.enabled
        && job.schedule_kind == "interval"
        && job.interval_seconds.unwrap_or(0) > 0
        && job.interval_seconds.unwrap_or(0) <= 300
    {
        "always_running"
    } else {
        "scheduled"
    };
    let primary_action = if job.enabled { "pause" } else { "resume" };
    MissionControlCalendarWeekJobResponse {
        job_id: job.job_id.clone(),
        name: job.name.clone(),
        agent_id: job.agent_id.clone(),
        enabled: job.enabled,
        schedule_kind: job.schedule_kind.clone(),
        interval_seconds: job.interval_seconds,
        cron_expr: job_cron_expr_from_payload_json(&job.payload_json),
        next_run_at: job.next_run_at,
        last_run_at: job.last_run_at,
        last_error: job.last_error.clone(),
        lane: lane.to_string(),
        primary_action: primary_action.to_string(),
    }
}

const MISSION_CONTROL_USAGE_CONTRACT_VERSION: &str = "mc-usage-v1";
const MISSION_CONTROL_USAGE_MAX_SAMPLE_ROWS: u32 = 50_000;

#[derive(Debug, Clone, Copy, Default)]
struct UsageAggregate {
    estimated_cost_total: f64,
    token_input_total: u64,
    token_output_total: u64,
}

impl UsageAggregate {
    fn add(&mut self, input_tokens: u64, output_tokens: u64, estimated_cost_usd: f64) {
        self.token_input_total = self.token_input_total.saturating_add(input_tokens);
        self.token_output_total = self.token_output_total.saturating_add(output_tokens);
        self.estimated_cost_total += estimated_cost_usd.max(0.0);
    }
}

#[derive(Debug, Clone, Copy)]
struct ParsedRunUsageMetrics {
    input_tokens: u64,
    output_tokens: u64,
    estimated_cost_usd: Option<f64>,
}

fn parse_non_negative_u64(value: Option<&serde_json::Value>) -> Option<u64> {
    match value {
        Some(serde_json::Value::Number(number)) => {
            if let Some(v) = number.as_u64() {
                Some(v)
            } else {
                number
                    .as_i64()
                    .and_then(|v| if v >= 0 { Some(v as u64) } else { None })
            }
        }
        _ => None,
    }
}

fn parse_non_negative_f64(value: Option<&serde_json::Value>) -> Option<f64> {
    match value {
        Some(serde_json::Value::Number(number)) => number.as_f64().filter(|v| *v >= 0.0),
        _ => None,
    }
}

fn parse_run_usage_metrics(usage_json: &str) -> AnyResult<ParsedRunUsageMetrics> {
    let payload: serde_json::Value =
        serde_json::from_str(usage_json).context("run usage_json must be valid JSON")?;
    let provider = payload
        .get("provider")
        .and_then(|value| value.as_object())
        .context("run usage_json provider section missing")?;
    Ok(ParsedRunUsageMetrics {
        input_tokens: parse_non_negative_u64(provider.get("input_tokens")).unwrap_or(0),
        output_tokens: parse_non_negative_u64(provider.get("output_tokens")).unwrap_or(0),
        estimated_cost_usd: parse_non_negative_f64(provider.get("estimated_cost_usd")),
    })
}

fn mission_control_day_start_ms(now_ms: i64, tz_offset_minutes: Option<i32>) -> i64 {
    let tz_offset_seconds = i64::from(tz_offset_minutes.unwrap_or(0)).saturating_mul(60);
    let local_seconds = now_ms
        .saturating_div(1000)
        .saturating_add(tz_offset_seconds);
    let local_dt = DateTime::<Utc>::from_timestamp(local_seconds, 0).unwrap_or_else(Utc::now);
    let local_date = local_dt.date_naive();
    let day_start_local_ms = local_date
        .and_hms_opt(0, 0, 0)
        .map(|value| value.and_utc().timestamp_millis())
        .unwrap_or(now_ms);
    day_start_local_ms.saturating_sub(tz_offset_seconds.saturating_mul(1000))
}

type MissionControlUsageWindow = (String, i64, i64, String);
type ApiErrorResponse = (StatusCode, Json<ApiError>);

fn resolve_mission_control_usage_window(
    now_ms: i64,
    query: &MissionControlUsageQuery,
) -> std::result::Result<MissionControlUsageWindow, ApiErrorResponse> {
    let timezone = query
        .timezone
        .as_ref()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| "UTC".to_string());
    let explicit_start = query.window_start_ms;
    let explicit_end = query.window_end_ms;
    match (explicit_start, explicit_end) {
        (Some(start_ms), Some(end_ms)) => {
            if end_ms <= start_ms {
                return Err(api_error(
                    StatusCode::BAD_REQUEST,
                    "window_end_ms must be greater than window_start_ms",
                ));
            }
            let span_ms = end_ms.saturating_sub(start_ms);
            let max_span_ms = 31_i64
                .saturating_mul(24)
                .saturating_mul(60)
                .saturating_mul(60_000);
            if span_ms > max_span_ms {
                return Err(api_error(
                    StatusCode::BAD_REQUEST,
                    "usage window exceeds maximum 31-day span",
                ));
            }
            Ok(("custom".to_string(), start_ms, end_ms, timezone))
        }
        (Some(_), None) | (None, Some(_)) => Err(api_error(
            StatusCode::BAD_REQUEST,
            "window_start_ms and window_end_ms must be provided together",
        )),
        (None, None) => {
            let window = query
                .window
                .as_ref()
                .map(|value| value.trim().to_ascii_lowercase())
                .filter(|value| !value.is_empty())
                .unwrap_or_else(|| "week".to_string());
            let (start_ms, end_ms) = match window.as_str() {
                "today" => {
                    let start = mission_control_day_start_ms(now_ms, query.tz_offset_minutes);
                    (start, start.saturating_add(24 * 60 * 60_000))
                }
                "week" => {
                    let start =
                        mission_control_week_start_ms(now_ms, None, query.tz_offset_minutes);
                    (start, start.saturating_add(7 * 24 * 60 * 60_000))
                }
                _ => return Err(api_error(
                    StatusCode::BAD_REQUEST,
                    "window must be one of: today, week, or explicit window_start_ms/window_end_ms",
                )),
            };
            Ok((window, start_ms, end_ms, timezone))
        }
    }
}

fn usage_bucket_spec(window: &str, window_start_ms: i64, window_end_ms: i64) -> (usize, i64) {
    match window {
        "today" => (24, 60 * 60_000),
        "week" => (7, 24 * 60 * 60_000),
        _ => {
            let bucket_count = 12usize;
            let span = window_end_ms.saturating_sub(window_start_ms).max(1);
            let bucket_ms = (span / bucket_count as i64).max(1);
            (bucket_count, bucket_ms)
        }
    }
}

fn utc_from_ms(ms: i64) -> DateTime<Utc> {
    DateTime::<Utc>::from_timestamp_millis(ms).unwrap_or_else(Utc::now)
}

fn mission_control_usage_unavailable(
    window: &str,
    timezone: &str,
    reason_code: &str,
    detail: &str,
) -> MissionControlUsageResponse {
    MissionControlUsageResponse {
        contract_version: MISSION_CONTROL_USAGE_CONTRACT_VERSION.to_string(),
        available: false,
        window: window.to_string(),
        timezone: timezone.to_string(),
        currency: "USD".to_string(),
        window_start_utc: None,
        window_end_utc: None,
        estimated_cost_total: None,
        token_input_total: None,
        token_output_total: None,
        by_agent: None,
        by_model: None,
        by_provider: None,
        by_time: None,
        by_job: None,
        by_card: None,
        budget_thresholds: None,
        updated_at_utc: None,
        reason_code: Some(reason_code.to_string()),
        detail: Some(detail.to_string()),
    }
}

fn build_mission_control_usage_response(
    state: &AppState,
    window: &str,
    timezone: &str,
    window_start_ms: i64,
    window_end_ms: i64,
) -> AnyResult<MissionControlUsageResponse> {
    let runtime_config = load_runtime_config(state)?;
    let sample_limit = MISSION_CONTROL_USAGE_MAX_SAMPLE_ROWS;
    let samples = state.storage.list_run_usage_samples_between(
        window_start_ms,
        window_end_ms,
        sample_limit,
    )?;
    let sampled_row_count = samples.len() as u64;
    let sample_limit_reached = sampled_row_count >= u64::from(sample_limit);
    let (bucket_count, bucket_ms) = usage_bucket_spec(window, window_start_ms, window_end_ms);
    let mut by_time = vec![UsageAggregate::default(); bucket_count];
    let mut by_agent: HashMap<String, (String, UsageAggregate)> = HashMap::new();
    let mut by_model: HashMap<String, ((String, String), UsageAggregate)> = HashMap::new();
    let mut by_provider: HashMap<String, (String, UsageAggregate)> = HashMap::new();
    let mut total = UsageAggregate::default();
    let mut valid_rows = 0u64;
    let mut invalid_rows = 0u64;
    let mut first_invalid_run_id: Option<String> = None;
    let mut latest_sample_ms = 0i64;

    for sample in samples {
        let parsed = match parse_run_usage_metrics(&sample.usage_json) {
            Ok(value) => value,
            Err(err) => {
                invalid_rows = invalid_rows.saturating_add(1);
                if first_invalid_run_id.is_none() {
                    first_invalid_run_id = Some(sample.run_id.clone());
                }
                debug!(
                    run_id = %sample.run_id,
                    error = %err,
                    "skipping run usage row with invalid usage_json payload"
                );
                continue;
            }
        };
        let total_tokens = parsed.input_tokens.saturating_add(parsed.output_tokens);
        let estimated_cost_usd = parsed.estimated_cost_usd.unwrap_or_else(|| {
            let policy = lookup_runtime_provider_policy(&runtime_config, &sample.model_provider);
            match policy.and_then(|item| item.usd_per_1k_tokens) {
                Some(rate) => (total_tokens as f64 / 1000.0) * rate,
                None => 0.0,
            }
        });

        valid_rows = valid_rows.saturating_add(1);
        latest_sample_ms = latest_sample_ms.max(sample.sample_ts_ms);
        total.add(
            parsed.input_tokens,
            parsed.output_tokens,
            estimated_cost_usd,
        );

        let agent_entry = by_agent
            .entry(sample.agent_id.clone())
            .or_insert_with(|| (sample.agent_name.clone(), UsageAggregate::default()));
        agent_entry.1.add(
            parsed.input_tokens,
            parsed.output_tokens,
            estimated_cost_usd,
        );

        let model_key = format!("{}::{}", sample.model_provider, sample.model_id);
        let model_entry = by_model.entry(model_key).or_insert_with(|| {
            (
                (sample.model_provider.clone(), sample.model_id.clone()),
                UsageAggregate::default(),
            )
        });
        model_entry.1.add(
            parsed.input_tokens,
            parsed.output_tokens,
            estimated_cost_usd,
        );

        let provider_key = sample.model_provider.to_ascii_lowercase();
        let provider_entry = by_provider
            .entry(provider_key)
            .or_insert_with(|| (sample.model_provider.clone(), UsageAggregate::default()));
        provider_entry.1.add(
            parsed.input_tokens,
            parsed.output_tokens,
            estimated_cost_usd,
        );

        if bucket_count > 0 {
            let relative_ms = sample.sample_ts_ms.saturating_sub(window_start_ms).max(0);
            let mut idx = (relative_ms / bucket_ms) as usize;
            if idx >= bucket_count {
                idx = bucket_count - 1;
            }
            by_time[idx].add(
                parsed.input_tokens,
                parsed.output_tokens,
                estimated_cost_usd,
            );
        }
    }

    if sample_limit_reached {
        let detail = format!(
            "Usage sample window hit safety limit of {} rows; totals may be truncated. Narrow the window for complete results.",
            sample_limit
        );
        return Ok(mission_control_usage_unavailable(
            window,
            timezone,
            "USAGE_SAMPLE_LIMIT_REACHED",
            &detail,
        ));
    }

    if valid_rows == 0 && invalid_rows > 0 {
        return Ok(mission_control_usage_unavailable(
            window,
            timezone,
            "INVALID_USAGE_DATA",
            "Usage metrics are present but could not be parsed safely.",
        ));
    }

    if valid_rows > 0 && invalid_rows > 0 {
        let detail = match first_invalid_run_id.as_deref() {
            Some(run_id) => format!(
                "Usage metrics include {} invalid row(s) (first run_id: {}). Results are withheld to avoid partial totals.",
                invalid_rows, run_id
            ),
            None => format!(
                "Usage metrics include {} invalid row(s). Results are withheld to avoid partial totals.",
                invalid_rows
            ),
        };
        return Ok(mission_control_usage_unavailable(
            window,
            timezone,
            "PARTIAL_USAGE_DATA",
            &detail,
        ));
    }

    let mut by_agent_items = by_agent
        .into_iter()
        .map(
            |(agent_id, (agent_name, totals))| MissionControlUsageByAgentResponse {
                agent_id,
                agent_name,
                estimated_cost_total: totals.estimated_cost_total,
                token_input_total: totals.token_input_total,
                token_output_total: totals.token_output_total,
            },
        )
        .collect::<Vec<_>>();
    by_agent_items.sort_by(|left, right| {
        right
            .estimated_cost_total
            .partial_cmp(&left.estimated_cost_total)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| left.agent_name.cmp(&right.agent_name))
    });

    let mut by_model_items = by_model
        .into_iter()
        .map(
            |(_, ((model_provider, model_id), totals))| MissionControlUsageByModelResponse {
                model_provider,
                model_id,
                estimated_cost_total: totals.estimated_cost_total,
                token_input_total: totals.token_input_total,
                token_output_total: totals.token_output_total,
            },
        )
        .collect::<Vec<_>>();
    by_model_items.sort_by(|left, right| {
        right
            .estimated_cost_total
            .partial_cmp(&left.estimated_cost_total)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| left.model_provider.cmp(&right.model_provider))
            .then_with(|| left.model_id.cmp(&right.model_id))
    });

    let mut by_provider_items = by_provider
        .into_iter()
        .map(
            |(_, (provider, totals))| MissionControlUsageByProviderResponse {
                provider,
                estimated_cost_total: totals.estimated_cost_total,
                token_input_total: totals.token_input_total,
                token_output_total: totals.token_output_total,
            },
        )
        .collect::<Vec<_>>();
    by_provider_items.sort_by(|left, right| {
        right
            .estimated_cost_total
            .partial_cmp(&left.estimated_cost_total)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| left.provider.cmp(&right.provider))
    });

    let by_time_items = (0..bucket_count)
        .map(|index| {
            let start_ms = window_start_ms.saturating_add((index as i64).saturating_mul(bucket_ms));
            let end_ms = (start_ms.saturating_add(bucket_ms)).min(window_end_ms);
            let totals = by_time[index];
            MissionControlUsageByTimeResponse {
                bucket_start_utc: utc_from_ms(start_ms),
                bucket_end_utc: utc_from_ms(end_ms),
                estimated_cost_total: totals.estimated_cost_total,
                token_input_total: totals.token_input_total,
                token_output_total: totals.token_output_total,
            }
        })
        .collect::<Vec<_>>();

    let mut budget_thresholds = Vec::new();
    for provider in &runtime_config.providers {
        if provider.daily_token_budget.is_none() && provider.daily_cost_usd_budget.is_none() {
            continue;
        }
        let usage = by_provider_items
            .iter()
            .find(|item| item.provider.eq_ignore_ascii_case(&provider.provider))
            .cloned()
            .unwrap_or(MissionControlUsageByProviderResponse {
                provider: provider.provider.clone(),
                estimated_cost_total: 0.0,
                token_input_total: 0,
                token_output_total: 0,
            });
        let token_usage_total = usage
            .token_input_total
            .saturating_add(usage.token_output_total);
        let token_ratio = provider.daily_token_budget.and_then(|limit| {
            if limit == 0 {
                None
            } else {
                Some(token_usage_total as f64 / limit as f64)
            }
        });
        let cost_ratio = provider.daily_cost_usd_budget.and_then(|limit| {
            if limit <= 0.0 {
                None
            } else {
                Some(usage.estimated_cost_total / limit)
            }
        });
        budget_thresholds.push(MissionControlUsageBudgetThresholdResponse {
            provider: provider.provider.clone(),
            daily_token_budget: provider.daily_token_budget,
            daily_cost_usd_budget: provider.daily_cost_usd_budget,
            token_usage_total,
            cost_usage_total: usage.estimated_cost_total,
            token_ratio,
            cost_ratio,
        });
    }

    let updated_at_utc = utc_from_ms(if latest_sample_ms > 0 {
        latest_sample_ms
    } else {
        current_time_ms()
    });
    Ok(MissionControlUsageResponse {
        contract_version: MISSION_CONTROL_USAGE_CONTRACT_VERSION.to_string(),
        available: true,
        window: window.to_string(),
        timezone: timezone.to_string(),
        currency: "USD".to_string(),
        window_start_utc: Some(utc_from_ms(window_start_ms)),
        window_end_utc: Some(utc_from_ms(window_end_ms)),
        estimated_cost_total: Some(total.estimated_cost_total),
        token_input_total: Some(total.token_input_total),
        token_output_total: Some(total.token_output_total),
        by_agent: Some(by_agent_items),
        by_model: Some(by_model_items),
        by_provider: Some(by_provider_items),
        by_time: Some(by_time_items),
        by_job: None::<Vec<MissionControlUsageByJobResponse>>,
        by_card: None::<Vec<MissionControlUsageByCardResponse>>,
        budget_thresholds: Some(budget_thresholds),
        updated_at_utc: Some(updated_at_utc),
        reason_code: None,
        detail: None,
    })
}

const STRATEGY_SUMMARY_ITEM_LIMIT: usize = 20;
const STRATEGY_CRITICAL_APPROVAL_AGE_MS: i64 = 30 * 60_000;
const STRATEGY_IMPORT_MAX_BYTES: usize = 16 * 1024;

#[derive(Debug, Deserialize)]
#[serde(deny_unknown_fields)]
struct ImportedBootstrapPresetPayload {
    schema_version: String,
    preset_key: String,
    display_name: String,
    description: String,
    role_label: String,
    provider_path: String,
    default_model_provider: Option<String>,
    default_model_id: Option<String>,
    default_tool_profile: Option<String>,
    default_workspace_root: Option<String>,
    default_reports_to_agent_id: Option<String>,
    setup_notes: Option<String>,
    created_at: i64,
    updated_at: i64,
}

fn normalize_optional_string(value: String) -> std::result::Result<String, ApiErrorResponse> {
    let trimmed = value.trim().to_string();
    if trimmed.is_empty() {
        Err(api_error(StatusCode::BAD_REQUEST, "value cannot be empty"))
    } else {
        Ok(trimmed)
    }
}

fn normalize_string_allow_empty(
    value: String,
) -> std::result::Result<Option<String>, ApiErrorResponse> {
    let trimmed = value.trim().to_string();
    if trimmed.is_empty() {
        Ok(None)
    } else {
        Ok(Some(trimmed))
    }
}

fn normalize_optional_agent_reference(
    value: String,
) -> std::result::Result<Option<String>, ApiErrorResponse> {
    Ok(normalize_string_allow_empty(value)?.map(|trimmed| trimmed.to_ascii_lowercase()))
}

fn normalize_nested_optional_string(
    value: Option<String>,
) -> std::result::Result<Option<String>, ApiErrorResponse> {
    match value {
        Some(inner) => normalize_string_allow_empty(inner),
        None => Ok(None),
    }
}

fn normalize_nested_optional_agent_reference(
    value: Option<String>,
) -> std::result::Result<Option<String>, ApiErrorResponse> {
    match value {
        Some(inner) => normalize_optional_agent_reference(inner),
        None => Ok(None),
    }
}

fn strategy_storage_err(context: &str, err: anyhow::Error) -> ApiErrorResponse {
    let message = err.to_string();
    let lower = message.to_ascii_lowercase();
    if lower.contains("unique")
        || lower.contains("already exists")
        || lower.contains("already linked")
    {
        api_error(StatusCode::CONFLICT, &message)
    } else if lower.contains("not found") {
        api_error(StatusCode::NOT_FOUND, &message)
    } else if lower.contains("does not exist")
        || lower.contains("invalid")
        || lower.contains("must ")
        || lower.contains("cannot")
        || lower.contains("required")
        || lower.contains("unsupported sort")
        || lower.contains("supports at most")
        || lower.contains("cycle")
    {
        api_error(StatusCode::BAD_REQUEST, &message)
    } else {
        internal_err_with_error(context, err)
    }
}

fn load_task_response(
    state: &AppState,
    record: TaskRecord,
) -> std::result::Result<carsinos_protocol::TaskResponse, ApiErrorResponse> {
    let runtime_link = state
        .storage
        .resolve_task_runtime_link(&record)
        .map_err(|err| internal_err_with_error("resolving task runtime link failed", err))?;
    Ok(to_task_response(record, runtime_link))
}

fn collect_goal_records(
    state: &AppState,
) -> std::result::Result<Vec<GoalRecord>, ApiErrorResponse> {
    let mut cursor = None;
    let mut items = Vec::new();
    loop {
        let page = state
            .storage
            .list_goals(GoalListFilter {
                limit: 200,
                cursor: cursor.clone(),
                ..GoalListFilter::default()
            })
            .map_err(|err| strategy_storage_err("collecting goals failed", err))?;
        items.extend(page.items);
        if page.next_cursor.is_none() {
            break;
        }
        cursor = page.next_cursor;
    }
    Ok(items)
}

fn collect_project_records(
    state: &AppState,
) -> std::result::Result<Vec<ProjectRecord>, ApiErrorResponse> {
    let mut cursor = None;
    let mut items = Vec::new();
    loop {
        let page = state
            .storage
            .list_projects(ProjectListFilter {
                limit: 200,
                cursor: cursor.clone(),
                ..ProjectListFilter::default()
            })
            .map_err(|err| strategy_storage_err("collecting projects failed", err))?;
        items.extend(page.items);
        if page.next_cursor.is_none() {
            break;
        }
        cursor = page.next_cursor;
    }
    Ok(items)
}

fn collect_task_records(
    state: &AppState,
    filter: TaskListFilter,
) -> std::result::Result<Vec<TaskRecord>, ApiErrorResponse> {
    let mut cursor = None;
    let mut items = Vec::new();
    loop {
        let mut page_filter = filter.clone();
        page_filter.limit = 200;
        page_filter.cursor = cursor.clone();
        let page = state
            .storage
            .list_tasks(page_filter)
            .map_err(|err| strategy_storage_err("collecting tasks failed", err))?;
        items.extend(page.items);
        if page.next_cursor.is_none() {
            break;
        }
        cursor = page.next_cursor;
    }
    Ok(items)
}

fn goal_progress_pct(state: &AppState, goal_id: &str) -> std::result::Result<u8, ApiErrorResponse> {
    let tasks = collect_task_records(
        state,
        TaskListFilter {
            goal_id: Some(goal_id.to_string()),
            now_ms: current_time_ms(),
            ..TaskListFilter::default()
        },
    )?;
    let leaf_parent_ids = tasks
        .iter()
        .filter_map(|task| task.parent_task_id.as_ref())
        .map(String::as_str)
        .collect::<HashSet<_>>();
    let mut denominator = 0u64;
    let mut numerator = 0u64;
    for task in tasks
        .iter()
        .filter(|task| !leaf_parent_ids.contains(task.task_id.as_str()))
    {
        denominator = denominator.saturating_add(1);
        if task.status == "done" {
            numerator = numerator.saturating_add(1);
        }
    }
    if denominator == 0 {
        return Ok(0);
    }
    Ok((((numerator as f64 / denominator as f64) * 100.0).round() as i64).clamp(0, 100) as u8)
}

fn task_projection(
    task: &TaskRecord,
    agents_by_id: &HashMap<String, AgentRecord>,
    projects_by_id: &HashMap<String, ProjectRecord>,
    goals_by_id: &HashMap<String, GoalRecord>,
) -> Option<StrategyTaskListItemResponse> {
    let project = projects_by_id.get(&task.project_id)?;
    let goal = goals_by_id.get(&project.goal_id)?;
    Some(StrategyTaskListItemResponse {
        task_id: task.task_id.clone(),
        title: task.title.clone(),
        status: task.status.clone(),
        priority: task.priority.clone(),
        owner_agent_id: task.owner_agent_id.clone(),
        owner_name: task
            .owner_agent_id
            .as_ref()
            .and_then(|agent_id| agents_by_id.get(agent_id))
            .map(|agent| agent.name.clone()),
        project_id: project.project_id.clone(),
        project_name: project.name.clone(),
        goal_id: goal.goal_id.clone(),
        goal_title: goal.title.clone(),
        updated_at: task.updated_at,
        due_at: task.due_at,
        blocked_reason: task.blocked_reason.clone(),
    })
}

fn parse_imported_bootstrap_preset(
    payload: &serde_json::Value,
) -> std::result::Result<ImportedBootstrapPresetPayload, ApiErrorResponse> {
    let bytes = serde_json::to_vec(payload).map_err(|err| {
        internal_err_with_error("serializing preset import payload failed", err.into())
    })?;
    if bytes.len() > STRATEGY_IMPORT_MAX_BYTES {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "bootstrap preset import exceeds 16 KB limit",
        ));
    }
    scan_bootstrap_preset_payload(payload)?;
    let parsed: ImportedBootstrapPresetPayload =
        serde_json::from_value(payload.clone()).map_err(|_| {
            api_error(
                StatusCode::BAD_REQUEST,
                "bootstrap preset import payload is invalid",
            )
        })?;
    if parsed.schema_version != "mc-bootstrap-preset-v1" {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "bootstrap preset schema_version must be mc-bootstrap-preset-v1",
        ));
    }
    let _ = (parsed.created_at, parsed.updated_at);
    Ok(parsed)
}

fn scan_bootstrap_preset_payload(
    value: &serde_json::Value,
) -> std::result::Result<(), ApiErrorResponse> {
    match value {
        serde_json::Value::Object(map) => {
            for (key, value) in map {
                let lower = key.to_ascii_lowercase();
                if [
                    "token",
                    "secret",
                    "password",
                    "api_key",
                    "access_token",
                    "refresh_token",
                ]
                .iter()
                .any(|fragment| lower.contains(fragment))
                {
                    return Err(api_error(
                        StatusCode::BAD_REQUEST,
                        "bootstrap preset import contains secret-shaped keys",
                    ));
                }
                scan_bootstrap_preset_payload(value)?;
            }
        }
        serde_json::Value::Array(items) => {
            for item in items {
                scan_bootstrap_preset_payload(item)?;
            }
        }
        serde_json::Value::String(text)
            if text.starts_with("Bearer ")
                || text.starts_with("sk-")
                || text.starts_with("sess-") =>
        {
            return Err(api_error(
                StatusCode::BAD_REQUEST,
                "bootstrap preset import contains secret-shaped values",
            ));
        }
        _ => {}
    }
    Ok(())
}

async fn strategy_summary(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<StrategySummaryQuery>,
) -> std::result::Result<impl IntoResponse, ApiErrorResponse> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[
            ROLE_OPERATOR_ADMIN,
            ROLE_OPERATOR_READONLY,
            ROLE_AUTOMATION_RUNNER,
        ],
        "mission_control.strategy_summary",
        "mission_control.strategy",
    )?;
    let now_ms = current_time_ms();
    let day_start_ms = mission_control_day_start_ms(now_ms, query.tz_offset_minutes);
    let day_end_ms = day_start_ms.saturating_add(24 * 60 * 60_000);

    let goals = collect_goal_records(&state)?;
    let projects = collect_project_records(&state)?;
    let tasks = collect_task_records(
        &state,
        TaskListFilter {
            now_ms,
            ..TaskListFilter::default()
        },
    )?;
    let agents = state.storage.list_agents().map_err(|err| {
        internal_err_with_error("listing agents for strategy summary failed", err)
    })?;
    let approvals = state
        .storage
        .list_approvals(Some("requested"), 10_000)
        .map_err(|err| {
            internal_err_with_error("listing approvals for strategy summary failed", err)
        })?;

    let goals_by_id = goals
        .iter()
        .cloned()
        .map(|goal| (goal.goal_id.clone(), goal))
        .collect::<HashMap<_, _>>();
    let projects_by_id = projects
        .iter()
        .cloned()
        .map(|project| (project.project_id.clone(), project))
        .collect::<HashMap<_, _>>();
    let agents_by_id = agents
        .iter()
        .cloned()
        .map(|agent| (agent.agent_id.clone(), agent))
        .collect::<HashMap<_, _>>();
    let tasks_by_id = tasks
        .iter()
        .cloned()
        .map(|task| (task.task_id.clone(), task))
        .collect::<HashMap<_, _>>();

    let mut blocked_tasks_all = tasks
        .iter()
        .filter(|task| task.status == "blocked")
        .filter_map(|task| task_projection(task, &agents_by_id, &projects_by_id, &goals_by_id))
        .collect::<Vec<_>>();
    blocked_tasks_all.sort_by_key(|item| std::cmp::Reverse(item.updated_at));

    let mut stale_tasks_all = tasks
        .iter()
        .filter(|task| !matches!(task.status.as_str(), "done" | "archived"))
        .filter(|task| now_ms.saturating_sub(task.updated_at) > 72 * 60 * 60_000)
        .filter_map(|task| task_projection(task, &agents_by_id, &projects_by_id, &goals_by_id))
        .collect::<Vec<_>>();
    stale_tasks_all.sort_by_key(|item| std::cmp::Reverse(item.updated_at));

    let mut runtime_by_task_id = HashMap::new();
    let mut run_to_task = HashMap::new();
    let mut session_to_tasks: HashMap<String, Vec<String>> = HashMap::new();
    let mut linked_task_count_by_owner: HashMap<String, u64> = HashMap::new();
    for task in &tasks {
        let runtime = state
            .storage
            .resolve_task_runtime_link(task)
            .map_err(|err| {
                internal_err_with_error("resolving task runtime for strategy summary failed", err)
            })?;
        if let Some(owner_agent_id) = task.owner_agent_id.as_ref() {
            if runtime.latest_run_id.is_some() || runtime.latest_session_id.is_some() {
                *linked_task_count_by_owner
                    .entry(owner_agent_id.clone())
                    .or_insert(0) += 1;
            }
        }
        if let Some(run_id) = runtime.latest_run_id.as_ref() {
            run_to_task.insert(run_id.clone(), task.task_id.clone());
        }
        if let Some(session_id) = runtime.latest_session_id.as_ref() {
            session_to_tasks
                .entry(session_id.clone())
                .or_default()
                .push(task.task_id.clone());
        }
        runtime_by_task_id.insert(task.task_id.clone(), runtime);
    }

    let samples = state
        .storage
        .list_run_usage_samples_between(
            day_start_ms,
            day_end_ms,
            MISSION_CONTROL_USAGE_MAX_SAMPLE_ROWS,
        )
        .map_err(|err| internal_err_with_error("loading strategy usage samples failed", err))?;
    let runtime_config = load_runtime_config(&state).map_err(|err| {
        internal_err_with_error("loading runtime config for strategy summary failed", err)
    })?;
    let mut spend_by_agent: HashMap<String, (String, f64)> = HashMap::new();
    let mut spend_by_project: HashMap<String, (String, String, String, f64, u64)> = HashMap::new();
    let mut unattributed_spend_total = 0.0f64;
    for sample in samples {
        let parsed = match parse_run_usage_metrics(&sample.usage_json) {
            Ok(value) => value,
            Err(_) => continue,
        };
        let total_tokens = parsed.input_tokens.saturating_add(parsed.output_tokens);
        let estimated_cost_usd = parsed.estimated_cost_usd.unwrap_or_else(|| {
            let policy = lookup_runtime_provider_policy(&runtime_config, &sample.model_provider);
            match policy.and_then(|item| item.usd_per_1k_tokens) {
                Some(rate) => (total_tokens as f64 / 1000.0) * rate,
                None => 0.0,
            }
        });
        let entry = spend_by_agent
            .entry(sample.agent_id.clone())
            .or_insert((sample.agent_name.clone(), 0.0));
        entry.1 += estimated_cost_usd;

        let maybe_task_id = run_to_task.get(&sample.run_id).cloned().or_else(|| {
            session_to_tasks
                .get(&sample.session_id)
                .and_then(|task_ids| {
                    if task_ids.len() == 1 {
                        Some(task_ids[0].clone())
                    } else {
                        None
                    }
                })
        });
        if let Some(task_id) = maybe_task_id {
            if let Some(task) = tasks_by_id.get(&task_id) {
                if let Some(project) = projects_by_id.get(&task.project_id) {
                    if let Some(goal) = goals_by_id.get(&project.goal_id) {
                        let project_entry = spend_by_project
                            .entry(project.project_id.clone())
                            .or_insert((
                                project.name.clone(),
                                goal.goal_id.clone(),
                                goal.title.clone(),
                                0.0,
                                0,
                            ));
                        project_entry.3 += estimated_cost_usd;
                        project_entry.4 = project_entry.4.saturating_add(1);
                        continue;
                    }
                }
            }
        }
        unattributed_spend_total += estimated_cost_usd;
    }

    let mut spend_by_agent_items = spend_by_agent
        .into_iter()
        .map(
            |(agent_id, (agent_name, estimated_cost_total))| StrategySpendByAgentItemResponse {
                linked_task_count: linked_task_count_by_owner
                    .get(&agent_id)
                    .copied()
                    .unwrap_or(0),
                agent_id,
                agent_name,
                estimated_cost_total,
            },
        )
        .collect::<Vec<_>>();
    spend_by_agent_items.sort_by(|left, right| {
        right
            .estimated_cost_total
            .partial_cmp(&left.estimated_cost_total)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| left.agent_name.cmp(&right.agent_name))
    });

    let mut spend_by_project_items = spend_by_project
        .into_iter()
        .map(
            |(
                project_id,
                (project_name, goal_id, goal_title, estimated_cost_total, attributed_run_count),
            )| {
                StrategySpendByProjectItemResponse {
                    project_id,
                    project_name,
                    goal_id,
                    goal_title,
                    estimated_cost_total,
                    attributed_run_count,
                }
            },
        )
        .collect::<Vec<_>>();
    spend_by_project_items.sort_by(|left, right| {
        right
            .estimated_cost_total
            .partial_cmp(&left.estimated_cost_total)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| left.project_name.cmp(&right.project_name))
    });

    let mut goal_progress_items = Vec::new();
    for goal in &goals {
        let progress_pct = goal_progress_pct(&state, &goal.goal_id)?;
        let goal_tasks = tasks
            .iter()
            .filter(|task| {
                projects_by_id
                    .get(&task.project_id)
                    .map(|project| project.goal_id.as_str() == goal.goal_id.as_str())
                    .unwrap_or(false)
            })
            .collect::<Vec<_>>();
        let open_task_count = goal_tasks
            .iter()
            .filter(|task| matches!(task.status.as_str(), "todo" | "in_progress" | "blocked"))
            .count() as u64;
        let blocked_task_count = goal_tasks
            .iter()
            .filter(|task| task.status == "blocked")
            .count() as u64;
        goal_progress_items.push(StrategyGoalProgressItemResponse {
            goal_id: goal.goal_id.clone(),
            title: goal.title.clone(),
            progress_pct,
            open_task_count,
            blocked_task_count,
        });
    }
    goal_progress_items.sort_by(|left, right| left.title.cmp(&right.title));

    let mut critical_approval_backlog = Vec::new();
    for approval in approvals {
        let linked_task_id = run_to_task.get(&approval.run_id).cloned().or_else(|| {
            state
                .storage
                .get_run(&approval.run_id)
                .ok()
                .flatten()
                .and_then(|run| {
                    session_to_tasks.get(&run.session_id).and_then(|task_ids| {
                        if task_ids.len() == 1 {
                            Some(task_ids[0].clone())
                        } else {
                            None
                        }
                    })
                })
        });
        let critical_task = linked_task_id
            .as_ref()
            .and_then(|task_id| tasks_by_id.get(task_id))
            .map(|task| task.priority == "critical")
            .unwrap_or(false);
        let aged = now_ms.saturating_sub(approval.requested_at) > STRATEGY_CRITICAL_APPROVAL_AGE_MS;
        if !(critical_task || aged) {
            continue;
        }
        critical_approval_backlog.push(StrategyApprovalBacklogItemResponse {
            approval_id: approval.approval_id,
            kind: approval.kind,
            summary: approval.request_summary,
            linked_task_id,
            requested_at: approval.requested_at,
        });
    }
    critical_approval_backlog.sort_by_key(|item| std::cmp::Reverse(item.requested_at));

    Ok(Json(StrategySummaryResponse {
        generated_at_ms: now_ms,
        currency: "USD".to_string(),
        blocked_task_count: blocked_tasks_all.len() as u64,
        blocked_tasks: blocked_tasks_all
            .into_iter()
            .take(STRATEGY_SUMMARY_ITEM_LIMIT)
            .collect(),
        stale_task_count: stale_tasks_all.len() as u64,
        stale_tasks: stale_tasks_all
            .into_iter()
            .take(STRATEGY_SUMMARY_ITEM_LIMIT)
            .collect(),
        spend_by_agent: spend_by_agent_items,
        spend_by_project: spend_by_project_items,
        unattributed_spend_total,
        goal_progress: goal_progress_items,
        critical_approval_backlog_count: critical_approval_backlog.len() as u64,
        critical_approval_backlog: critical_approval_backlog
            .into_iter()
            .take(STRATEGY_SUMMARY_ITEM_LIMIT)
            .collect(),
    }))
}

async fn mission_control_calendar_week(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<MissionControlCalendarWeekQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[
            ROLE_OPERATOR_ADMIN,
            ROLE_OPERATOR_READONLY,
            ROLE_AUTOMATION_RUNNER,
        ],
        "mission_control.calendar_week",
        "mission_control.calendar",
    )?;
    let now_ms = current_time_ms();
    let week_start_ms =
        mission_control_week_start_ms(now_ms, query.week_start_ms, query.tz_offset_minutes);
    let week_end_ms = week_start_ms.saturating_add(
        7_i64
            .saturating_mul(24)
            .saturating_mul(60)
            .saturating_mul(60_000),
    );
    let jobs = state
        .storage
        .list_jobs(500, true)
        .map_err(|err| internal_err_with_error("listing mission control jobs failed", err))?;

    let mut jobs_payload = jobs
        .iter()
        .map(mission_control_calendar_job_from_record)
        .collect::<Vec<_>>();

    jobs_payload.sort_by(|left, right| {
        left.next_run_at
            .unwrap_or(i64::MAX)
            .cmp(&right.next_run_at.unwrap_or(i64::MAX))
            .then_with(|| left.name.cmp(&right.name))
    });

    let always_running = jobs_payload
        .iter()
        .filter(|job| job.lane == "always_running")
        .cloned()
        .collect::<Vec<_>>();
    let next_up = jobs_payload
        .iter()
        .filter(|job| job.enabled)
        .take(20)
        .cloned()
        .collect::<Vec<_>>();

    Ok(Json(MissionControlCalendarWeekResponse {
        week_start_ms,
        week_end_ms,
        generated_at_ms: now_ms,
        always_running,
        next_up,
        jobs: jobs_payload,
    }))
}

