async fn create_run(
    headers: HeaderMap,
    State(state): State<AppState>,
    Path(session_id): Path<String>,
    Json(request): Json<CreateRunRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_AUTOMATION_RUNNER],
        "run.create",
        &format!("session:{session_id}"),
    )?;
    require_endpoint_rate_limit_with_error(&state, &auth, "run")?;
    let session = state
        .storage
        .get_session(&session_id)
        .map_err(|err| internal_err_with_error("loading session before run failed", err))?
        .ok_or_else(|| api_error(StatusCode::NOT_FOUND, "session not found"))?;
    let requested_model_provider = request
        .model_provider
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    let requested_model_id = request
        .model_id
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    let requested_auth_profile_id = request
        .auth_profile_id
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    let runtime_config = load_runtime_config(&state)
        .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
    let session_lane_managed = session_key_looks_lane_managed(&session.session_key);
    let lane_route = resolve_lane_route_for_session(&state, &runtime_config.routing, &session)
        .map_err(|err| internal_err_with_error("resolving session lane route failed", err))?;
    if session_lane_managed && lane_route.is_none() {
        return Err(api_error(
            StatusCode::CONFLICT,
            "this lane-backed session no longer matches an enabled person and assistant route",
        ));
    }
    let lane_authoritative = lane_route.is_some();
    let (model_provider, model_id, requested_auth_profile_id) = if lane_authoritative {
        let agent = state
            .storage
            .get_agent(&session.agent_id)
            .map_err(|err| internal_err_with_error("loading session assistant failed", err))?
            .ok_or_else(|| {
                api_error(
                    StatusCode::BAD_REQUEST,
                    "session assistant does not exist anymore",
                )
            })?;
        info!(
            session_id = %session.session_id,
            session_key = %session.session_key,
            agent_id = %session.agent_id,
            requested_model_provider = ?requested_model_provider,
            requested_model_id = ?requested_model_id,
            requested_auth_profile_id = ?requested_auth_profile_id,
            "canonical lane session is enforcing assistant route for run creation"
        );
        (
            agent.model_provider.trim().to_string(),
            agent.model_id.trim().to_string(),
            None,
        )
    } else {
        (
            requested_model_provider.unwrap_or_else(|| "mock".to_string()),
            requested_model_id.unwrap_or_else(|| "mock-echo-v1".to_string()),
            requested_auth_profile_id,
        )
    };

    if model_provider.is_empty() || model_id.is_empty() {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "model_provider and model_id must be non-empty",
        ));
    }
    if !provider_supported(&model_provider) {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "unsupported model_provider",
        ));
    }
    let lane = state.session_run_lanes.lane_for_session(&session_id);
    let Ok(_lane_guard) = lane.try_lock() else {
        return Err(api_error(
            StatusCode::CONFLICT,
            "an active run is already in progress for this session",
        ));
    };

    let created_run = state
        .storage
        .create_run(NewRun {
            session_id: session_id.clone(),
            model_provider,
            model_id,
        })
        .map_err(|err| internal_err_with_error("creating run failed", err))?;

    let created_run =
        created_run.ok_or_else(|| api_error(StatusCode::NOT_FOUND, "session not found"))?;
    info!(
        run_id = %created_run.run_id,
        session_id = %created_run.session_id,
        model_provider = %created_run.model_provider,
        model_id = %created_run.model_id,
        "run created"
    );
    record_security_audit(
        &headers,
        &state,
        &auth,
        "run.create",
        &format!("run:{}", created_run.run_id),
        "allow",
        Some("run created".to_string()),
        StatusCode::CREATED,
        None,
        Some(&created_run.session_id),
        Some(&created_run.run_id),
        Some(serde_json::json!({
            "lane_authoritative": lane_authoritative,
            "model_provider": &created_run.model_provider,
            "model_id": &created_run.model_id
        })),
    );
    emit_event(
        &state,
        "run.created",
        serde_json::json!({
            "run_id": &created_run.run_id,
            "session_id": &created_run.session_id,
            "status": &created_run.status,
            "lane_authoritative": lane_authoritative,
            "model_provider": &created_run.model_provider,
            "model_id": &created_run.model_id
        }),
    );

    let run = execute_run_with_status_handling(
        &state,
        &created_run,
        &session.agent_id,
        requested_auth_profile_id.as_deref(),
    )
    .await
    .map_err(|err| internal_err_with_error("executing run failed", err))?;
    info!(
        run_id = %run.run_id,
        session_id = %run.session_id,
        status = %run.status,
        "run execution finished"
    );

    Ok((
        StatusCode::CREATED,
        Json(CreateRunResponse {
            run: to_run_response(run),
        }),
    ))
}

async fn resume_run(
    headers: HeaderMap,
    State(state): State<AppState>,
    Path(run_id): Path<String>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_AUTOMATION_RUNNER],
        "run.resume",
        &format!("run:{run_id}"),
    )?;
    require_endpoint_rate_limit_with_error(&state, &auth, "run")?;
    let run = state
        .storage
        .get_run(&run_id)
        .map_err(|err| internal_err_with_error("loading run failed", err))?
        .ok_or_else(|| api_error(StatusCode::NOT_FOUND, "run not found"))?;
    if run.status == "running" {
        return Err(api_error(
            StatusCode::CONFLICT,
            "run is currently running and cannot be resumed",
        ));
    }
    if run.status == "succeeded" {
        return Err(api_error(
            StatusCode::CONFLICT,
            "run already succeeded and cannot be resumed",
        ));
    }

    let session = state
        .storage
        .get_session(&run.session_id)
        .map_err(|err| internal_err_with_error("loading session for run failed", err))?
        .ok_or_else(|| api_error(StatusCode::NOT_FOUND, "session not found for run"))?;
    let refreshed = match execute_run_with_lane_control(
        &state,
        &run,
        &session.agent_id,
        None,
        RunLaneConflictPolicy::RejectIfBusy,
    )
    .await
    {
        Ok(run) => run,
        Err(RunLaneExecutionError::Busy) => {
            return Err(api_error(
                StatusCode::CONFLICT,
                "an active run is already in progress for this session",
            ))
        }
        Err(RunLaneExecutionError::Execute(err)) => {
            return Err(internal_err_with_error("resuming run failed", err))
        }
    };
    record_security_audit(
        &headers,
        &state,
        &auth,
        "run.resume",
        &format!("run:{}", refreshed.run_id),
        "allow",
        Some("run resumed".to_string()),
        StatusCode::OK,
        None,
        Some(&refreshed.session_id),
        Some(&refreshed.run_id),
        Some(serde_json::json!({
            "status": &refreshed.status
        })),
    );
    Ok((
        StatusCode::OK,
        Json(CreateRunResponse {
            run: to_run_response(refreshed),
        }),
    ))
}

async fn run_memory_why(
    headers: HeaderMap,
    State(state): State<AppState>,
    Path(run_id): Path<String>,
    Json(request): Json<RunMemoryWhyRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        "run.memory.why",
        &format!("run:{run_id}"),
    )?;
    let run = state
        .storage
        .get_run(&run_id)
        .map_err(|err| internal_err_with_error("loading run failed", err))?
        .ok_or_else(|| api_error(StatusCode::NOT_FOUND, "run not found"))?;
    let runtime_config = load_runtime_config(&state)
        .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
    let client = resolve_numquam_client_for_session(&state, &runtime_config, &run.session_id)
        .await
        .map_err(|err| internal_err_with_error("resolving numquam client failed", err))?
        .ok_or_else(|| {
            api_error(
                StatusCode::FAILED_DEPENDENCY,
                "numquam integration is disabled for context.why",
            )
        })?;

    let mut evidence_ids = request
        .evidence_ids
        .iter()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .collect::<Vec<_>>();
    if evidence_ids.is_empty() {
        if let Some(usage_json) = run.usage_json.as_ref() {
            if let Ok(usage_value) = serde_json::from_str::<serde_json::Value>(usage_json) {
                if let Some(items) = usage_value
                    .get("memory")
                    .and_then(|value| value.get("evidence"))
                    .and_then(|value| value.as_array())
                {
                    for item in items {
                        if let Some(evidence_id) =
                            item.get("evidence_id").and_then(|value| value.as_str())
                        {
                            let normalized = evidence_id.trim();
                            if !normalized.is_empty() {
                                evidence_ids.push(normalized.to_string());
                            }
                        }
                    }
                }
            }
        }
    }
    evidence_ids.sort();
    evidence_ids.dedup();
    if evidence_ids.is_empty() {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "no evidence ids available for context.why",
        ));
    }

    let envelope = client
        .context_why(
            &run.session_id,
            &run.run_id,
            &evidence_ids,
            request.expand_citations,
        )
        .await
        .map_err(|err| internal_err_with_error("calling numquam context.why failed", err))?;
    if !envelope.ok {
        let message = envelope
            .error
            .as_ref()
            .map(|row| row.message.clone())
            .unwrap_or_else(|| "numquam context.why returned non-ok envelope".to_string());
        let status = envelope
            .error
            .as_ref()
            .map(|row| numquam_status_from_error_code(row.code.as_str()))
            .unwrap_or(StatusCode::BAD_GATEWAY);
        return Err(api_error(status, &message));
    }

    let reasons = envelope
        .data
        .as_ref()
        .map(|row| {
            row.reasons
                .iter()
                .map(|item| {
                    serde_json::json!({
                        "evidence_id": item.evidence_id,
                        "reason": item.reason
                    })
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let evidence = envelope
        .data
        .as_ref()
        .map(|row| row.evidence.clone())
        .unwrap_or_default();
    record_security_audit(
        &headers,
        &state,
        &auth,
        "run.memory.why",
        &format!("run:{}", run.run_id),
        "allow",
        Some("fetched numquam context.why".to_string()),
        StatusCode::OK,
        None,
        Some(&run.session_id),
        Some(&run.run_id),
        Some(serde_json::json!({
            "evidence_ids": evidence_ids,
            "request_id": envelope.request_id,
            "request_id_source": envelope.request_id_source,
            "degrade_mode": envelope.degrade_mode
        })),
    );

    Ok(Json(RunMemoryWhyResponse {
        run_id: run.run_id,
        session_id: run.session_id,
        transport: Some(client.transport.as_str().to_string()),
        request_id: Some(envelope.request_id),
        request_id_source: Some(envelope.request_id_source),
        degrade_mode: envelope.degrade_mode,
        warning_codes: numquam_warning_codes(&envelope.warnings),
        reasons,
        evidence,
    }))
}

async fn list_approvals(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListApprovalsQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        "approval.list",
        "approvals",
    )?;
    let status = query.status.as_ref().and_then(|value| {
        if value.trim().is_empty() {
            None
        } else {
            Some(value.as_str())
        }
    });
    let limit = query.limit.unwrap_or(50).clamp(1, 200);
    let items: Vec<ApprovalResponse> = state
        .storage
        .list_approvals(status, limit)
        .map_err(|err| internal_err_with_error("listing approvals failed", err))?
        .into_iter()
        .map(to_approval_response)
        .collect();
    debug!(
        status_filter = status.unwrap_or("all"),
        limit,
        count = items.len(),
        "approvals listed"
    );

    Ok(Json(ListApprovalsResponse { items }))
}

async fn create_approval_request(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<CreateApprovalRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_AUTOMATION_RUNNER],
        "approval.create",
        "approvals",
    )?;
    require_endpoint_rate_limit_with_error(&state, &auth, "approval")?;
    require_operator_allowlist(&headers, &state)?;
    if request.run_id.trim().is_empty() {
        return Err(api_error(StatusCode::BAD_REQUEST, "run_id cannot be empty"));
    }
    if request.tool_name.trim().is_empty() {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "tool_name cannot be empty",
        ));
    }
    if request.request_summary.trim().is_empty() {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "request_summary cannot be empty",
        ));
    }

    let request_json = request
        .request_json
        .unwrap_or_else(|| serde_json::json!({}))
        .to_string();

    let approval = state
        .storage
        .create_approval(NewApproval {
            run_id: request.run_id.clone(),
            tool_call_id: None,
            kind: request.tool_name,
            request_summary: request.request_summary,
            request_json,
        })
        .map_err(|err| internal_err_with_error("creating approval failed", err))?
        .ok_or_else(|| api_error(StatusCode::NOT_FOUND, "run not found"))?;
    info!(
        approval_id = %approval.approval_id,
        run_id = %approval.run_id,
        kind = %approval.kind,
        "approval requested"
    );
    record_security_audit(
        &headers,
        &state,
        &auth,
        "approval.create",
        &format!("approval:{}", approval.approval_id),
        "allow",
        Some("approval created".to_string()),
        StatusCode::CREATED,
        None,
        None,
        Some(&approval.run_id),
        Some(serde_json::json!({
            "kind": &approval.kind,
            "status": &approval.status
        })),
    );

    emit_event(
        &state,
        "approval.requested",
        serde_json::json!({
            "approval_id": &approval.approval_id,
            "run_id": &approval.run_id,
            "status": &approval.status,
            "kind": &approval.kind
        }),
    );

    Ok((
        StatusCode::CREATED,
        Json(CreateApprovalResponse {
            approval: to_approval_response(approval),
        }),
    ))
}

async fn resolve_approval(
    headers: HeaderMap,
    State(state): State<AppState>,
    Path(approval_id): Path<String>,
    Json(request): Json<ResolveApprovalRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_CHANNEL_ADAPTER],
        "approval.resolve",
        &format!("approval:{approval_id}"),
    )?;
    require_endpoint_rate_limit_with_error(&state, &auth, "approval")?;
    require_operator_allowlist(&headers, &state)?;
    if request.decision != "approve" && request.decision != "deny" {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "decision must be 'approve' or 'deny'",
        ));
    }

    let existing = state
        .storage
        .get_approval(&approval_id)
        .map_err(|err| internal_err_with_error("loading approval before resolve failed", err))?;
    let mut assistant_approval_metadata: Option<serde_json::Value> = None;

    if let Some(existing_record) = existing.as_ref() {
        if existing_record.kind == NUMQUAM_APPROVAL_KIND_WRITEBACK
            && existing_record.status == "requested"
        {
            let runtime_config = load_runtime_config(&state)
                .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
            let run = state
                .storage
                .get_run(&existing_record.run_id)
                .map_err(|err| {
                    internal_err_with_error("loading run for memory writeback resolve failed", err)
                })?
                .ok_or_else(|| api_error(StatusCode::NOT_FOUND, "run not found for approval"))?;
            let client =
                resolve_numquam_client_for_session(&state, &runtime_config, &run.session_id)
                    .await
                    .map_err(|err| internal_err_with_error("resolving numquam client failed", err))?
                    .ok_or_else(|| {
                        api_error(
                            StatusCode::FAILED_DEPENDENCY,
                            "numquam integration is disabled for memory writeback resolve",
                        )
                    })?;
            let request_json: serde_json::Value =
                serde_json::from_str(&existing_record.request_json).map_err(|_| {
                    api_error(
                        StatusCode::BAD_REQUEST,
                        "memory writeback approval payload is invalid",
                    )
                })?;
            let proposal_id = request_json
                .get("proposal_id")
                .and_then(|value| value.as_str())
                .map(|value| value.trim().to_string())
                .filter(|value| !value.is_empty())
                .ok_or_else(|| {
                    api_error(
                        StatusCode::BAD_REQUEST,
                        "memory writeback approval is missing proposal_id",
                    )
                })?;
            let upstream_decision = if request.decision == "approve" {
                "approve"
            } else {
                "reject"
            };
            let decided_by = request
                .decided_by_peer_id
                .clone()
                .or_else(|| {
                    headers
                        .get("x-operator-id")
                        .and_then(|value| value.to_str().ok())
                        .map(|value| value.trim().to_string())
                        .filter(|value| !value.is_empty())
                })
                .unwrap_or_else(|| "carsinos_operator".to_string());
            let resolve_envelope = client
                .writeback_resolve(
                    &run.session_id,
                    &run.run_id,
                    &proposal_id,
                    upstream_decision,
                    &decided_by,
                    Some("carsinos_approval_resolution"),
                )
                .await
                .map_err(|err| {
                    error!(
                        approval_id = %approval_id,
                        run_id = %run.run_id,
                        error = %err,
                        "Numquam writeback resolve request failed"
                    );
                    api_error(StatusCode::BAD_GATEWAY, "numquam writeback resolve failed")
                })?;
            if !resolve_envelope.ok {
                let message = resolve_envelope
                    .error
                    .as_ref()
                    .map(|error| format!("numquam writeback resolve failed: {}", error.message))
                    .unwrap_or_else(|| {
                        "numquam writeback resolve returned non-ok response".to_string()
                    });
                return Err(api_error(
                    numquam_status_from_error_code(
                        resolve_envelope
                            .error
                            .as_ref()
                            .map(|error| error.code.as_str())
                            .unwrap_or("INTERNAL_ERROR"),
                    ),
                    &message,
                ));
            }
        }
        if existing_record.status == "requested"
            && (existing_record.kind == ASSISTANT_TOOL_WORKER_SPAWN_KIND
                || existing_record.kind == ASSISTANT_TOOL_WORKER_UPDATE_KIND)
        {
            assistant_approval_metadata =
                apply_assistant_worker_approval_action(&state, existing_record, &request.decision)
                    .await?;
        }
    }

    let resolved = state
        .storage
        .resolve_approval(
            &approval_id,
            &request.decision,
            request.decided_via.clone(),
            request.decided_by_peer_id.clone(),
        )
        .map_err(|err| internal_err_with_error("resolving approval failed", err))?;

    match resolved {
        ApprovalResolveResult::Resolved(record) => {
            info!(
                approval_id = %record.approval_id,
                run_id = %record.run_id,
                status = %record.status,
                decided_via = ?record.decided_via,
                "approval resolved"
            );
            let mut metadata = serde_json::json!({
                "status": &record.status,
                "kind": &record.kind,
                "decision": &request.decision
            });
            if let Some(extra) = assistant_approval_metadata {
                if let Some(object) = metadata.as_object_mut() {
                    object.insert("assistant".to_string(), extra);
                }
            }
            record_security_audit(
                &headers,
                &state,
                &auth,
                "approval.resolve",
                &format!("approval:{}", record.approval_id),
                "allow",
                Some("approval resolved".to_string()),
                StatusCode::OK,
                None,
                None,
                Some(&record.run_id),
                Some(metadata),
            );
            emit_event(
                &state,
                "approval.resolved",
                serde_json::json!({
                    "approval_id": &record.approval_id,
                    "run_id": &record.run_id,
                    "status": &record.status,
                    "kind": &record.kind
                }),
            );
            Ok(Json(ResolveApprovalResponse {
                approval: to_approval_response(record),
            }))
        }
        ApprovalResolveResult::AlreadyResolved(record) => {
            warn!(
                approval_id = %record.approval_id,
                status = %record.status,
                "approval resolution conflict: already resolved"
            );
            record_security_audit(
                &headers,
                &state,
                &auth,
                "approval.resolve",
                &format!("approval:{}", record.approval_id),
                "deny",
                Some(format!(
                    "approval already resolved with status {}",
                    record.status
                )),
                StatusCode::CONFLICT,
                Some("POLICY_DENY"),
                None,
                Some(&record.run_id),
                Some(serde_json::json!({
                    "status": &record.status,
                    "kind": &record.kind,
                    "decision": &request.decision
                })),
            );
            Err(api_error(
                StatusCode::CONFLICT,
                &format!("approval already resolved with status {}", record.status),
            ))
        }
        ApprovalResolveResult::NotFound => {
            Err(api_error(StatusCode::NOT_FOUND, "approval not found"))
        }
    }
}

async fn list_security_audit(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListSecurityAuditQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        "security.audit.list",
        "security_audit_events",
    )?;
    let limit = query.limit.unwrap_or(200).clamp(1, 1000);
    let action = query
        .action
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let principal = query
        .principal
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let decision = query
        .decision
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let status = query
        .status
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let error_code = query
        .error_code
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let created_after = query.created_after;
    let created_before = query.created_before;
    if let (Some(after), Some(before)) = (created_after, created_before) {
        if after > before {
            return Err(api_error_with_code(
                StatusCode::BAD_REQUEST,
                "INVALID_INPUT",
                "created_after must be <= created_before",
            ));
        }
    }
    let filter = SecurityAuditEventListFilter {
        action: action.map(str::to_string),
        principal: principal.map(str::to_string),
        decision: decision.map(str::to_string),
        status: status.map(str::to_string),
        error_code: error_code.map(str::to_string),
        created_after,
        created_before,
    };
    let items = state
        .storage
        .list_security_audit_events(limit, &filter)
        .map_err(|err| internal_err_with_error("listing security audit events failed", err))?
        .into_iter()
        .map(to_security_audit_event_response)
        .collect();
    Ok(Json(ListSecurityAuditResponse { items }))
}

async fn run_security_audit_retention(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<RunSecurityAuditRetentionRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_SERVICE_INTERNAL],
        "security.audit.retention.run",
        "security_audit_events",
    )?;

    let hot_retention_days = request
        .hot_retention_days
        .unwrap_or_else(|| i64_env("CARSINOS_SECURITY_AUDIT_HOT_RETENTION_DAYS", 90));
    if !(0..=3650).contains(&hot_retention_days) {
        return Err(api_error_with_code(
            StatusCode::BAD_REQUEST,
            "INVALID_INPUT",
            "hot_retention_days must be between 0 and 3650",
        ));
    }

    let dry_run = request.dry_run.unwrap_or(false);
    let cutoff_ms = current_time_ms().saturating_sub(hot_retention_days.saturating_mul(86_400_000));
    let candidate_count = state
        .storage
        .count_security_audit_events_before(cutoff_ms)
        .map_err(|err| {
            internal_err_with_error("counting security audit retention candidates failed", err)
        })?;

    let (archived_count, deleted_count) = if dry_run {
        (0, 0)
    } else {
        let archived = state
            .storage
            .archive_security_audit_events_before(cutoff_ms)
            .map_err(|err| {
                internal_err_with_error("archiving security audit retention candidates failed", err)
            })?;
        let deleted = state
            .storage
            .delete_security_audit_events_before(cutoff_ms)
            .map_err(|err| {
                internal_err_with_error("deleting security audit retention candidates failed", err)
            })?;
        (archived, deleted)
    };

    record_security_audit(
        &headers,
        &state,
        &auth,
        "security.audit.retention.run",
        "security_audit_events",
        "allow",
        None,
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "hot_retention_days": hot_retention_days,
            "cutoff_ms": cutoff_ms,
            "candidate_count": candidate_count,
            "archived_count": archived_count,
            "deleted_count": deleted_count,
            "dry_run": dry_run
        })),
    );

    Ok(Json(RunSecurityAuditRetentionResponse {
        hot_retention_days,
        cutoff_ms,
        candidate_count,
        archived_count,
        deleted_count,
        dry_run,
    }))
}

fn budget_error(code: &str, detail: impl AsRef<str>) -> anyhow::Error {
    anyhow::anyhow!("{code}: {}", detail.as_ref())
}

fn extract_reason_code_from_error_text(error_text: &str) -> Option<String> {
    let candidate = error_text.split(':').next()?.trim();
    if candidate.is_empty() {
        return None;
    }
    if candidate
        .chars()
        .all(|ch| ch.is_ascii_uppercase() || ch.is_ascii_digit() || ch == '_')
    {
        Some(candidate.to_string())
    } else {
        None
    }
}

fn normalize_breaker_error_code(error_code: Option<&str>) -> Option<String> {
    error_code
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
}

fn get_active_circuit_breaker_state(
    state: &AppState,
    scope: &str,
    target_id: &str,
) -> AnyResult<Option<CircuitBreakerStateRecord>> {
    let now = current_time_ms();
    let Some(record) = state.storage.get_circuit_breaker_state(scope, target_id)? else {
        return Ok(None);
    };
    if record.state != CIRCUIT_BREAKER_STATE_OPEN {
        return Ok(None);
    }
    if let Some(cooldown_until) = record.cooldown_until {
        if cooldown_until > now {
            return Ok(Some(record));
        }
        state
            .storage
            .upsert_circuit_breaker_state(CircuitBreakerStateUpsert {
                scope: scope.to_string(),
                target_id: target_id.to_string(),
                state: CIRCUIT_BREAKER_STATE_CLOSED.to_string(),
                consecutive_failures: 0,
                opened_at: None,
                cooldown_until: None,
                last_error_code: record.last_error_code.clone(),
            })?;
        return Ok(None);
    }
    Ok(Some(record))
}

fn reset_circuit_breaker_state_on_success(
    state: &AppState,
    scope: &str,
    target_id: &str,
) -> AnyResult<()> {
    let Some(existing) = state.storage.get_circuit_breaker_state(scope, target_id)? else {
        return Ok(());
    };
    if existing.state == CIRCUIT_BREAKER_STATE_CLOSED && existing.consecutive_failures == 0 {
        return Ok(());
    }
    state
        .storage
        .upsert_circuit_breaker_state(CircuitBreakerStateUpsert {
            scope: scope.to_string(),
            target_id: target_id.to_string(),
            state: CIRCUIT_BREAKER_STATE_CLOSED.to_string(),
            consecutive_failures: 0,
            opened_at: None,
            cooldown_until: None,
            last_error_code: None,
        })?;
    Ok(())
}

