fn scheduler_auth_context(job_id: &str, mode: &str) -> AuthContext {
    let mut roles = HashSet::new();
    roles.insert(ROLE_OPERATOR_ADMIN.to_string());
    roles.insert(ROLE_SERVICE_INTERNAL.to_string());
    AuthContext {
        principal_id: format!("scheduler:{job_id}:{mode}"),
        roles,
        auth_method: "scheduler_job",
        token_id: Some(job_id.to_string()),
        session_id: None,
        client_ip: "127.0.0.1".to_string(),
    }
}

fn scheduler_headers(job_id: &str, mode: &str) -> HeaderMap {
    let mut headers = HeaderMap::new();
    let request_id = format!("job.{mode}.{job_id}.{}", uuid::Uuid::new_v4());
    if let Ok(value) = HeaderValue::from_str(&request_id) {
        headers.insert("x-request-id", value);
    }
    headers
}

#[derive(Debug, Clone)]
struct SchedulerDeliveryTarget {
    provider: String,
    target: String,
    action: String,
}

fn parse_scheduler_delivery_targets(payload: &serde_json::Value) -> Vec<SchedulerDeliveryTarget> {
    let Some(items) = payload
        .get("delivery_targets")
        .and_then(|value| value.as_array())
    else {
        return Vec::new();
    };
    let mut targets = Vec::new();
    for item in items {
        let Some(object) = item.as_object() else {
            continue;
        };
        let provider = object
            .get("provider")
            .and_then(|value| value.as_str())
            .map(|value| value.trim().to_ascii_lowercase())
            .unwrap_or_default();
        let target = object
            .get("target")
            .and_then(|value| value.as_str())
            .map(|value| value.trim().to_string())
            .unwrap_or_default();
        let action = object
            .get("action")
            .and_then(|value| value.as_str())
            .map(|value| value.trim().to_ascii_lowercase())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "send".to_string());
        targets.push(SchedulerDeliveryTarget {
            provider,
            target,
            action,
        });
    }
    targets
}

fn scheduler_delivery_retry_attempts(payload: &serde_json::Value) -> usize {
    payload
        .get("delivery_retry_attempts")
        .and_then(|value| value.as_i64())
        .unwrap_or(1)
        .clamp(1, 5) as usize
}

fn scheduler_delivery_mode(payload: &serde_json::Value) -> &'static str {
    let mode = payload
        .get("delivery_mode")
        .and_then(|value| value.as_str())
        .map(|value| value.trim().to_ascii_lowercase())
        .unwrap_or_else(|| "all".to_string());
    if mode == "first_success" {
        "first_success"
    } else {
        "all"
    }
}

fn scheduler_delivery_text(state: &AppState, session_id: &str, run_id: &str) -> AnyResult<String> {
    let messages = state.storage.list_messages(session_id, 64)?;
    if let Some(message) = messages
        .iter()
        .rev()
        .find(|item| item.role == "assistant" && !item.content_text.trim().is_empty())
    {
        return Ok(message.content_text.clone());
    }
    Ok(format!("Scheduled run {run_id} completed."))
}

fn latest_assistant_reply_text(state: &AppState, session_id: &str) -> AnyResult<Option<String>> {
    let messages = state.storage.list_messages(session_id, 64)?;
    Ok(messages
        .iter()
        .rev()
        .find(|item| item.role == "assistant" && !item.content_text.trim().is_empty())
        .map(|item| item.content_text.clone()))
}

fn dispatch_channel_ingest_reply(
    state: &AppState,
    provider: &str,
    action: &str,
    target: &str,
    content_text: &str,
) -> AnyResult<(usize, &'static str, Vec<String>)> {
    let provider = provider.trim().to_ascii_lowercase();
    let action = action.trim().to_ascii_lowercase();
    let target = target.trim();
    if provider.is_empty() || action.is_empty() || target.is_empty() {
        anyhow::bail!("ingest reply dispatch requires provider/action/target");
    }
    if !matches!(provider.as_str(), "telegram" | "discord") {
        anyhow::bail!("unsupported ingest reply provider: {}", provider);
    }
    if !matches!(action.as_str(), "send" | "reply") {
        anyhow::bail!("unsupported ingest reply action: {}", action);
    }
    let runtime_config = load_runtime_config(state)?;
    let policy_outcome = evaluate_channel_provider_policy(
        &runtime_config,
        state.channel_tool_allowed_provider_override.as_deref(),
        &provider,
    );
    if policy_outcome != ChannelProviderPolicyOutcome::Allowed {
        anyhow::bail!(
            "{}",
            channel_provider_policy_reason(&provider, policy_outcome)
        );
    }
    if content_text.trim().is_empty() {
        anyhow::bail!("ingest reply content is empty");
    }

    let chunks = match provider.as_str() {
        "telegram" => telegram_channel::split_outbound_chunks(
            content_text,
            telegram_channel::TELEGRAM_DEFAULT_CHUNK_LIMIT,
        ),
        _ => discord_channel::split_outbound_chunks(
            content_text,
            discord_channel::DISCORD_DEFAULT_CHUNK_LIMIT,
        ),
    };
    let mut chunk_count = chunks.len();
    let mut transport_message_ids: Vec<String> = Vec::new();
    let mut delivery_mode = DISCORD_OPERATION_MODE_SHIM;

    if provider == "telegram" {
        if normalize_telegram_operation_mode(&runtime_config.channels.telegram.operation_mode)
            == TELEGRAM_OPERATION_MODE_TRANSPORT
        {
            transport_message_ids = send_telegram_chunks_via_transport(
                &runtime_config,
                &state.secret_store,
                target,
                &action,
                &chunks,
            )
            .map(|ids| ids.into_iter().map(|id| id.to_string()).collect::<Vec<_>>())?;
            chunk_count = transport_message_ids.len();
            delivery_mode = TELEGRAM_OPERATION_MODE_TRANSPORT;
            state.channel_runtime.record_outbound(
                "telegram",
                Some("Telegram sent a live outbound reply".to_string()),
            );
        }
    } else if provider == "discord"
        && normalize_discord_operation_mode(&runtime_config.channels.discord.operation_mode)
            == DISCORD_OPERATION_MODE_TRANSPORT
    {
        transport_message_ids = send_discord_chunks_via_transport(
            &runtime_config,
            &state.secret_store,
            target,
            &action,
            &chunks,
        )?;
        chunk_count = transport_message_ids.len();
        delivery_mode = DISCORD_OPERATION_MODE_TRANSPORT;
        state.channel_runtime.record_outbound(
            "discord",
            Some("Discord sent a live outbound reply".to_string()),
        );
    }

    Ok((chunk_count, delivery_mode, transport_message_ids))
}

fn dispatch_scheduler_delivery(
    state: &AppState,
    job: &JobRecord,
    session_id: &str,
    run_id: &str,
    target: &SchedulerDeliveryTarget,
    content_text: &str,
    attempt: usize,
) -> AnyResult<usize> {
    let provider = target.provider.trim().to_ascii_lowercase();
    let action = target.action.trim().to_ascii_lowercase();
    let target_id = target.target.trim();
    let resource = format!("channel:{}:{}", provider, target_id);

    let deny = |reason: String, error_code: &'static str| -> AnyResult<usize> {
        record_security_audit_internal(
            state,
            "job.delivery.dispatch",
            &resource,
            "deny",
            Some(reason.clone()),
            StatusCode::BAD_REQUEST,
            Some(error_code),
            Some(session_id),
            Some(run_id),
            Some(serde_json::json!({
                "job_id": &job.job_id,
                "provider": provider,
                "target": target_id,
                "action": action,
                "attempt": attempt
            })),
        );
        anyhow::bail!("{reason}");
    };

    if provider.is_empty() || target_id.is_empty() {
        return deny(
            "delivery target requires non-empty provider and target".to_string(),
            "INVALID_INPUT",
        );
    }
    if !matches!(provider.as_str(), "telegram" | "discord") {
        return deny(
            format!("unsupported delivery provider '{}'", provider),
            "INVALID_INPUT",
        );
    }
    if !matches!(action.as_str(), "send" | "reply") {
        return deny(
            format!("unsupported delivery action '{}'", action),
            "INVALID_INPUT",
        );
    }
    let runtime_config = load_runtime_config(state)?;
    let policy_outcome = evaluate_channel_provider_policy(
        &runtime_config,
        state.channel_tool_allowed_provider_override.as_deref(),
        &provider,
    );
    if policy_outcome != ChannelProviderPolicyOutcome::Allowed {
        return deny(
            channel_provider_policy_reason(&provider, policy_outcome),
            "AUTH_FORBIDDEN",
        );
    }
    if content_text.trim().is_empty() {
        return deny(
            "delivery content is empty; refusing channel dispatch".to_string(),
            "INVALID_INPUT",
        );
    }

    let chunks = match provider.as_str() {
        "telegram" => telegram_channel::split_outbound_chunks(
            content_text,
            telegram_channel::TELEGRAM_DEFAULT_CHUNK_LIMIT,
        ),
        _ => discord_channel::split_outbound_chunks(
            content_text,
            discord_channel::DISCORD_DEFAULT_CHUNK_LIMIT,
        ),
    };
    let mut chunk_count = chunks.len();
    let mut transport_message_ids: Vec<String> = Vec::new();
    let mut delivery_mode = DISCORD_OPERATION_MODE_SHIM;
    if provider == "telegram" {
        if normalize_telegram_operation_mode(&runtime_config.channels.telegram.operation_mode)
            == TELEGRAM_OPERATION_MODE_TRANSPORT
        {
            transport_message_ids = send_telegram_chunks_via_transport(
                &runtime_config,
                &state.secret_store,
                target_id,
                &action,
                &chunks,
            )
            .map(|ids| ids.into_iter().map(|id| id.to_string()).collect::<Vec<_>>())
            .with_context(|| {
                format!(
                    "telegram transport delivery failed for target {}",
                    target_id
                )
            })?;
            chunk_count = transport_message_ids.len();
            delivery_mode = TELEGRAM_OPERATION_MODE_TRANSPORT;
            state.channel_runtime.record_outbound(
                "telegram",
                Some("Telegram sent a live scheduled outbound message".to_string()),
            );
        }
    } else if provider == "discord"
        && normalize_discord_operation_mode(&runtime_config.channels.discord.operation_mode)
            == DISCORD_OPERATION_MODE_TRANSPORT
    {
        transport_message_ids = send_discord_chunks_via_transport(
            &runtime_config,
            &state.secret_store,
            target_id,
            &action,
            &chunks,
        )
        .with_context(|| format!("discord transport delivery failed for target {}", target_id))?;
        chunk_count = transport_message_ids.len();
        delivery_mode = DISCORD_OPERATION_MODE_TRANSPORT;
        state.channel_runtime.record_outbound(
            "discord",
            Some("Discord sent a live scheduled outbound message".to_string()),
        );
    }

    emit_event(
        state,
        "channel.tool_action.dispatched",
        serde_json::json!({
            "run_id": run_id,
            "session_id": session_id,
            "provider": provider,
            "action": action,
            "target": target_id,
            "chunk_count": chunk_count,
            "delivery_mode": delivery_mode,
            "transport_message_ids": transport_message_ids,
            "source": "scheduler",
            "job_id": &job.job_id
        }),
    );
    record_security_audit_internal(
        state,
        "job.delivery.dispatch",
        &resource,
        "allow",
        None,
        StatusCode::OK,
        None,
        Some(session_id),
        Some(run_id),
        Some(serde_json::json!({
            "job_id": &job.job_id,
            "provider": provider,
            "target": target_id,
            "action": action,
            "attempt": attempt,
            "chunk_count": chunk_count,
            "delivery_mode": delivery_mode
        })),
    );
    Ok(chunk_count)
}

fn execute_secret_rotate_job(
    state: &AppState,
    job: &JobRecord,
    payload: &serde_json::Value,
) -> AnyResult<String> {
    let auth_profile_id = required_job_payload_string(payload, "auth_profile_id")?;
    let reason = optional_job_payload_string(payload, "reason");
    let auth = scheduler_auth_context(&job.job_id, "secret.rotate_profile");
    let headers = scheduler_headers(&job.job_id, "secret.rotate_profile");
    let outcome = match rotate_auth_profile_secret_outcome(state, &auth_profile_id) {
        Ok(outcome) => outcome,
        Err((status, body)) => {
            let error = body.0;
            record_security_audit(
                &headers,
                state,
                &auth,
                "security.secret.rotate",
                &format!("auth_profile:{auth_profile_id}"),
                "deny",
                Some(error.error.clone()),
                status,
                error.error_code.as_deref(),
                None,
                None,
                Some(serde_json::json!({
                    "job_id": &job.job_id,
                    "mode": "secret.rotate_profile",
                    "trigger_kind": "scheduler"
                })),
            );
            anyhow::bail!("{} {}", status.as_u16(), error.error);
        }
    };

    record_security_audit(
        &headers,
        state,
        &auth,
        "security.secret.rotate",
        &format!("auth_profile:{auth_profile_id}"),
        "allow",
        reason
            .clone()
            .or_else(|| Some("scheduled auth profile secret rotation".to_string())),
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "job_id": &job.job_id,
            "mode": "secret.rotate_profile",
            "trigger_kind": "scheduler",
            "provider": &outcome.profile.provider,
            "auth_mode": &outcome.profile.auth_mode,
            "previous_secret_ref": &outcome.previous_secret_ref,
            "rotated_secret_ref": &outcome.rotated_secret_ref
        })),
    );

    Ok(serde_json::json!({
        "mode": "secret.rotate_profile",
        "job_id": &job.job_id,
        "auth_profile_id": auth_profile_id,
        "previous_secret_ref": outcome.previous_secret_ref,
        "rotated_secret_ref": outcome.rotated_secret_ref,
        "reason": reason,
        "now_ms": current_time_ms()
    })
    .to_string())
}

fn execute_secret_revoke_job(
    state: &AppState,
    job: &JobRecord,
    payload: &serde_json::Value,
) -> AnyResult<String> {
    let auth_profile_id = required_job_payload_string(payload, "auth_profile_id")?;
    let reason = optional_job_payload_string(payload, "reason");
    let remove_secret = payload
        .get("remove_secret")
        .and_then(|value| value.as_bool())
        .unwrap_or(true);
    let disable_profile = payload
        .get("disable_profile")
        .and_then(|value| value.as_bool())
        .unwrap_or(true);
    let kill_switch_scope = optional_job_payload_string(payload, "kill_switch_scope");
    let auth = scheduler_auth_context(&job.job_id, "secret.revoke_profile");
    let headers = scheduler_headers(&job.job_id, "secret.revoke_profile");
    let outcome = match revoke_auth_profile_secret_outcome(
        state,
        &auth_profile_id,
        remove_secret,
        disable_profile,
        kill_switch_scope.clone(),
    ) {
        Ok(outcome) => outcome,
        Err((status, body)) => {
            let error = body.0;
            record_security_audit(
                &headers,
                state,
                &auth,
                "security.secret.revoke",
                &format!("auth_profile:{auth_profile_id}"),
                "deny",
                Some(error.error.clone()),
                status,
                error.error_code.as_deref(),
                None,
                None,
                Some(serde_json::json!({
                    "job_id": &job.job_id,
                    "mode": "secret.revoke_profile",
                    "trigger_kind": "scheduler",
                    "remove_secret": remove_secret,
                    "disable_profile": disable_profile
                })),
            );
            anyhow::bail!("{} {}", status.as_u16(), error.error);
        }
    };

    record_security_audit(
        &headers,
        state,
        &auth,
        "security.secret.revoke",
        &format!("auth_profile:{auth_profile_id}"),
        "allow",
        reason
            .clone()
            .or_else(|| Some("scheduled auth profile revocation".to_string())),
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "job_id": &job.job_id,
            "mode": "secret.revoke_profile",
            "trigger_kind": "scheduler",
            "provider": &outcome.profile.provider,
            "auth_mode": &outcome.profile.auth_mode,
            "enabled": outcome.profile.enabled,
            "kill_switch_scope": &outcome.profile.kill_switch_scope,
            "revoked_secret_ref": &outcome.revoked_secret_ref,
            "remove_secret": remove_secret,
            "disable_profile": disable_profile
        })),
    );

    Ok(serde_json::json!({
        "mode": "secret.revoke_profile",
        "job_id": &job.job_id,
        "auth_profile_id": auth_profile_id,
        "enabled": outcome.profile.enabled,
        "kill_switch_scope": outcome.profile.kill_switch_scope,
        "revoked_secret_ref": outcome.revoked_secret_ref,
        "remove_secret": remove_secret,
        "disable_profile": disable_profile,
        "reason": reason,
        "now_ms": current_time_ms()
    })
    .to_string())
}

async fn execute_session_run_job(
    state: &AppState,
    job: &JobRecord,
    payload: &serde_json::Value,
) -> AnyResult<String> {
    let mode = "session.run";
    let payload_agent_id = optional_job_payload_string(payload, "agent_id");
    let requested_assistant_agent_id = optional_job_payload_string(payload, "assistant_agent_id")
        .or_else(|| payload_agent_id.clone());
    let requested_human_identity_id = optional_job_payload_string(payload, "human_identity_id");
    let explicit_session_key = optional_job_payload_string(payload, "session_key");
    let session_title_override = optional_job_payload_string(payload, "session_title");
    let input = required_job_payload_string(payload, "input")?;
    let model_provider = optional_job_payload_string(payload, "model_provider")
        .unwrap_or_else(|| "mock".to_string());
    let model_id = optional_job_payload_string(payload, "model_id")
        .unwrap_or_else(|| "mock-echo-v1".to_string());
    let auth_profile_id = optional_job_payload_string(payload, "auth_profile_id");
    let runtime_config = load_runtime_config(state)?;

    let scheduler_lane_route = if explicit_session_key.is_none() {
        requested_human_identity_id
            .as_deref()
            .map(|human_identity_id| {
                resolve_lane_route_for_human_identity(
                    state,
                    &runtime_config.routing,
                    human_identity_id,
                    requested_assistant_agent_id.as_deref(),
                )
            })
            .transpose()?
            .flatten()
    } else {
        None
    };
    let resolved_agent_id = scheduler_lane_route
        .as_ref()
        .map(|route| route.assistant_agent_id.clone())
        .or(payload_agent_id.clone())
        .unwrap_or(job.agent_id.clone());
    let session_key = scheduler_lane_route
        .as_ref()
        .map(|route| route.session_key.clone())
        .or(explicit_session_key)
        .unwrap_or_else(|| format!("scheduler:{}:{}", job.job_id, resolved_agent_id));
    let session_title = session_title_override.or_else(|| {
        scheduler_lane_route
            .as_ref()
            .map(|route| route.session_title.clone())
    });

    if !provider_supported(&model_provider) {
        anyhow::bail!(
            "job payload model_provider '{}' is unsupported",
            model_provider
        );
    }

    let auth = scheduler_auth_context(&job.job_id, mode);
    let headers = scheduler_headers(&job.job_id, mode);
    let session = if let Some(existing) = state.storage.get_session_by_key(&session_key)? {
        existing
    } else {
        state.storage.create_session(NewSession {
            session_key: Some(session_key.clone()),
            agent_id: resolved_agent_id.clone(),
            title: session_title,
        })?
    };

    let message = state
        .storage
        .create_message(NewMessage {
            session_id: session.session_id.clone(),
            source_channel: "scheduler".to_string(),
            source_peer_id: Some(format!("job:{}", job.job_id)),
            source_message_id: None,
            role: "user".to_string(),
            content_text: input.clone(),
            content_format: "markdown".to_string(),
        })?
        .with_context(|| {
            format!(
                "failed creating scheduler message for session {}",
                session.session_id
            )
        })?;

    let run = state
        .storage
        .create_run(NewRun {
            session_id: session.session_id.clone(),
            model_provider: model_provider.clone(),
            model_id: model_id.clone(),
        })?
        .with_context(|| {
            format!(
                "failed creating scheduler run for session {}",
                session.session_id
            )
        })?;

    let refreshed = match execute_run_with_lane_control(
        state,
        &run,
        &resolved_agent_id,
        auth_profile_id.as_deref(),
        RunLaneConflictPolicy::Wait,
    )
    .await
    {
        Ok(run) => run,
        Err(RunLaneExecutionError::Busy) => {
            anyhow::bail!("unexpected scheduler lane lock busy state")
        }
        Err(RunLaneExecutionError::Execute(err)) => return Err(err),
    };

    let run_succeeded = refreshed.status == "succeeded";
    let delivery_targets = parse_scheduler_delivery_targets(payload);
    let delivery_retry_attempts = scheduler_delivery_retry_attempts(payload);
    let delivery_mode = scheduler_delivery_mode(payload);
    let mut delivery_results = Vec::new();
    let mut delivery_attempted: usize = 0;
    let mut delivery_delivered: usize = 0;

    if run_succeeded && !delivery_targets.is_empty() {
        let delivery_text = scheduler_delivery_text(state, &session.session_id, &refreshed.run_id)?;
        for target in delivery_targets {
            delivery_attempted = delivery_attempted.saturating_add(1);
            let mut delivered = false;
            let mut last_error: Option<String> = None;
            let mut chunk_count: usize = 0;
            let mut attempts_used: usize = 0;

            for attempt in 1..=delivery_retry_attempts {
                attempts_used = attempt;
                emit_event(
                    state,
                    "job.delivery",
                    serde_json::json!({
                        "job_id": &job.job_id,
                        "session_id": &session.session_id,
                        "run_id": &refreshed.run_id,
                        "provider": &target.provider,
                        "target": &target.target,
                        "action": &target.action,
                        "delivery_mode": delivery_mode,
                        "attempt": attempt,
                        "status": "attempt"
                    }),
                );
                match dispatch_scheduler_delivery(
                    state,
                    job,
                    &session.session_id,
                    &refreshed.run_id,
                    &target,
                    &delivery_text,
                    attempt,
                ) {
                    Ok(chunks) => {
                        delivered = true;
                        chunk_count = chunks;
                        break;
                    }
                    Err(err) => {
                        last_error = Some(err.to_string());
                        if attempt < delivery_retry_attempts {
                            sleep(Duration::from_millis(25)).await;
                        }
                    }
                }
            }

            if delivered {
                delivery_delivered = delivery_delivered.saturating_add(1);
            }
            let event_error = last_error.clone();
            emit_event(
                state,
                "job.delivery",
                serde_json::json!({
                    "job_id": &job.job_id,
                    "session_id": &session.session_id,
                    "run_id": &refreshed.run_id,
                    "provider": &target.provider,
                    "target": &target.target,
                    "action": &target.action,
                    "delivery_mode": delivery_mode,
                    "attempts_used": attempts_used,
                    "status": if delivered { "delivered" } else { "failed" },
                    "chunk_count": chunk_count,
                    "error": event_error
                }),
            );

            delivery_results.push(serde_json::json!({
                "provider": &target.provider,
                "target": &target.target,
                "action": &target.action,
                "attempts_used": attempts_used,
                "status": if delivered { "delivered" } else { "failed" },
                "chunk_count": chunk_count,
                "error": last_error
            }));

            if delivered && delivery_mode == "first_success" {
                break;
            }
        }
    }

    let delivery_failed = delivery_attempted.saturating_sub(delivery_delivered);
    record_security_audit(
        &headers,
        state,
        &auth,
        "job.session_run.execute",
        &format!("job:{}", job.job_id),
        if run_succeeded { "allow" } else { "deny" },
        Some(if run_succeeded {
            "scheduled session run completed".to_string()
        } else {
            format!(
                "scheduled session run finished with status {}",
                refreshed.status
            )
        }),
        if run_succeeded {
            StatusCode::OK
        } else {
            StatusCode::FAILED_DEPENDENCY
        },
        if run_succeeded {
            None
        } else {
            Some("DEPENDENCY_UNAVAILABLE")
        },
        Some(&session.session_id),
        Some(&refreshed.run_id),
        Some(serde_json::json!({
            "job_id": &job.job_id,
            "mode": mode,
            "agent_id": &resolved_agent_id,
            "human_identity_id": requested_human_identity_id.as_deref().unwrap_or(""),
            "session_key": &session_key,
            "model_provider": &model_provider,
            "model_id": &model_id,
            "auth_profile_id": auth_profile_id.as_deref().unwrap_or(""),
            "run_status": &refreshed.status,
            "delivery_mode": delivery_mode,
            "delivery_attempted": delivery_attempted,
            "delivery_delivered": delivery_delivered,
            "delivery_failed": delivery_failed
        })),
    );

    Ok(serde_json::json!({
        "mode": mode,
        "job_id": &job.job_id,
        "agent_id": &resolved_agent_id,
        "human_identity_id": requested_human_identity_id,
        "session_id": &session.session_id,
        "session_key": &session_key,
        "message_id": &message.message_id,
        "run_id": &refreshed.run_id,
        "run_status": &refreshed.status,
        "model_provider": &refreshed.model_provider,
        "model_id": &refreshed.model_id,
        "auth_profile_id": auth_profile_id,
        "delivery": {
            "mode": delivery_mode,
            "retry_attempts": delivery_retry_attempts,
            "attempted": delivery_attempted,
            "delivered": delivery_delivered,
            "failed": delivery_failed,
            "results": delivery_results
        },
        "now_ms": current_time_ms()
    })
    .to_string())
}

fn execass_wakeup_attention_item_cap_reached(items: &[serde_json::Value]) -> bool {
    items.len() >= EXECASS_WAKEUP_ATTENTION_ITEM_CAP
}

fn collect_execass_wakeup_approval_attention_items(
    state: &AppState,
    items: &mut Vec<serde_json::Value>,
) -> AnyResult<bool> {
    let requested_approvals = state.storage.list_approvals(Some("requested"), 10)?;
    if requested_approvals.is_empty() {
        return Ok(false);
    }

    items.push(serde_json::json!({
        "kind": "pending_approvals",
        "category": "approvals",
        "summary": format!("{} pending operator approval(s)", requested_approvals.len()),
        "count": requested_approvals.len(),
        "examples": requested_approvals
            .iter()
            .take(3)
            .map(|approval| {
                serde_json::json!({
                    "approval_id": &approval.approval_id,
                    "kind": &approval.kind,
                    "summary": &approval.request_summary
                })
            })
            .collect::<Vec<_>>()
    }));
    if execass_wakeup_attention_item_cap_reached(items) {
        return Ok(true);
    }

    for approval in requested_approvals
        .iter()
        .filter(|approval| approval.kind == NUMQUAM_APPROVAL_KIND_WRITEBACK)
        .take(3)
    {
        items.push(serde_json::json!({
            "kind": "pending_memory_writeback_approval",
            "category": "memory",
            "approval_id": &approval.approval_id,
            "run_id": &approval.run_id,
            "summary": &approval.request_summary,
            "requested_at": approval.requested_at
        }));
        if execass_wakeup_attention_item_cap_reached(items) {
            return Ok(true);
        }
    }

    Ok(false)
}

fn collect_execass_wakeup_job_attention_items(
    state: &AppState,
    job: &JobRecord,
    items: &mut Vec<serde_json::Value>,
) -> AnyResult<bool> {
    for watched_job in state.storage.list_jobs(100, true)? {
        if watched_job.job_id == job.job_id {
            continue;
        }
        let watched_job_mode = job_payload_mode(&watched_job.payload_json);
        if let Some(last_error) = watched_job
            .last_error
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
        {
            if watched_job_mode.starts_with("memory.") {
                items.push(serde_json::json!({
                    "kind": "failed_memory_job",
                    "category": "memory",
                    "job_id": &watched_job.job_id,
                    "name": &watched_job.name,
                    "mode": &watched_job_mode,
                    "summary": format!("Memory scheduled job '{}' has last_error", watched_job.name),
                    "error": last_error
                }));
                if execass_wakeup_attention_item_cap_reached(items) {
                    return Ok(true);
                }
            }
            items.push(serde_json::json!({
                "kind": "failed_scheduled_job_runbook",
                "category": "runbooks",
                "runbook_kind": "scheduled_job_run",
                "runbook_id": format!("scheduled_job_run:{}", watched_job.job_id),
                "job_id": &watched_job.job_id,
                "name": &watched_job.name,
                "summary": format!("Scheduled-job runbook for '{}' is failed", watched_job.name),
                "error": last_error
            }));
            if execass_wakeup_attention_item_cap_reached(items) {
                return Ok(true);
            }
            items.push(serde_json::json!({
                "kind": "job_error",
                "category": "jobs",
                "job_id": &watched_job.job_id,
                "name": &watched_job.name,
                "summary": format!("Scheduled job '{}' has last_error", watched_job.name),
                "last_error": last_error
            }));
            if execass_wakeup_attention_item_cap_reached(items) {
                return Ok(true);
            }
            continue;
        }
        if let Some(latest_run) = state
            .storage
            .list_job_runs(&watched_job.job_id, 1)?
            .into_iter()
            .next()
        {
            if latest_run.status == "failed" {
                if watched_job_mode.starts_with("memory.") {
                    items.push(serde_json::json!({
                        "kind": "failed_memory_job",
                        "category": "memory",
                        "job_id": &watched_job.job_id,
                        "job_run_id": &latest_run.job_run_id,
                        "name": &watched_job.name,
                        "mode": &watched_job_mode,
                        "summary": format!("Memory scheduled job '{}' latest run failed", watched_job.name),
                        "error": latest_run.error_text
                    }));
                    if execass_wakeup_attention_item_cap_reached(items) {
                        return Ok(true);
                    }
                }
                items.push(serde_json::json!({
                    "kind": "failed_scheduled_job_runbook",
                    "category": "runbooks",
                    "runbook_kind": "scheduled_job_run",
                    "runbook_id": format!("scheduled_job_run:{}", watched_job.job_id),
                    "job_id": &watched_job.job_id,
                    "job_run_id": &latest_run.job_run_id,
                    "name": &watched_job.name,
                    "summary": format!("Scheduled-job runbook for '{}' latest run failed", watched_job.name),
                    "error": latest_run.error_text
                }));
                if execass_wakeup_attention_item_cap_reached(items) {
                    return Ok(true);
                }
                items.push(serde_json::json!({
                    "kind": "failed_job_run",
                    "category": "jobs",
                    "job_id": &watched_job.job_id,
                    "job_run_id": &latest_run.job_run_id,
                    "name": &watched_job.name,
                    "summary": format!("Scheduled job '{}' latest run failed", watched_job.name),
                    "error": latest_run.error_text
                }));
                if execass_wakeup_attention_item_cap_reached(items) {
                    return Ok(true);
                }
            }
        }
    }

    Ok(false)
}

fn collect_execass_wakeup_attention_items(
    state: &AppState,
    job: &JobRecord,
) -> AnyResult<Vec<serde_json::Value>> {
    let mut items = Vec::new();
    if collect_execass_wakeup_approval_attention_items(state, &mut items)? {
        return Ok(items);
    }
    if collect_execass_wakeup_job_attention_items(state, job, &mut items)? {
        return Ok(items);
    }

    for session in state.storage.list_sessions(100)? {
        let Some(latest_run) = state.storage.latest_run_for_session(&session.session_id)? else {
            continue;
        };
        if latest_run.status != "failed" {
            continue;
        }
        items.push(serde_json::json!({
            "kind": "failed_assistant_session_runbook",
            "category": "runbooks",
            "runbook_kind": "assistant_session_run",
            "runbook_id": format!("assistant_session_run:{}", latest_run.run_id),
            "session_id": &session.session_id,
            "run_id": &latest_run.run_id,
            "agent_id": &session.agent_id,
            "title": session.title,
            "summary": format!("Assistant session runbook '{}' is failed", latest_run.run_id),
            "error": latest_run.error_text
        }));
        if execass_wakeup_attention_item_cap_reached(&items) {
            return Ok(items);
        }
    }

    for task in state
        .storage
        .list_tasks(TaskListFilter {
            blocked: Some(true),
            limit: 20,
            now_ms: current_time_ms(),
            ..TaskListFilter::default()
        })?
        .items
        .into_iter()
        .take(8)
    {
        items.push(serde_json::json!({
            "kind": "blocked_task",
            "category": "tasks",
            "task_id": &task.task_id,
            "title": &task.title,
            "priority": &task.priority,
            "owner_agent_id": task.owner_agent_id,
            "blocked_reason": task.blocked_reason,
            "summary": format!("Blocked task '{}' needs attention", task.title)
        }));
        if execass_wakeup_attention_item_cap_reached(&items) {
            return Ok(items);
        }
    }

    for task in state
        .storage
        .list_tasks(TaskListFilter {
            limit: 50,
            now_ms: current_time_ms(),
            ..TaskListFilter::default()
        })?
        .items
        .into_iter()
    {
        if matches!(task.status.as_str(), "done" | "archived" | "blocked") {
            continue;
        }
        if let (Some(card_id), Some(job_id)) = (
            task.linked_board_card_id.as_deref(),
            task.linked_job_id.as_deref(),
        ) {
            if let Some(linked_job) = state.storage.get_job(job_id)? {
                let latest_failed_run = state
                    .storage
                    .list_job_runs(job_id, 1)?
                    .into_iter()
                    .next()
                    .filter(|run| run.status == "failed");
                if linked_job.last_error.is_some() || latest_failed_run.is_some() {
                    items.push(serde_json::json!({
                        "kind": "board_card_linked_failed_job",
                        "category": "boards",
                        "card_id": card_id,
                        "task_id": &task.task_id,
                        "job_id": job_id,
                        "job_name": &linked_job.name,
                        "summary": format!("Board card for task '{}' is linked to a failed job", task.title)
                    }));
                    if execass_wakeup_attention_item_cap_reached(&items) {
                        return Ok(items);
                    }
                }
            }
        }
        if let Some(due_at) = task.due_at {
            if due_at < current_time_ms() {
                if let Some(card_id) = task.linked_board_card_id.as_deref() {
                    items.push(serde_json::json!({
                        "kind": "board_card_linked_overdue_task",
                        "category": "boards",
                        "card_id": card_id,
                        "task_id": &task.task_id,
                        "title": &task.title,
                        "status": &task.status,
                        "priority": &task.priority,
                        "due_at": due_at,
                        "summary": format!("Board card for task '{}' is overdue", task.title)
                    }));
                    if execass_wakeup_attention_item_cap_reached(&items) {
                        return Ok(items);
                    }
                }
                items.push(serde_json::json!({
                    "kind": "overdue_task",
                    "category": "tasks",
                    "task_id": &task.task_id,
                    "title": &task.title,
                    "status": &task.status,
                    "priority": &task.priority,
                    "owner_agent_id": task.owner_agent_id,
                    "due_at": due_at,
                    "summary": format!("Task '{}' is overdue", task.title)
                }));
                if execass_wakeup_attention_item_cap_reached(&items) {
                    return Ok(items);
                }
                continue;
            }
        }
        if task.priority == "high" && task.owner_agent_id.is_none() {
            items.push(serde_json::json!({
                "kind": "high_priority_unowned_task",
                "category": "tasks",
                "task_id": &task.task_id,
                "title": &task.title,
                "status": &task.status,
                "priority": &task.priority,
                "summary": format!("High-priority task '{}' has no owner", task.title)
            }));
            if execass_wakeup_attention_item_cap_reached(&items) {
                return Ok(items);
            }
        }
    }

    for thread in state
        .storage
        .list_agent_mail_threads(&AgentMailThreadListFilter {
            principal_id: Some(job.agent_id.clone()),
            mailbox: Some("inbox".to_string()),
            limit: 20,
            ..AgentMailThreadListFilter::default()
        })?
        .into_iter()
        .filter(|thread| thread.unread_count > 0)
        .take(3)
    {
        items.push(serde_json::json!({
            "kind": "unread_agent_mail_thread",
            "category": "agent_mail",
            "thread_id": &thread.thread.thread_id,
            "subject": &thread.thread.subject,
            "latest_sender_principal": thread.latest_sender_principal,
            "latest_message_preview": thread.latest_message_preview,
            "unread_count": thread.unread_count,
            "summary": format!("Agent '{}' has unread mail in '{}'", job.agent_id, thread.thread.subject)
        }));
        if execass_wakeup_attention_item_cap_reached(&items) {
            return Ok(items);
        }
    }

    for interaction in state
        .storage
        .list_connector_interactions(None)?
        .into_iter()
        .filter(|interaction| {
            interaction.status == "waiting_on_operator"
                && interaction
                    .agent_id
                    .as_deref()
                    .map(|agent_id| agent_id == job.agent_id)
                    .unwrap_or(true)
        })
        .take(3)
    {
        items.push(serde_json::json!({
            "kind": "waiting_connector_interaction",
            "category": "connectors",
            "interaction_id": &interaction.interaction_id,
            "connector_id": &interaction.connector_id,
            "agent_id": interaction.agent_id,
            "interaction_kind": &interaction.interaction_kind,
            "status": &interaction.status,
            "prompt_summary": &interaction.prompt_summary,
            "summary": format!("Connector interaction '{}' is waiting on operator input", interaction.prompt_summary)
        }));
        if execass_wakeup_attention_item_cap_reached(&items) {
            return Ok(items);
        }
    }

    for connector in state.storage.list_connectors(ConnectorListFilter {
        include_disabled: true,
        ..ConnectorListFilter::default()
    })? {
        for assignment in state
            .storage
            .list_connector_assignments(&connector.connector_id)?
            .into_iter()
            .filter(|assignment| assignment.agent_id == job.agent_id && !assignment.enabled)
            .take(2)
        {
            items.push(serde_json::json!({
                "kind": "disabled_connector_assignment",
                "category": "connectors",
                "assignment_id": &assignment.assignment_id,
                "connector_id": &connector.connector_id,
                "connector_name": &connector.display_name,
                "agent_id": &assignment.agent_id,
                "status": &connector.status,
                "summary": format!("Connector '{}' is assigned to agent '{}' but disabled", connector.display_name, assignment.agent_id)
            }));
            if execass_wakeup_attention_item_cap_reached(&items) {
                return Ok(items);
            }
        }
        if connector.assigned_agent_count > 0
            && matches!(connector.status.as_str(), "disabled" | "error")
        {
            items.push(serde_json::json!({
                "kind": "unhealthy_connector_source",
                "category": "connectors",
                "connector_id": &connector.connector_id,
                "connector_name": &connector.display_name,
                "status": &connector.status,
                "assigned_agent_count": connector.assigned_agent_count,
                "summary": format!("Connector '{}' is '{}' with active assignments", connector.display_name, connector.status)
            }));
            if execass_wakeup_attention_item_cap_reached(&items) {
                return Ok(items);
            }
        }
        for conversion in state
            .storage
            .list_connector_conversions(&connector.connector_id, None)?
            .into_iter()
            .filter(|conversion| conversion.status == "failed")
            .take(2)
        {
            items.push(serde_json::json!({
                "kind": "failed_connector_conversion",
                "category": "connectors",
                "conversion_id": &conversion.conversion_id,
                "connector_id": &connector.connector_id,
                "connector_name": &connector.display_name,
                "version_id": &conversion.version_id,
                "status": &conversion.status,
                "summary": format!("Connector '{}' latest conversion failed", connector.display_name)
            }));
            if execass_wakeup_attention_item_cap_reached(&items) {
                return Ok(items);
            }
        }
    }

    for breaker in state
        .storage
        .list_circuit_breaker_states(20, Some(CIRCUIT_BREAKER_SCOPE_PROVIDER))?
        .into_iter()
        .filter(|breaker| breaker.state == "open")
        .take(3)
    {
        items.push(serde_json::json!({
            "kind": "open_provider_circuit_breaker",
            "category": "providers",
            "scope": &breaker.scope,
            "target_id": &breaker.target_id,
            "state": &breaker.state,
            "consecutive_failures": breaker.consecutive_failures,
            "opened_at": breaker.opened_at,
            "cooldown_until": breaker.cooldown_until,
            "last_error_code": breaker.last_error_code,
            "summary": format!("Provider circuit breaker '{}' is open", breaker.target_id)
        }));
        if execass_wakeup_attention_item_cap_reached(&items) {
            return Ok(items);
        }
    }

    for (scope, kind) in [
        (CIRCUIT_BREAKER_SCOPE_JOB, "open_job_circuit_breaker"),
        (
            CIRCUIT_BREAKER_SCOPE_NUMQUAM,
            "open_numquam_circuit_breaker",
        ),
    ] {
        for breaker in state
            .storage
            .list_circuit_breaker_states(20, Some(scope))?
            .into_iter()
            .filter(|breaker| breaker.state == "open")
            .take(3)
        {
            if scope == CIRCUIT_BREAKER_SCOPE_JOB && breaker.target_id == job.job_id {
                continue;
            }
            items.push(serde_json::json!({
                "kind": kind,
                "category": "providers",
                "scope": &breaker.scope,
                "target_id": &breaker.target_id,
                "state": &breaker.state,
                "consecutive_failures": breaker.consecutive_failures,
                "opened_at": breaker.opened_at,
                "cooldown_until": breaker.cooldown_until,
                "last_error_code": breaker.last_error_code,
                "summary": format!("{} circuit breaker '{}' is open", scope, breaker.target_id)
            }));
            if execass_wakeup_attention_item_cap_reached(&items) {
                return Ok(items);
            }
        }
    }

    if let Some(agent) = state.storage.get_agent(&job.agent_id)? {
        for profile in state
            .storage
            .list_auth_profiles(Some(&agent.model_provider), true)?
            .into_iter()
            .filter(|profile| !profile.enabled)
            .take(3)
        {
            items.push(serde_json::json!({
                "kind": "disabled_agent_auth_profile",
                "category": "providers",
                "auth_profile_id": &profile.auth_profile_id,
                "agent_id": &agent.agent_id,
                "provider": &profile.provider,
                "display_name": &profile.display_name,
                "summary": format!("Agent '{}' uses provider '{}' with a disabled auth profile '{}'", agent.agent_id, agent.model_provider, profile.display_name)
            }));
            if execass_wakeup_attention_item_cap_reached(&items) {
                return Ok(items);
            }
        }
    }

    Ok(items)
}

fn execass_wakeup_checked_categories(
    attention_items: &[serde_json::Value],
) -> Vec<serde_json::Value> {
    EXECASS_WAKEUP_CATEGORIES
        .iter()
        .map(|category| {
            let count = attention_items
                .iter()
                .filter(|item| {
                    item.get("category")
                        .and_then(|value| value.as_str())
                        .map(|value| value == *category)
                        .unwrap_or(false)
                })
                .count();
            let status = if count > 0 { "attention" } else { "clear" };
            serde_json::json!({
                "category": category,
                "status": status,
                "summary": if count > 0 {
                    format!("{count} attention item(s) found")
                } else {
                    "No attention items found".to_string()
                },
                "count": count
            })
        })
        .collect()
}

fn execass_wakeup_escalation_input(
    payload: &serde_json::Value,
    attention_items: &[serde_json::Value],
) -> String {
    let base = optional_job_payload_string(payload, "input").unwrap_or_else(|| {
        "ExecAss wakeup preflight found attention items. Review them and respond only with the useful update or decision request.".to_string()
    });
    let attention_json =
        serde_json::to_string_pretty(attention_items).unwrap_or_else(|_| "[]".to_string());
    format!(
        "{base}\n\nExecAss wakeup preflight found these attention items. Only message the user if a decision, blocker, failed job, pending approval, or stale context truly needs attention:\n{attention_json}"
    )
}

async fn execute_execass_wakeup_job(
    state: &AppState,
    job: &JobRecord,
    payload: &serde_json::Value,
    attempt: i64,
) -> AnyResult<String> {
    let attention_items = collect_execass_wakeup_attention_items(state, job)?;
    let checked = execass_wakeup_checked_categories(&attention_items);
    if attention_items.is_empty() {
        return Ok(serde_json::json!({
            "mode": JOB_MODE_EXECASS_WAKEUP,
            "coverage_version": EXECASS_WAKEUP_COVERAGE_VERSION,
            "job_id": &job.job_id,
            "attempt": attempt,
            "status": "quiet",
            "llm_invoked": false,
            "reason": "no_attention_items",
            "checked": checked,
            "attention_items": [],
            "preset": payload.get("preset").cloned().unwrap_or(serde_json::Value::Null),
            "notify_policy": payload.get("notify_policy").cloned().unwrap_or(serde_json::json!("attention_only")),
            "now_ms": current_time_ms()
        })
        .to_string());
    }

    let mut escalation_payload = payload.clone();
    let object = escalation_payload
        .as_object_mut()
        .ok_or_else(|| anyhow::anyhow!("execass.wakeup payload must be a JSON object"))?;
    object.insert("mode".to_string(), serde_json::json!("session.run"));
    object.insert(
        "input".to_string(),
        serde_json::json!(execass_wakeup_escalation_input(payload, &attention_items)),
    );
    let session_output = execute_session_run_job(state, job, &escalation_payload).await?;
    let session_value = serde_json::from_str::<serde_json::Value>(&session_output)
        .unwrap_or_else(|_| serde_json::json!({ "raw_output": session_output }));
    Ok(serde_json::json!({
        "mode": JOB_MODE_EXECASS_WAKEUP,
        "coverage_version": EXECASS_WAKEUP_COVERAGE_VERSION,
        "job_id": &job.job_id,
        "attempt": attempt,
        "status": "escalated",
        "llm_invoked": true,
        "reason": "attention_items_found",
        "checked": checked,
        "attention_items": attention_items,
        "session_run": session_value,
        "now_ms": current_time_ms()
    })
    .to_string())
}

fn generate_automation_script(card: &BoardCardRecord) -> String {
    let title = card.title.trim();
    let description = card
        .description
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("No description provided.");
    format!(
        "# {}\n\n## Objective\n{}\n\n## Outline\n- Hook\n- Core points\n- Call to action\n",
        title, description
    )
}

fn escape_svg_text(value: &str) -> String {
    value
        .replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
}

fn generate_thumbnail_draft_svg(card: &BoardCardRecord) -> String {
    let title = escape_svg_text(card.title.trim());
    let script_line = card
        .script_markdown
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .and_then(|value| value.lines().find(|line| !line.trim().is_empty()))
        .unwrap_or("Draft thumbnail")
        .trim();
    let subtitle = escape_svg_text(script_line);
    format!(
        r##"<svg xmlns="http://www.w3.org/2000/svg" width="1280" height="720" viewBox="0 0 1280 720">
  <defs>
    <linearGradient id="bg" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0%" stop-color="#13203a"/>
      <stop offset="100%" stop-color="#2b172f"/>
    </linearGradient>
  </defs>
  <rect width="1280" height="720" fill="url(#bg)"/>
  <rect x="40" y="40" width="1200" height="640" rx="20" fill="rgba(0,0,0,0.24)" stroke="#70bcff" stroke-width="2"/>
  <text x="80" y="170" fill="#f6f7ff" font-size="62" font-family="Arial, sans-serif" font-weight="700">{}</text>
  <text x="80" y="250" fill="#ffd66d" font-size="34" font-family="Arial, sans-serif">{}</text>
  <text x="80" y="650" fill="#a9d8ff" font-size="24" font-family="Arial, sans-serif">carsinOS automation thumbnail draft</text>
</svg>"##,
        title, subtitle
    )
}

fn persist_generated_board_card_asset(
    state: &AppState,
    card: &BoardCardRecord,
    filename: &str,
    mime: &str,
    content: &[u8],
) -> AnyResult<BoardCardAssetRecord> {
    let cleaned_filename = sanitize_filename(filename);
    let asset_dir = std::path::Path::new(state.attachments_path.as_str())
        .join("board_cards")
        .join(&card.card_id);
    std::fs::create_dir_all(&asset_dir).with_context(|| {
        format!(
            "failed creating board card automation asset directory {}",
            asset_dir.display()
        )
    })?;
    let asset_path = asset_dir.join(format!("{}-{}", current_time_ms(), cleaned_filename));
    std::fs::write(&asset_path, content)
        .with_context(|| format!("failed writing automation asset {}", asset_path.display()))?;
    let sha256 = sha256_hex(std::str::from_utf8(content).unwrap_or_default());
    state
        .storage
        .create_board_card_asset(NewBoardCardAsset {
            card_id: card.card_id.clone(),
            filename: cleaned_filename,
            mime: mime.to_string(),
            sha256,
            bytes: content.len() as i64,
            local_path: asset_path.to_string_lossy().to_string(),
        })?
        .ok_or_else(|| anyhow::anyhow!("automation asset metadata insert returned no row"))
}

async fn execute_board_automation_job(
    state: &AppState,
    job: &JobRecord,
    payload: &serde_json::Value,
    attempt: i64,
) -> AnyResult<String> {
    let rule = parse_board_automation_payload(payload, Some(&job.job_id))?;
    let now_ms = current_time_ms();
    let day_key = utc_day_key(now_ms);
    let daily_run_counter_key = format!("mc3.auto.runs.{}.{}", rule.rule_id, day_key);
    let current_runs = app_kv_counter_get(&state.storage, &daily_run_counter_key)?;
    if current_runs >= rule.max_runs_per_day {
        anyhow::bail!(
            "{REASON_AUTOMATION_DAILY_RUN_LIMIT}: automation '{}' reached max_runs_per_day={}",
            rule.rule_id,
            rule.max_runs_per_day
        );
    }
    let _ = app_kv_counter_increment(&state.storage, &daily_run_counter_key, 1)?;

    let board = state
        .storage
        .get_board(&rule.board_id)?
        .with_context(|| format!("automation board not found: {}", rule.board_id))?;
    let columns = state.storage.list_board_columns(&rule.board_id)?;
    if !columns
        .iter()
        .any(|column| column.column_id == rule.column_id)
    {
        anyhow::bail!("automation source column not found in board");
    }
    if !columns
        .iter()
        .any(|column| column.column_id == rule.target_column_id)
    {
        anyhow::bail!("automation target column not found in board");
    }

    let mut source_cards = state
        .storage
        .list_board_cards(&rule.board_id)?
        .into_iter()
        .filter(|card| card.column_id == rule.column_id)
        .collect::<Vec<_>>();
    source_cards.sort_by_key(|card| card.position);
    source_cards.truncate(rule.max_cards_per_run as usize);

    let model_provider = rule
        .model_provider
        .as_deref()
        .unwrap_or("mock")
        .trim()
        .to_string();
    let model_id = rule
        .model_id
        .as_deref()
        .unwrap_or("mock-echo-v1")
        .trim()
        .to_string();
    if !provider_supported(&model_provider) {
        anyhow::bail!(
            "{REASON_AUTOMATION_EXECUTION_FAILED}: unsupported model_provider '{}'",
            model_provider
        );
    }

    let mut processed_cards = 0usize;
    let mut succeeded_cards = 0usize;
    let mut skipped_cards = Vec::new();
    let mut failed_cards = Vec::new();
    let mut created_assets = Vec::new();

    for card in source_cards {
        let card_attempt_key = format!(
            "mc3.auto.card_attempts.{}.{}.{}",
            rule.rule_id, day_key, card.card_id
        );
        let card_attempts = app_kv_counter_get(&state.storage, &card_attempt_key)?;
        if card_attempts >= rule.max_attempts_per_card_per_day {
            skipped_cards.push(serde_json::json!({
                "card_id": card.card_id,
                "reason_code": REASON_AUTOMATION_CARD_ATTEMPT_LIMIT,
                "attempts_today": card_attempts
            }));
            continue;
        }
        let _ = app_kv_counter_increment(&state.storage, &card_attempt_key, 1)?;
        processed_cards = processed_cards.saturating_add(1);

        let mut current_card = card.clone();
        if current_card
            .script_markdown
            .as_deref()
            .map(str::trim)
            .unwrap_or("")
            .is_empty()
        {
            let generated_script = generate_automation_script(&current_card);
            if let Some(updated) = state.storage.update_board_card(
                &rule.board_id,
                &current_card.card_id,
                BoardCardUpdatePatch {
                    title: None,
                    description: None,
                    owner_kind: None,
                    owner_agent_id: None,
                    owner_human_id: None,
                    due_at: None,
                    tags_json: None,
                    script_markdown: Some(Some(generated_script)),
                },
            )? {
                current_card = updated;
            }
        }

        let agent_id = current_card
            .owner_agent_id
            .clone()
            .unwrap_or_else(|| job.agent_id.clone());
        let session_key = format!(
            "board:{}:card:{}:agent:{}",
            rule.board_id, current_card.card_id, agent_id
        );
        let session = match state.storage.get_session_by_key(&session_key)? {
            Some(existing) => existing,
            None => state.storage.create_session(NewSession {
                session_key: Some(session_key),
                agent_id: agent_id.clone(),
                title: Some(format!("Board card {}", current_card.title)),
            })?,
        };
        let prompt = format!(
            "Automation run (attempt {}): progress content pipeline card '{}'.",
            attempt, current_card.title
        );
        let _ = state.storage.create_message(NewMessage {
            session_id: session.session_id.clone(),
            source_channel: "scheduler".to_string(),
            source_peer_id: Some(format!(
                "board:{}:card:{}",
                rule.board_id, current_card.card_id
            )),
            source_message_id: None,
            role: "user".to_string(),
            content_text: prompt,
            content_format: "markdown".to_string(),
        });
        let created_run = state
            .storage
            .create_run(NewRun {
                session_id: session.session_id.clone(),
                model_provider: model_provider.clone(),
                model_id: model_id.clone(),
            })?
            .with_context(|| {
                format!(
                    "failed creating automation run for card {}",
                    current_card.card_id
                )
            })?;
        let run = match execute_run_with_lane_control(
            state,
            &created_run,
            &agent_id,
            rule.auth_profile_id.as_deref(),
            RunLaneConflictPolicy::Wait,
        )
        .await
        {
            Ok(run) => run,
            Err(RunLaneExecutionError::Busy) => {
                failed_cards.push(serde_json::json!({
                    "card_id": current_card.card_id,
                    "error": "session lane unexpectedly busy"
                }));
                continue;
            }
            Err(RunLaneExecutionError::Execute(err)) => {
                failed_cards.push(serde_json::json!({
                    "card_id": current_card.card_id,
                    "error": err.to_string()
                }));
                continue;
            }
        };
        let Some(updated_with_run) = state.storage.update_board_card_run_link(
            &rule.board_id,
            &current_card.card_id,
            Some(&session.session_id),
            Some(&run.run_id),
        )?
        else {
            failed_cards.push(serde_json::json!({
                "card_id": current_card.card_id,
                "error": "card disappeared before run link update"
            }));
            continue;
        };
        current_card = updated_with_run;

        if rule.generate_thumbnail_draft {
            let svg = generate_thumbnail_draft_svg(&current_card);
            match persist_generated_board_card_asset(
                state,
                &current_card,
                "thumbnail-draft.svg",
                "image/svg+xml",
                svg.as_bytes(),
            ) {
                Ok(asset) => {
                    created_assets.push(serde_json::json!({
                        "card_id": current_card.card_id,
                        "card_asset_id": asset.card_asset_id,
                        "filename": asset.filename
                    }));
                }
                Err(err) => {
                    warn!(
                        job_id = %job.job_id,
                        card_id = %current_card.card_id,
                        error = %err,
                        "failed to create thumbnail draft asset"
                    );
                }
            }
        }

        let moved = state.storage.move_board_card(
            &rule.board_id,
            &current_card.card_id,
            &rule.target_column_id,
            None,
        )?;
        if moved.is_none() {
            failed_cards.push(serde_json::json!({
                "card_id": current_card.card_id,
                "error": "failed moving card to target column"
            }));
            continue;
        }
        succeeded_cards = succeeded_cards.saturating_add(1);
        emit_event(
            state,
            "board.automation.card",
            serde_json::json!({
                "job_id": &job.job_id,
                "rule_id": &rule.rule_id,
                "board_id": &board.board_id,
                "card_id": &current_card.card_id,
                "target_column_id": &rule.target_column_id,
                "run_id": &run.run_id,
                "status": &run.status
            }),
        );
    }

    if processed_cards > 0 && succeeded_cards == 0 {
        anyhow::bail!(
            "{REASON_AUTOMATION_EXECUTION_FAILED}: no cards advanced successfully in this run"
        );
    }

    Ok(serde_json::json!({
        "mode": JOB_MODE_MC3_COLUMN_AUTOMATION,
        "job_id": &job.job_id,
        "rule_id": &rule.rule_id,
        "board_id": &rule.board_id,
        "column_id": &rule.column_id,
        "target_column_id": &rule.target_column_id,
        "processed_cards": processed_cards,
        "succeeded_cards": succeeded_cards,
        "skipped_cards": skipped_cards,
        "failed_cards": failed_cards,
        "created_assets": created_assets,
        "max_cards_per_run": rule.max_cards_per_run,
        "max_runs_per_day": rule.max_runs_per_day,
        "max_attempts_per_card_per_day": rule.max_attempts_per_card_per_day,
        "attempt": attempt,
        "now_ms": current_time_ms()
    })
    .to_string())
}

async fn execute_job_payload(state: &AppState, job: &JobRecord, attempt: i64) -> AnyResult<String> {
    let payload: serde_json::Value = serde_json::from_str(&job.payload_json).unwrap_or_else(|_| {
        serde_json::json!({
            "mode": "noop"
        })
    });
    let mode = payload
        .get("mode")
        .and_then(|value| value.as_str())
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| "noop".to_string());

    if mode == "fail" {
        anyhow::bail!("job payload requested failure");
    }
    if let Some(fail_until_attempt) = payload
        .get("fail_until_attempt")
        .and_then(|value| value.as_i64())
    {
        if attempt <= fail_until_attempt {
            anyhow::bail!(
                "job payload configured to fail until attempt {}",
                fail_until_attempt
            );
        }
    }
    if let Some(delay_ms) = payload.get("delay_ms").and_then(|value| value.as_u64()) {
        if delay_ms > 0 {
            sleep(Duration::from_millis(delay_ms.min(600_000))).await;
        }
    }

    if mode == "secret.rotate_profile" {
        return execute_secret_rotate_job(state, job, &payload);
    }
    if mode == "secret.revoke_profile" {
        return execute_secret_revoke_job(state, job, &payload);
    }
    if mode == JOB_MODE_HEARTBEAT_RUN {
        return execute_heartbeat_run_job(state, job, &payload, attempt)
            .await
            .map_err(|err| {
                let text = err.to_string();
                if extract_reason_code_from_error_text(&text).is_some() {
                    anyhow::anyhow!("{text}")
                } else {
                    anyhow::anyhow!("{REASON_HEARTBEAT_RUN_FAILED}: {text}")
                }
            });
    }
    if mode == "memory.sync" {
        return execute_memory_sync_job(state, job, &payload, attempt).await;
    }
    if mode == "memory.preflight" {
        return execute_memory_preflight_job(state, job, &payload, attempt).await;
    }
    if mode == "memory.parity_probe" {
        return execute_memory_parity_probe_job(state, job, &payload, attempt).await;
    }
    if mode == "memory.pipeline.hook" {
        return execute_memory_pipeline_hook_job(state, job, &payload, attempt);
    }
    if mode == JOB_MODE_EXECASS_WAKEUP {
        return execute_execass_wakeup_job(state, job, &payload, attempt).await;
    }
    if mode == "session.run" {
        return execute_session_run_job(state, job, &payload).await;
    }
    if mode == JOB_MODE_MC3_COLUMN_AUTOMATION {
        return execute_board_automation_job(state, job, &payload, attempt).await;
    }

    let output = serde_json::json!({
        "mode": &mode,
        "job_id": &job.job_id,
        "attempt": attempt,
        "now_ms": current_time_ms(),
        "message": payload
            .get("message")
            .and_then(|value| value.as_str())
            .unwrap_or("job executed")
    });
    Ok(output.to_string())
}

fn next_run_after_completion(job: &JobRecord) -> Option<i64> {
    match job.schedule_kind.as_str() {
        "interval" | "every" => job
            .interval_seconds
            .map(|seconds| current_time_ms().saturating_add(seconds.max(1) * 1000)),
        "once" | "at" => None,
        "cron" => job_cron_expr_from_payload_json(&job.payload_json).and_then(|cron_expr| {
            compute_next_cron_run_at(cron_expr.as_str(), current_time_ms()).ok()
        }),
        _ => None,
    }
}

