    #[tokio::test]
    async fn telegram_channel_inbound_run_dispatches_transport_reply_when_enabled() {
        let ctx = test_context();
        let transport = MockServer::start();
        let transport_mock = transport.mock(|when, then| {
            when.method(POST).path("/bottelegram-token/sendMessage");
            then.status(200)
                .header("content-type", "application/json")
                .body(r#"{"ok":true,"result":{"message_id":901}}"#);
        });

        ctx.secret_store
            .set_raw("runtime.channels.telegram.bot_token", "telegram-token")
            .expect("set telegram runtime secret");

        let runtime_update_payload = serde_json::json!({
            "channels": {
                "discord": {
                    "bot_token_secret_ref": null,
                    "operation_mode": "shim",
                    "application_id": null,
                    "intents": ["guilds"],
                    "staging_guild_ids": [],
                    "staging_channel_ids": []
                },
                "telegram": {
                    "bot_token_secret_ref": "secret://runtime.channels.telegram.bot_token",
                    "operation_mode": "transport",
                    "api_base_url": transport.base_url(),
                    "transport_timeout_ms": 1000,
                    "transport_retry_attempts": 1,
                    "long_poll_timeout_seconds": 10,
                    "webhook_mode": "long_poll",
                    "webhook_url": null,
                    "staging_chat_ids": []
                }
            }
        });
        let runtime_update = ctx
            .app
            .clone()
            .oneshot(auth_request(
                "POST",
                "/api/v1/config/runtime",
                Body::from(runtime_update_payload.to_string()),
            ))
            .await
            .expect("update runtime config for telegram transport");
        assert_eq!(runtime_update.status(), StatusCode::OK);
        let _ = ctx
            .app
            .clone()
            .oneshot(auth_request(
                "POST",
                "/api/v1/config/channels",
                Body::from(
                    r#"{
                        "telegram":{
                            "require_mention_in_groups":false,
                            "allowlisted_user_ids":[77],
                            "dm_policy":"allowlist",
                            "auto_run_enabled":true,
                            "default_model_provider":"mock",
                            "default_model_id":"mock-echo-v1"
                        }
                    }"#,
                ),
            ))
            .await
            .expect("update telegram channel config");

        let inbound = ctx
            .app
            .clone()
            .oneshot(auth_request(
                "POST",
                "/api/v1/channels/telegram/inbound",
                Body::from(
                    r#"{
                        "chat_id":444,
                        "user_id":77,
                        "text":"run and reply",
                        "is_group_chat":false,
                        "mentions_bot":false,
                        "reply_to_bot":false,
                        "run_immediately":true,
                        "model_provider":"mock",
                        "model_id":"mock-echo-v1"
                    }"#,
                ),
            ))
            .await
            .expect("telegram inbound run");
        assert_eq!(inbound.status(), StatusCode::OK);
        let inbound_json = parse_json(inbound).await;
        assert_eq!(inbound_json["decision"], "accepted");
        let run_id = inbound_json["run_id"].as_str().expect("run id");
        let run = ctx
            .storage
            .get_run(run_id)
            .expect("get run")
            .expect("run exists");
        assert_eq!(run.status, "succeeded");
        let session = ctx
            .storage
            .get_session_by_key("telegram:dm:77")
            .expect("load telegram channel session")
            .expect("telegram channel session exists");
        let messages = ctx
            .storage
            .list_messages(&session.session_id, 10)
            .expect("load telegram channel messages");
        assert!(messages.iter().any(|message| message.role == "system"
            && message
                .content_text
                .contains("You are the CarsinOS assistant.")));
        let assistant_reply = latest_assistant_reply_text(&ctx.state, &session.session_id)
            .expect("load assistant reply")
            .expect("assistant reply");
        let expected_chunks = telegram_channel::split_outbound_chunks(
            &assistant_reply,
            telegram_channel::TELEGRAM_DEFAULT_CHUNK_LIMIT,
        )
        .len();
        assert!(expected_chunks > 0);
        transport_mock.assert_hits(expected_chunks);
    }

