    #[tokio::test]
    async fn assistant_desk_transcript_is_scoped_to_selected_run() {
        let ctx = test_context();
        let session = ctx
            .storage
            .create_session(NewSession {
                session_key: None,
                agent_id: "default".to_string(),
                title: Some("Scoped transcript".to_string()),
            })
            .expect("create scoped transcript session");

        ctx.storage
            .create_message(NewMessage {
                session_id: session.session_id.clone(),
                source_channel: "assistant-chat".to_string(),
                source_peer_id: None,
                source_message_id: None,
                role: "user".to_string(),
                content_text: "first scoped prompt".to_string(),
                content_format: "markdown".to_string(),
            })
            .expect("create first scoped user message");
        let first_run = ctx
            .storage
            .create_run(NewRun {
                session_id: session.session_id.clone(),
                model_provider: "mock".to_string(),
                model_id: "mock-echo-v1".to_string(),
            })
            .expect("create first scoped run")
            .expect("first scoped run exists");
        ctx.storage
            .mark_run_started(&first_run.run_id)
            .expect("mark first scoped run started");
        ctx.storage
            .create_message(NewMessage {
                session_id: session.session_id.clone(),
                source_channel: "assistant-chat".to_string(),
                source_peer_id: None,
                source_message_id: None,
                role: "assistant".to_string(),
                content_text: "first scoped answer".to_string(),
                content_format: "markdown".to_string(),
            })
            .expect("create first scoped assistant message");
        std::thread::sleep(std::time::Duration::from_millis(2));
        ctx.storage
            .mark_run_succeeded(&first_run.run_id)
            .expect("mark first scoped run succeeded");
        std::thread::sleep(std::time::Duration::from_millis(2));

        ctx.storage
            .create_message(NewMessage {
                session_id: session.session_id.clone(),
                source_channel: "assistant-chat".to_string(),
                source_peer_id: None,
                source_message_id: None,
                role: "user".to_string(),
                content_text: "second scoped prompt".to_string(),
                content_format: "markdown".to_string(),
            })
            .expect("create second scoped user message");
        let second_run = ctx
            .storage
            .create_run(NewRun {
                session_id: session.session_id.clone(),
                model_provider: "mock".to_string(),
                model_id: "mock-echo-v1".to_string(),
            })
            .expect("create second scoped run")
            .expect("second scoped run exists");
        ctx.storage
            .mark_run_started(&second_run.run_id)
            .expect("mark second scoped run started");
        ctx.storage
            .create_message(NewMessage {
                session_id: session.session_id.clone(),
                source_channel: "assistant-chat".to_string(),
                source_peer_id: None,
                source_message_id: None,
                role: "assistant".to_string(),
                content_text: "second scoped answer".to_string(),
                content_format: "markdown".to_string(),
            })
            .expect("create second scoped assistant message");

        let transcript_response = ctx
            .app
            .clone()
            .oneshot(auth_request(
                "GET",
                &format!(
                    "/api/v1/assistant-desk/run:{}/transcript",
                    second_run.run_id
                ),
                Body::empty(),
            ))
            .await
            .expect("assistant desk scoped transcript response");
        assert_eq!(transcript_response.status(), StatusCode::OK);
        let transcript_json = parse_json(transcript_response).await;
        let serialized =
            serde_json::to_string(&transcript_json).expect("serialize scoped transcript");
        assert!(serialized.contains("second scoped prompt"));
        assert!(serialized.contains("second scoped answer"));
        assert!(!serialized.contains("first scoped prompt"));
        assert!(!serialized.contains("first scoped answer"));
    }

    #[tokio::test]
    async fn mission_control_usage_read_model_returns_required_contract_fields() {
        let ctx = test_context();
        let session = ctx
            .storage
            .create_session(NewSession {
                session_key: None,
                agent_id: "default".to_string(),
                title: Some("usage read model".to_string()),
            })
            .expect("create usage session");
        let run = ctx
            .storage
            .create_run(NewRun {
                session_id: session.session_id.clone(),
                model_provider: "openai".to_string(),
                model_id: "gpt-4o-mini".to_string(),
            })
            .expect("create usage run")
            .expect("usage run exists");
        ctx.storage
            .set_run_usage_json(
                &run.run_id,
                r#"{"provider":{"input_tokens":120,"output_tokens":40,"estimated_cost_usd":0.42}}"#,
            )
            .expect("set usage json");

        let response = ctx
            .app
            .clone()
            .oneshot(auth_request(
                "GET",
                "/api/v1/mission-control/usage?window=today&timezone=UTC&tz_offset_minutes=0",
                Body::empty(),
            ))
            .await
            .expect("usage response");
        assert_eq!(response.status(), StatusCode::OK);
        let usage_json = parse_json(response).await;
        assert_eq!(usage_json["available"], true);
        assert_eq!(usage_json["window"], "today");
        assert_eq!(usage_json["timezone"], "UTC");
        assert_eq!(usage_json["currency"], "USD");
        assert!(usage_json["window_start_utc"].is_string());
        assert!(usage_json["window_end_utc"].is_string());
        assert!(usage_json["updated_at_utc"].is_string());
        assert!((usage_json["estimated_cost_total"].as_f64().unwrap_or(0.0) - 0.42).abs() < 1e-9);
        assert_eq!(usage_json["token_input_total"], 120);
        assert_eq!(usage_json["token_output_total"], 40);

        let by_agent = usage_json["by_agent"].as_array().expect("by_agent array");
        assert!(by_agent.iter().any(|item| {
            item["agent_id"]
                .as_str()
                .map(|value| value == "default")
                .unwrap_or(false)
        }));

        let by_model = usage_json["by_model"].as_array().expect("by_model array");
        assert!(by_model.iter().any(|item| {
            item["model_provider"]
                .as_str()
                .map(|value| value == "openai")
                .unwrap_or(false)
                && item["model_id"]
                    .as_str()
                    .map(|value| value == "gpt-4o-mini")
                    .unwrap_or(false)
        }));

        let by_time = usage_json["by_time"].as_array().expect("by_time array");
        assert_eq!(by_time.len(), 24);
        assert!(usage_json["by_job"].is_null());
        assert!(usage_json["by_card"].is_null());
    }

